import type { SignTemplates } from './types';

export const aquariusTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '머릿속을 번쩍이는 영감이 오늘 당신의 가장 강력한 무기가 됩니다. 천왕성의 번갯불 같은 에너지가 혁신적인 아이디어를 현실로 끌어내리는 날로, 평소에 막혀 있던 창의적 흐름이 폭발적으로 열립니다. 지금 떠오르는 아이디어를 즉시 실행에 옮길 용기를 가지세요—당신은 미래를 먼저 보는 사람입니다.', en: 'Lightning-like inspiration from Uranus strikes you today, unlocking creative breakthroughs you\'ve been waiting for. This is a powerful day when innovative ideas don\'t just stay in your mind—they become tangible reality. Act on your boldest thoughts now; the universe is fully aligned behind your vision.', zh: '天王星闪电般的灵感降临于你，今天是创新想法变为现实的强大时刻。被压抑已久的创意能量如洪水般涌现，勇敢地将你最大胆的想法付诸行动吧。', ja: '天王星の稲妻のようなインスピレーションがあなたに降りてきます。革新的なアイデアが現実になる日で、長い間滞っていた創造のエネルギーが一気に解放されます。最も大胆なアイデアを今すぐ実行に移してください。', es: 'La inspiracion de Urano llega como un rayo hoy, desbloqueando avances creativos que has estado esperando. Tus ideas mas innovadoras tienen el poder de volverse realidad—actua con audacia y confia en tu vision unica.' },
      { ko: '남들과 다른 방식으로 세상을 보는 당신의 시선이 오늘 가장 빛나는 자산이 됩니다. 천왕성의 강력한 혁신 에너지가 당신의 독창적인 아이디어에 날개를 달아, 불가능해 보이는 것들을 현실로 만들어줍니다. 그 특별한 생각을 세상과 나눌 용기를 내어보세요—미래는 당신 같은 혁신가들이 만들어갑니다.', en: 'Your original perspective amazes those around you today, revealing paths that others simply cannot see. The unconventional lens through which you view the world is your greatest strength right now. Step forward with confidence—your unique vision is exactly what is needed.', zh: '你独创性的视角让周围人惊讶，别人看不到的路在你眼前清晰可见。这种与众不同的洞察力是你今天最宝贵的财富，勇敢地分享你的独特想法吧。', ja: 'あなたの独創的な視点が周囲を驚かせます。他の人が見えない道がはっきり見え、その独自の視点こそが今日最大の強みです。自信を持って前に進んでください。', es: 'Tu perspectiva original sorprende a quienes te rodean hoy, revelando caminos invisibles para otros. Esta capacidad de ver el mundo de manera diferente es tu mayor fortaleza—comparte tu vision unica con confianza.' },
      { ko: '오랫동안 당신을 가두었던 틀에서 마침내 벗어나는 해방의 기운이 온몸에 퍼집니다. 자유로운 에너지가 충만한 이 날은 진정한 나로 살아가는 첫걸음을 내딛기에 완벽한 타이밍입니다. 두려움 없이 제약을 걷어내세요—진정한 물병자리의 힘은 자유에서 비롯됩니다.', en: 'A day brimming with liberated energy as you sense a powerful release from constraints that have held you back for far too long. This breakthrough feeling is real and aligned with Uranus\'s forward momentum. Embrace your freedom fully and take bold steps toward the life you truly envision.', zh: '充满自由能量的一天，长期束缚你的限制终于开始松动。这种解放的气息是真实的，勇敢地打破那些不再适合你的框架，拥抱真正属于你的自由。', ja: '自由なエネルギーに満ちた一日です。長く縛られていた制約から解放される気運が感じられ、それは本物の突破口です。真の水瓶座の力は自由から生まれます—勇気を持って踏み出してください。', es: 'Un dia lleno de energia libre donde sientes la liberacion de restricciones antiguas que ya no te sirven. Esta sensacion de breakthrough es real—abrazar tu libertad con audacia y da pasos decisivos hacia la vida que imaginas.' },
      { ko: '혼자 빛나는 별보다 별자리를 이루는 당신의 헌신이 오늘 최고의 결실을 맺습니다. 공동체를 위해 쏟아온 노력이 구체적인 형태로 되돌아오며, 함께하는 기쁨이 개인의 성취보다 훨씬 크다는 것을 실감하는 날입니다. 더 많은 사람을 이 빛 안으로 초대하세요—연대의 힘이 당신의 가장 큰 자산입니다.', en: 'Your dedication to the community bears remarkable fruit today, proving that collective effort creates something far greater than individual achievement. The joy you experience through togetherness is multiplied and deeply fulfilling. Invite more people into this shared vision—your humanitarian spirit inspires those around you.', zh: '你对社区的奉献今天结出丰硕果实，集体的努力创造了远超个人成就的成果。共同分享的喜悦加倍，邀请更多人加入这个共同愿景，你的人道主义精神激励着周围的人。', ja: 'コミュニティへのあなたの献身が大きな実を結びます。集合的な努力が個人の達成をはるかに超えるものを生み出し、共にある喜びが倍増します。より多くの人をこの共有のビジョンに招いてください。', es: 'Tu dedicacion a la comunidad da grandes frutos hoy, demostrando que el esfuerzo colectivo supera al individual. La alegria que experimentas en conjunto es multiplicada—invita a mas personas a esta vision compartida y deja que tu espiritu humanitario inspire a quienes te rodean.' },
      { ko: '아직 아무도 보지 못한 미래를 당신은 오늘 선명하게 볼 수 있습니다. 이 예지적 직관은 천왕성이 주는 가장 귀한 선물로, 지금 떠오르는 생각들이 훗날 세상을 바꾸는 씨앗이 될 수 있습니다. 반드시 기록해 두고 가장 강렬한 아이디어에 실행 계획을 더해보세요.', en: 'Your intuition toward the future shines with remarkable clarity today, allowing you to see possibilities that others miss entirely. These forward-looking insights are gifts from Uranus and deserve to be captured and acted upon. Record your thoughts now and attach concrete plans to your most powerful visions.', zh: '你面向未来的直觉今天以惊人的清晰度闪耀，让你看到别人完全错过的可能性。一定要记录下现在浮现的想法，并为最有力的愿景制定具体计划。', ja: '未来に向けた直感が輝く日で、他の人が完全に見逃す可能性があなたには見えます。今浮かぶ考えを必ず記録しておき、最も力強いビジョンに具体的な実行計画を加えてください。', es: 'Tu intuicion hacia el futuro brilla con claridad notable hoy, permitiendote ver posibilidades que otros pasan por alto. Anota tus pensamientos ahora y adjunta planes concretos a tus visiones mas poderosas.' },
      { ko: '남의 눈치를 보지 않고 소신을 지켜온 당신에게 오늘 하늘이 최고의 격려를 보냅니다. 독립적인 정신은 물병자리의 핵심 정체성이며, 오늘 그 정체성에 충실한 결정이 당신에게 최고의 결과를 가져다줍니다. 흔들리지 말고 당신만의 길을 걸어가세요—역사는 언제나 독립적인 사람들이 만들었습니다.', en: 'The stars powerfully encourage your independent spirit today, affirming that your principled, self-directed choices lead to the best outcomes. Your refusal to follow the crowd is not stubbornness—it is wisdom. Walk your unique path with confidence, as history has always been shaped by those who dared to think differently.', zh: '星星今天有力地鼓励你独立的精神，印证了你有原则、自主的选择会带来最好的结果。坚守自己的信念走自己独特的路—历史总是由敢于不同思考的人书写的。', ja: '星々があなたの独立した精神を力強く励ましています。信念ある決定が最高の結果をもたらし、群れに従わないことは頑固ではなく知恵です。自信を持って独自の道を歩んでください。', es: 'Las estrellas alientan poderosamente tu espiritu independiente hoy, confirmando que tus decisiones con conviccion llevan a los mejores resultados. Camina tu camino unico con confianza—la historia siempre fue escrita por quienes se atrevieron a pensar diferente.' },
      { ko: '당신의 머릿속이 오늘 가장 빠르게 돌아가고 있습니다. 지적 호기심이 폭발하듯 터지는 이 날, 전혀 몰랐던 분야를 탐구해 보면 그것이 뜻밖의 행운으로 연결되는 놀라운 경험을 하게 됩니다. 아는 것의 경계를 의도적으로 넓혀보세요—지식의 확장이 곧 기회의 확장입니다.', en: 'Intellectual curiosity explodes within you today, making your mind sharper and faster than usual. Exploring an entirely new field or subject can lead to unexpected fortune and life-changing connections. Intentionally push the boundaries of what you know—expanding your knowledge directly expands your opportunities.', zh: '你的知识好奇心今天爆发，让你的思维比平时更敏锐快捷。探索全新的领域或主题可以带来意外的好运和改变人生的联系，有意识地拓展你所知道的边界吧。', ja: '知的好奇心が爆発する一日で、頭がいつもより鋭く速く動いています。全く新しい分野や主題を探求すれば思いがけない幸運と人生を変える出会いにつながります。知識の境界を意図的に広げてください。', es: 'La curiosidad intelectual estalla en ti hoy, haciendo tu mente mas aguda que de costumbre. Explorar un campo completamente nuevo puede traer fortuna inesperada y conexiones transformadoras—expande intencionalmente los limites de lo que sabes.' },
      { ko: '"이렇게 하면 안 된다"는 고정관념을 당신이 오늘 가장 당당하게 깨뜨릴 수 있습니다. 틀을 벗어난 시도를 두려워하지 않는 물병자리의 용기가 오늘 구체적인 보상으로 돌아오는 날로, 상식을 넘어서는 아이디어가 진짜 해답이 됩니다. 지금 당장 그 과감한 시도를 시작해 보세요.', en: 'Courage to break stereotypes is powerfully rewarded today—the universe is backing your unconventional instincts. Out-of-the-box attempts that others dismissed as unrealistic create truly amazing results now. The answer you have been looking for is not the obvious one; start that daring attempt right now.', zh: '打破固定观念的勇气今天得到有力的回报，宇宙支持你的非传统直觉。跳出框架的尝试创造惊人成果，你一直寻找的答案不是那个显而易见的，现在就开始那个大胆的尝试吧。', ja: '固定観念を打ち破る勇気が今日は力強く報われます。型を超えた試みが驚くべき成果を生み、宇宙があなたの型破りな直感を後押ししています。今すぐその大胆な挑戦を始めてください。', es: 'El valor de romper estereotipos es poderosamente recompensado hoy—el universo respalda tus instintos no convencionales. Los intentos fuera de lo comun crean resultados verdaderamente asombrosos ahora. Comienza ese atrevido intento de inmediato.' },
      { ko: '오늘 당신의 인맥은 단순한 연락처 목록이 아니라 기회를 만드는 살아있는 네트워크입니다. 오랫동안 연락이 끊겼던 인연이 예상치 못한 방식으로 새로운 문을 열어줄 수 있으니 먼저 손을 내밀어 보세요. 연결의 힘을 믿고 적극적으로 관계를 활성화하면 그 이상의 결과가 기다립니다.', en: 'The power of your network is maximized today, transforming your connections into a living engine of opportunity. Old bonds you had forgotten may surprise you by opening remarkable new doors. Reach out proactively, trust in the power of connection, and watch your network become your greatest asset.', zh: '你的人脉力量今天最大化，你的联系成为机会的活引擎。长久沉睡的缘分可能以意想不到的方式打开惊人的新大门，主动联系，相信连接的力量。', ja: 'ネットワークの力が最大化され、あなたのつながりが機会を生む生きたエンジンになります。古い縁が予想外の形で新しいドアを開いてくれるかもしれません。積極的に連絡を取り、つながりの力を信頼してください。', es: 'El poder de tu red se maximiza hoy, convirtiendo tus conexiones en un motor vivo de oportunidades. Viejos vinculos pueden sorprenderte abriendo nuevas puertas notables—comunicate proactivamente y confia en el poder de la conexion.' },
      { ko: '변화를 두려워하지 않고 준비해 온 당신에게 드디어 하늘이 "지금이야"라고 말하는 날입니다. 변화의 바람이 강하게 당신 편에서 불고 있어, 그동안 갈고 닦아온 혁신적 계획을 실행에 옮길 최적의 타이밍이 도달했습니다. 망설이지 말고 첫 발을 내딛으세요—준비된 자에게 기회는 반드시 옵니다.', en: 'The winds of change blow powerfully in your favor today, signaling the optimal moment to execute the innovative plans you have carefully been preparing. This alignment of energy and readiness is rare—do not hesitate. Take that decisive first step now, because you are fully prepared for this moment.', zh: '变革之风今天有力地吹向你的方向，标志着执行你精心准备的创新计划的最佳时机已经到来。这种能量与准备的结合是罕见的，不要犹豫，迈出那决定性的第一步。', ja: '変化の風が力強くあなたの味方になっています。これまで準備してきた革新的な計画を実行する最適なタイミングが到来しました。ためらわずに最初の一歩を踏み出してください。', es: 'Los vientos de cambio soplan poderosamente a tu favor hoy, senalando el momento optimo para ejecutar tus planes innovadores. Esta alineacion de energia y preparacion es rara—no dudes. Da ese primer paso decisivo ahora.' },
    ],
    medium: [
      { ko: '높은 이상을 품는 것은 물병자리의 본능이지만, 오늘은 현실과 이상 사이의 거리를 냉철하게 바라볼 필요가 있습니다. 완벽한 이상을 고집하는 대신 지금 할 수 있는 최선에서 출발하는 유연함이 오히려 더 빠른 길이 됩니다. 작은 현실적 한 걸음이 큰 이상에 가까워지는 진짜 방법입니다.', en: 'A day to thoughtfully balance your high ideals with practical reality—both matter equally today. Rather than insisting on perfection, a flexible attitude that starts from where you are now is actually the faster path forward. Small realistic steps are the true bridge to your grand vision.', zh: '需要在理想和现实之间取得平衡的一天，两者今天都同样重要。与其坚持完美，从现在的位置出发的灵活态度反而是更快的前进之路，小小的现实步骤才是通往宏大愿景的真正桥梁。', ja: '理想と現実の間でバランスを取る必要がある一日です。完璧を主張するより今いる場所から出発する柔軟な態度が実は近道です。小さな現実的な一歩が大きな理想に近づく本当の方法です。', es: 'Un dia para equilibrar tus altos ideales con la realidad practica—ambos importan por igual hoy. En lugar de insistir en la perfeccion, una actitud flexible es en realidad el camino mas rapido. Pequenos pasos realistas son el verdadero puente hacia tu gran vision.' },
      { ko: '혁신을 사랑하는 당신에게 반복되는 일상이 오늘따라 더 답답하게 느껴질 수 있습니다. 하지만 이것은 변화가 필요하다는 내면의 신호이지, 실패의 표시가 아닙니다. 점심 메뉴를 바꾸거나 새로운 음악을 듣는 것처럼 작은 변화 하나라도 시도해 보세요—작은 파문이 큰 파도를 만듭니다.', en: 'Daily routine may feel a bit stifling today, which is actually your inner signal that you need a dose of novelty. This restlessness is not a flaw—it is your innovative nature asking for stimulation. Try even one small change, however minor; small ripples have a way of becoming transformative waves.', zh: '日常惯例今天可能感觉有些沉闷，这实际上是你的内心信号，说明你需要一些新鲜感。这种不安分不是缺点，而是你的创新天性在寻求刺激。尝试一个小变化，小涟漪会变成大浪潮。', ja: '日常のルーティンが少し息苦しく感じるかもしれませんが、これは新鮮さが必要という内なるサインです。この落ち着きのなさはあなたの革新的な本性が刺激を求めているのです。小さな変化でも試してみてください。', es: 'La rutina diaria puede sentirse algo asfixiante hoy, lo cual es realmente una senal interna de que necesitas novedad. Esta inquietud no es un defecto—es tu naturaleza innovadora. Intenta aunque sea un pequeno cambio; las pequenas ondas se convierten en olas transformadoras.' },
      { ko: '아이디어가 넘쳐나는 당신이 오늘은 말하는 것보다 듣는 것에 더 집중해야 할 때입니다. 주변 사람들과의 소통에 조금 더 신경을 쓰면, 그 안에서 당신의 아이디어를 완성시켜 줄 중요한 단서를 발견할 수 있습니다. 경청은 수동적인 행위가 아니라, 정보를 모으는 가장 강력한 능동적 전략입니다.', en: 'You need to put more conscious effort into communicating with those around you today, particularly in the art of listening. There are valuable clues hidden in what others are saying that can complete your own ideas. Remember that listening is not passive—it is the most powerful active strategy for gathering intelligence.', zh: '今天你需要更加注意与周围人的沟通，特别是倾听的艺术。他人所说的话中隐藏着能完善你想法的宝贵线索。记住，倾听不是被动的，而是收集信息最强大的主动策略。', ja: '周りの人とのコミュニケーションにもう少し気を配る必要があります。特に傾聴の技術において。他の人が言っていることの中にあなた自身のアイデアを完成させる貴重なヒントが隠れています。傾聴は受動的な行為ではなく最も強力な情報収集戦略です。', es: 'Necesitas poner mas esfuerzo consciente en comunicarte con quienes te rodean hoy, especialmente en el arte de escuchar. Hay pistas valiosas en lo que dicen otros que pueden completar tus ideas. Escuchar no es pasivo—es la estrategia activa mas poderosa.' },
      { ko: '아이디어가 넘쳐나는 것은 당신의 가장 큰 재능이지만, 오늘은 실행 없는 아이디어가 머릿속에서만 맴돌 수 있습니다. 이 모든 가능성 중에서 딱 하나를 선택해 오늘 반드시 첫 발을 내딛겠다는 우선순위를 정하는 것이 핵심입니다. 완성된 하나가 미완성된 열 개보다 훨씬 큰 가치를 지닙니다.', en: 'Ideas are abundant but execution may lag behind today—your mind is generating more possibilities than you can act on at once. The key is to choose just one idea and commit to taking a first concrete step on it today. One completed action is worth far more than ten brilliant thoughts left unexecuted.', zh: '想法丰富但今天执行力可能跟不上，你的思维产生的可能性超过你一次能行动的数量。关键是选择一个想法，并承诺今天采取第一个具体步骤。一个完成的行动远比十个未执行的想法更有价值。', ja: 'アイデアは豊富ですが今日は実行が遅れるかもしれません。心がいっぺんに対応できる以上の可能性を生み出しています。一つのアイデアを選んで今日具体的な最初の一歩を踏み出すことを約束してください。', es: 'Las ideas abundan pero la ejecucion puede rezagarse hoy—tu mente genera mas posibilidades de las que puedes actuar a la vez. La clave es elegir una idea y comprometerte a dar un primer paso concreto hoy. Una accion completada vale mas que diez brillantes pensamientos sin ejecutar.' },
      { ko: '뇌는 새로운 자극이 없으면 가장 빠르게 지칩니다. 오늘 평소와 다른 사소한 변화 하나가 당신의 창의성을 깨우는 스위치가 될 수 있습니다. 출퇴근 경로, 점심 메뉴, 작업 순서 중 무엇이든 바꿔보세요—익숙한 것을 낯설게 만드는 것이 혁신의 씨앗입니다.', en: 'A small change from your daily norm can provide exactly the new stimulation your mind needs today. Your brain craves novelty, and even something as simple as changing your commute route or lunch choice can spark fresh ideas. Make the familiar feel unfamiliar—that small shift is where innovation begins.', zh: '与日常不同的一个小变化可以为你的思维提供所需的新刺激。你的大脑渴望新鲜感，即使是改变通勤路线这样简单的事情也能激发新想法。让熟悉的事物感觉陌生，这就是创新的开始。', ja: 'いつもと違う些細な変化が今日の心に必要な新しい刺激を与えてくれます。脳は新鮮さを求めています。通勤ルートを変えるだけでも新しいアイデアが生まれます。慣れ親しんだものを非日常的に感じさせること、それが革新の始まりです。', es: 'Un pequeno cambio de tu norma diaria puede proporcionar exactamente la nueva estimulacion que tu mente necesita hoy. Tu cerebro anhela novedad, y algo tan simple como cambiar tu ruta puede despertar ideas frescas—hacer lo familiar sentirse extrano es donde comienza la innovacion.' },
      { ko: '당신은 혼자 해낼 수 있는 능력을 갖고 있지만, 오늘만큼은 어느 일이 혼자의 힘으로 빛나고 어느 일이 협력으로 완성되는지를 구별하는 지혜가 필요합니다. 모든 것을 혼자 하려는 것은 독립심이 아니라 비효율입니다. 팀의 힘을 빌리면 당신의 빛이 더 크게 퍼집니다.', en: 'Wisdom to distinguish between tasks requiring your independent focus and those needing collaborative input is essential today. Insisting on doing everything alone is not independence—it is inefficiency. When you leverage the strength of others, your own light radiates even further than it could alone.', zh: '今天需要区分哪些任务需要你独立专注，哪些需要协作投入的智慧。坚持独自完成所有事情不是独立，而是低效。当你借助他人的力量时，你自己的光芒会传播得更远。', ja: '独立した集中が必要な作業と協力が必要な作業を区別する知恵が今日は必要です。すべてを一人でやろうとすることは独立心ではなく非効率です。他者の力を借りれば自分の光はさらに遠くまで届きます。', es: 'La sabiduria para distinguir entre tareas que requieren tu enfoque independiente y las que necesitan colaboracion es esencial hoy. Insistir en hacerlo todo solo no es independencia—es ineficiencia. Cuando aprovechas la fuerza de otros, tu propia luz irradia aun mas lejos.' },
      { ko: '폭발적인 에너지로 달려가던 천왕성도 오늘은 잠시 숨을 고르는 날입니다. 이 조용한 시간은 낭비가 아니라, 다음 도약을 위한 필수적인 재충전 구간입니다. 내면을 고요히 들여다보며 당신이 정말 원하는 것이 무엇인지 다시 확인해 보세요—방향이 명확해질수록 에너지는 더 강력해집니다.', en: 'Uranus\' energy is calm today, creating a natural pause in your forward momentum. This quieter period is not wasted time—it is essential recharging that fuels your next great leap. Use this space for inner reflection to clarify what you truly want; the clearer your direction, the more powerful your energy becomes.', zh: '天王星的能量今天平静，在你前进的势头中创造了一个自然的暂停。这段较安静的时期不是浪费时间，而是为你下一次巨大飞跃提供燃料的必要充电。利用这个空间进行内省，澄清你真正想要的东西。', ja: '天王星のエネルギーが静かな日で、前進の勢いに自然な休止が生まれます。この静かな時間は無駄ではなく、次の大きな飛躍への必要な充電です。内省の機会として自分が本当に望むことを明確にしてください。', es: 'La energia de Urano esta tranquila hoy, creando una pausa natural en tu impulso. Este periodo mas quieto no es tiempo perdido—es la recarga esencial que alimenta tu proximo gran salto. Usa este espacio para reflexionar y clarificar lo que verdaderamente deseas.' },
      { ko: '변화를 간절히 원할수록 지연이 더 크게 느껴지는 법입니다. 기대했던 변화가 조금 미뤄지고 있다면, 그것은 우주가 더 완벽한 타이밍을 준비 중이라는 숨겨진 신호일 수 있습니다. 인내심을 갖고 과정을 신뢰하세요—지연된 기회는 종종 더 크고 좋은 형태로 돌아옵니다.', en: 'Expected changes may be slightly delayed today, which can feel frustrating for someone with your forward-thinking nature. Consider that this delay may be the universe fine-tuning the timing for something even better. Be patient and trust the process—delayed opportunities often return in a bigger and better form.', zh: '期待的变化今天可能稍有延迟，对于你这种前瞻性思维的人来说可能会感到沮丧。考虑这种延迟可能是宇宙在为更好的东西微调时机。保持耐心，信任过程——延迟的机会往往以更好的形式回来。', ja: '期待していた変化が少し遅れるかもしれませんが、それはもっと良いものの時機を宇宙が調整しているサインかもしれません。忍耐心を持ちプロセスを信頼してください。遅れた機会はしばしばより大きく良い形で戻ってきます。', es: 'Los cambios esperados pueden retrasarse un poco hoy, lo que puede frustrarte con tu naturaleza visionaria. Considera que este retraso puede ser el universo ajustando el momento para algo aun mejor. Ten paciencia y confia—las oportunidades retrasadas suelen regresar en mejor forma.' },
      { ko: '모든 것에 관심을 갖는 것이 당신의 본성이지만, 오늘은 그 관심이 사방으로 흩어지며 정작 중요한 것에 집중하기 어려워질 수 있습니다. 숨을 한 번 깊게 들이쉬고, 오늘 반드시 완성해야 할 단 하나의 일에 에너지를 집중해 보세요—선택과 집중이 오늘의 가장 혁신적인 전략입니다.', en: 'A day when your naturally wide-ranging interests scatter in many directions, making deep focus challenging. Take a breath and deliberately channel your energy into just one thing that must be completed today. Selective focus is your most innovative strategy right now—depth beats breadth today.', zh: '你天然广泛的兴趣今天可能向四面八方分散，使深度专注变得困难。深呼吸，有意识地将能量集中在今天必须完成的一件事上。选择性专注是你目前最有创新性的策略。', ja: '様々な関心事が分散しやすい日です。深呼吸をして今日完成しなければならない一つのことにエネルギーを集中してみてください。選択と集中が今日最も革新的な戦略です。深さが広さに勝ります。', es: 'Un dia donde tus intereses naturalmente amplios se dispersan en muchas direcciones. Respira profundo y canaliza deliberadamente tu energia en una sola cosa que deba completarse hoy. El enfoque selectivo es tu estrategia mas innovadora ahora—la profundidad supera a la amplitud hoy.' },
      { ko: '세상을 더 나은 곳으로 만들고 싶은 열망과 지금 당장 나 자신을 돌봐야 하는 필요 사이에서 갈등을 느낄 수 있습니다. 이것은 나쁜 것이 아니라, 당신이 진정으로 깊이 있는 사람이라는 증거입니다. 자신을 충분히 돌봐야 세상도 더 잘 돌볼 수 있음을 기억하세요—두 가지 모두 동등하게 중요합니다.', en: 'You may feel torn between your deep commitment to universal values and your very real personal needs today. This tension is not a flaw—it is evidence of your genuine depth and compassion. Remember that you must care for yourself fully before you can truly care for the world; both needs matter equally.', zh: '今天你可能感到在对普遍价值的深切承诺和你非常真实的个人需求之间纠结。这种张力不是缺点，而是你真正深度和同情心的证明。记住，你必须先充分照顾自己，才能真正照顾世界。', ja: '普遍的な価値への深いコミットメントと個人的なニーズの間で葛藤するかもしれません。この緊張は欠点ではなく、あなたの本物の深さと思いやりの証拠です。世界を真にケアする前に自分自身を十分にケアする必要があることを覚えておいてください。', es: 'Puedes sentirte dividido/a entre tu compromiso con valores universales y tus necesidades personales reales hoy. Esta tension no es un defecto—es evidencia de tu genuina profundidad. Recuerda que debes cuidarte completamente antes de poder cuidar verdaderamente al mundo; ambas necesidades importan por igual.' },
    ],
    low: [
      { ko: '변화를 즐기는 당신도 완전히 예상 밖의 변수 앞에서는 당황할 수 있습니다. 이런 혼돈은 일시적이며, 당신의 유연한 사고방식이 이 상황을 헤쳐나갈 최고의 도구입니다. 감정적 결정은 잠시 유보하고 심호흡 한 번으로 상황을 객관적으로 바라보는 순간, 해결의 실마리가 보일 것입니다.', en: 'Sudden unexpected variables may throw you off today, even though you generally embrace change. This turbulence is temporary, and your naturally flexible thinking is the best tool you have to navigate it. Pause before any major decisions, take a breath, and view the situation objectively—clarity will follow quickly.', zh: '突发意外变数今天可能让你措手不及，即使你通常欢迎变化。这种动荡是暂时的，你天然灵活的思维是应对的最佳工具。在做任何重大决定之前暂停，深呼吸，客观看待情况——清晰很快就会来临。', ja: '突然の予想外の変数に慌てるかもしれません。普段は変化を受け入れているあなたでも。この混乱は一時的で、柔軟な思考が乗り越えるための最良のツールです。重要な決定の前に一息ついて状況を客観的に見てください。', es: 'Variables repentinas pueden desconcertarte hoy, aunque generalmente aceptas los cambios. Esta turbulencia es temporal, y tu pensamiento flexible es la mejor herramienta para navegarla. Pausa antes de decisiones importantes, respira, y mira la situacion objetivamente—la claridad llegara pronto.' },
      { ko: '자신의 생각이 옳다는 확신이 강한 날일수록 오히려 한 걸음 물러서는 지혜가 필요합니다. 고집은 원칙과 다릅니다—타인의 의견을 듣는 것은 당신의 생각을 포기하는 것이 아니라 더 강하게 만드는 과정입니다. 겸손함은 약함이 아니라, 지적으로 가장 강한 사람들이 갖는 특성입니다.', en: 'Stubbornness comes more easily today, but this is precisely the moment when humility serves you best. Listening to others\' opinions is not giving up your own perspective—it is a process of strengthening your thinking. Remember that intellectual humility is not weakness; it is the trait of the most genuinely strong thinkers.', zh: '今天固执更容易出现，但这正是谦逊最能为你服务的时刻。倾听他人意见不是放弃自己的观点，而是强化你思维的过程。记住，知识上的谦逊不是软弱，而是真正强大思考者的特质。', ja: '頑固になりやすい日ですが、これこそ謙虚さが最も役立つ瞬間です。他人の意見を聞くことは自分の視点を諦めることではなく、思考を強化するプロセスです。知的な謙虚さは弱さではなく、本当に強い思考者の特質です。', es: 'La terquedad surge mas facilmente hoy, pero este es precisamente el momento en que la humildad te sirve mejor. Escuchar a otros no es abandonar tu perspectiva—es fortalecer tu pensamiento. La humildad intelectual no es debilidad; es el rasgo de los pensadores genuinamente fuertes.' },
      { ko: '혁신가는 계획이 무너졌을 때 더 창의적으로 빛납니다. 예상치 못한 방해 요소가 오늘 당신의 계획을 흔들 수 있지만, 이것이 끝이 아닙니다. 지금 당장 플랜 B를 미리 생각해 두면, 그 대안이 원래 계획보다 훨씬 나은 결과를 가져올 수도 있습니다—장애물을 새로운 방향의 표지판으로 읽어보세요.', en: 'Unexpected obstacles may shake your plans today, but true innovators shine most brightly when plans fall apart. Have a Plan B ready now—often the alternative path turns out better than the original. Try reading each obstacle as a signpost pointing toward a new and better direction rather than a roadblock.', zh: '意想不到的干扰因素今天可能动摇你的计划，但真正的创新者在计划崩溃时最耀眼。现在准备好B计划——往往替代路径比原计划更好。试着把每个障碍读作指向新的更好方向的路标，而不是路障。', ja: '予想外の妨害要素が計画を揺さぶる可能性があります。しかし真の革新者は計画が崩れたときに最も輝きます。今すぐプランBを準備してください。代替ルートが元の計画より良くなることが多いです。障害を新しい方向への道標として読んでみてください。', es: 'Obstaculos inesperados pueden sacudir tus planes hoy, pero los verdaderos innovadores brillan mas cuando los planes se deshacen. Ten un Plan B listo ahora—a menudo el camino alternativo resulta mejor que el original. Lee cada obstaculo como un indicador hacia una nueva y mejor direccion.' },
      { ko: '당신의 독립적인 에너지가 오늘 주변 사람들에게 거리감으로 느껴질 수 있습니다. 고립이 아닌 자유를 원하는 것이지만, 상대방은 그 차이를 알기 어렵습니다. 의도적으로 따뜻한 말 한마디를 건네거나 짧은 연락 하나를 보내는 작은 노력이 관계의 온도를 지켜줄 것입니다.', en: 'Distance from those around you may grow today as your independent energy can feel like withdrawal to others. You want freedom, not isolation—but others cannot always tell the difference. A single intentional warm word or brief message can preserve the warmth in relationships that matter to you.', zh: '与周围人的距离感今天可能扩大，因为你的独立能量对他人来说可能感觉像撤退。你想要的是自由而不是孤立，但他人不总能分辨区别。一句有意识的温暖话语或简短消息可以维护对你重要的关系温度。', ja: '周囲との距離感が大きくなりやすい日です。あなたの独立したエネルギーが他者には引きこもりのように感じられることがあります。自由を望んでいることは孤立とは違いますが、相手にはわかりにくいです。意図的な温かい一言が大切な関係の温度を守ります。', es: 'La distancia con tu entorno puede crecer hoy, ya que tu energia independiente puede parecer alejamiento para otros. Quieres libertad, no aislamiento—pero otros no siempre pueden distinguirlo. Una sola palabra calida intencional puede preservar la calidez en relaciones que te importan.' },
      { ko: '높은 이상을 가진 사람일수록 현실과의 간극에서 오는 좌절감도 깊습니다. 오늘 그 감정이 강하게 밀려올 수 있지만, 완벽하지 않아도 진전은 분명히 이루어지고 있다는 사실을 기억하세요. 과거의 당신과 오늘의 당신을 비교해 보세요—당신은 이미 놀라운 거리를 걸어왔습니다.', en: 'Frustration over your ideals may surge strongly today—the higher the standard, the deeper the gap can feel. But remember with certainty that progress is absolutely happening, even when it is invisible to you. Compare today\'s you with who you were months ago; you have already traveled a remarkable distance.', zh: '对理想的挫败感今天可能强烈涌来——标准越高，差距感越深。但请确信进步绝对在发生，即使你看不见。将今天的你与几个月前的你比较，你已经走了一段了不起的距离。', ja: '理想に対する挫折感が強く押し寄せるかもしれません。基準が高いほど差を深く感じます。しかし進展は確実に起きていることを覚えておいてください。数ヶ月前の自分と今の自分を比べてみてください、あなたは既に驚くべき距離を歩んできています。', es: 'La frustracion por tus ideales puede surgir fuertemente hoy—cuanto mas alto el estandar, mas profunda la brecha. Pero recuerda con certeza que el progreso absolutamente esta ocurriendo. Compara el tu de hoy con quien eras meses atras—ya has recorrido una distancia notable.' },
      { ko: '천왕성의 에너지가 불안정하게 요동치는 오늘은 충동적인 결단이 나중에 후회로 이어질 수 있습니다. 지금 이 불안정함은 일시적인 것이며, 내일이면 훨씬 더 명확한 시야가 열릴 것입니다. 중요한 결정은 하루만 미루고, 오늘은 정보를 모으고 마음을 가다듬는 데 집중하세요.', en: 'Uranus\' unstable energy is strongly felt today, and impulsive decisions made now may lead to regret later. This turbulence is temporary—tomorrow will bring a far clearer perspective. Postpone important decisions just one day, and use today to gather information and find your inner calm.', zh: '今天强烈感受到天王星不稳定的能量，现在做出的冲动决定以后可能会后悔。这种动荡是暂时的，明天会带来更清晰的视角。把重要决定推迟一天，今天用来收集信息并找到内心的平静。', ja: '天王星の不安定なエネルギーが強く感じられます。今衝動的にした決定は後悔につながる可能性があります。この動乱は一時的で明日はずっと明確な視点が開けるでしょう。重要な決定を一日延期して今日は情報を集め内なる穏やかさを見つけることに集中してください。', es: 'La energia inestable de Urano se siente fuertemente hoy, y las decisiones impulsivas hechas ahora pueden llevar al arrepentimiento. Esta turbulencia es temporal—manana traera una perspectiva mucho mas clara. Pospón decisiones importantes un dia y usa hoy para reunir informacion y encontrar tu calma interior.' },
      { ko: '혼자서 모든 것을 해내려는 의지가 강할수록, 그 벽이 당신을 고립시킬 수 있습니다. 도움을 요청하는 것은 의존이 아니라 용기이며, 협력은 독립심을 포기하는 것이 아닙니다. 가장 혁신적인 성과들은 대부분 혼자가 아닌 연결된 사람들이 만들어냈다는 사실을 기억하세요.', en: 'Excessive independence may invite isolation today—the stronger the desire to do it all alone, the higher the wall you build around yourself. Asking for help is not dependency; it is genuine courage. Remember that the most innovative achievements are almost always created by connected people, not solitary ones.', zh: '过度独立今天可能导致孤立——越想独自完成一切，你建造的围墙就越高。寻求帮助不是依赖，而是真正的勇气。记住，最具创新性的成就几乎总是由相互连接的人创造的，而不是孤独的人。', ja: '過度な独立心がかえって孤立を招く可能性があります。一人でやり遂げたい欲求が強いほど、自分の周りに高い壁を作ってしまいます。助けを求めることは依存ではなく本物の勇気です。最も革新的な成果はほぼ常につながった人々によって作られています。', es: 'La independencia excesiva puede invitar al aislamiento hoy—cuanto mas fuerte el deseo de hacerlo todo solo, mas alta la barrera que construyes. Pedir ayuda no es dependencia; es valentia genuina. Los logros mas innovadores casi siempre son creados por personas conectadas, no solitarias.' },
      { ko: '무한한 가능성을 품은 당신에게 반복되는 일상이 오늘은 감옥처럼 느껴질 수 있습니다. 이 답답함은 당신이 더 큰 것을 향해 태어났다는 신호입니다. 지금 당장 15분이라도 밖으로 나가 걸으세요—신선한 공기와 움직임이 막혀 있던 에너지를 순환시켜 줄 것입니다.', en: 'A day of feeling greatly stifled by repetitive daily life—for someone of your boundless curiosity, routine can feel like a cage. This restlessness is a signal, not a problem; it tells you that you are meant for something bigger. Even a short fifteen-minute walk outside can unblock your circulating energy and bring relief.', zh: '对重复日常感到非常沉闷的一天——对于像你这样有无限好奇心的人来说，惯例可能感觉像牢笼。这种不安是一个信号，不是问题，它告诉你你注定要成就更大的事情。即使短短15分钟的户外散步也能疏通你的能量带来解脱。', ja: '繰り返される日常に大きな息苦しさを感じる日です。あなたのような無限の好奇心を持つ人にとって、ルーティンは牢屋に感じられることがあります。この落ち着きのなさは問題ではなくシグナルです。短い散歩でも気分転換に役立ちます。', es: 'Un dia de sentirse muy agobiado por lo cotidiano—para alguien de tu curiosidad sin limites, la rutina puede sentirse como una jaula. Esta inquietud es una senal, no un problema; te dice que estas destinado/a a algo mayor. Incluso un paseo corto de quince minutos puede desbloquear tu energia.' },
      { ko: '평소에는 토론을 즐기는 당신이지만, 오늘은 신경이 예민해져 있어 논쟁이 불필요하게 격해질 수 있습니다. 이 예민함은 일시적인 것이며, 에너지를 소모적인 마찰보다 회복에 쓰는 것이 더 현명한 선택입니다. 오늘은 이기는 것보다 보존하는 것이 훨씬 가치 있습니다.', en: 'You are easily sensitized today, so avoid arguments or debates if at all possible—what you normally enjoy can turn unnecessarily heated now. This heightened sensitivity is temporary, and spending your energy on recovery rather than friction is the wiser choice. Today, preserving yourself is worth far more than winning.', zh: '今天你容易变得敏感，所以尽量避免争论或辩论——你平时享受的东西现在可能变得不必要地激烈。这种高度敏感是暂时的，将能量花在恢复而不是摩擦上是更明智的选择。今天，保存自己远比赢得争论更有价值。', ja: '敏感になりやすい日なので議論や討論はなるべく避けてください。普段楽しんでいることも今は不必要に白熱する可能性があります。この高まった感受性は一時的です。摩擦より回復にエネルギーを使う方が賢明です。', es: 'Estas facilmente sensible hoy, asi que evita discusiones si es posible—lo que normalmente disfrutas puede volverse innecesariamente acalorado ahora. Esta sensibilidad elevada es temporal. Usar tu energia en recuperarte en lugar de fricciones es la eleccion mas sabia hoy.' },
      { ko: '변화는 물병자리의 본능이지만, 오늘은 너무 빠른 변화가 지금 당신이 쌓아온 안정의 기반을 흔들 수 있습니다. 변화를 원하는 마음은 옳지만, 지금은 타이밍을 재는 지혜가 필요합니다. 신중하게 한 발자국씩 움직이세요—혁신은 속도가 아니라 방향이 결정합니다.', en: 'Pursuing change may destabilize existing stability today—your instinct for transformation is right, but the timing needs calibration. Move cautiously and thoughtfully, step by measured step. True innovation is determined not by speed but by direction; getting the direction right now protects everything you have built.', zh: '追求变化今天可能动摇现有的稳定——你对变革的本能是对的，但时机需要校准。谨慎地一步一步移动。真正的创新不是由速度决定的，而是由方向决定的，现在把方向搞对可以保护你已经建立的一切。', ja: '変化を追求して既存の安定を揺るがす可能性があります。変革への本能は正しいですが、タイミングの調整が必要です。慎重に一歩一歩動いてください。真の革新は速度ではなく方向が決めます。', es: 'Buscar cambios puede desestabilizar la estabilidad existente hoy—tu instinto transformador es correcto, pero el momento necesita calibracion. Muevete con cautela, paso a paso. La verdadera innovacion es determinada por la direccion, no la velocidad; acertar la direccion ahora protege todo lo que has construido.' },
    ],
  },
  love: {
    high: [
      { ko: '당신에게 사랑은 마음만이 아니라 지성으로도 이루어집니다. 오늘 깊고 솔직한 대화가 상상 이상의 감정적 교감으로 이어지는 특별한 경험을 할 수 있습니다. 마음을 활짝 열고 생각을 나누어 보세요—지적인 연결이 가장 깊은 사랑의 문을 여는 열쇠입니다.', en: 'Intellectual conversation leads to deep emotional connection today in a way that feels genuinely special. For you, love is built through the mind as much as the heart, and today that truth shines brightly. Open your heart and share your thoughts freely—intellectual connection is the key that unlocks your deepest love.', zh: '知识性对话今天以真正特别的方式引向深层情感连接。对你来说，爱是通过思想和心灵共同建立的，今天这个真理闪耀着光芒。敞开心扉，自由分享你的想法——智识连接是打开你最深爱情的钥匙。', ja: '知的な会話が深い感情的な交感につながる日で、本当に特別な感覚があります。あなたにとって愛は心だけでなく知性でも築かれます。心を開いて思いを自由に分かち合ってください。', es: 'La conversacion intelectual lleva a una conexion emocional profunda hoy de una manera genuinamente especial. Para ti, el amor se construye tanto a traves de la mente como del corazon—abre tu corazon y comparte tus pensamientos libremente.' },
      { ko: '같은 자유를 꿈꾸는 영혼끼리만 느낄 수 있는 독특한 끌림이 오늘 강하게 작동합니다. 사람들이 모이는 자리나 공통 관심사를 나누는 커뮤니티에서 운명적인 인연이 기다리고 있을 수 있습니다. 먼저 손을 내밀고 당신의 세계관을 나눠보세요—진정한 연결은 공통된 비전에서 시작됩니다.', en: 'There is a fateful energy drawing free spirits together today in a uniquely powerful way. Someone who shares your vision and love of freedom may be waiting in a gathering or community you are part of. Reach out first and share your worldview—true connection always begins with a shared vision of something greater.', zh: '今天有一种命运般的能量将自由灵魂吸引在一起，以独特而有力的方式。一个分享你愿景和自由精神的人可能在你所在的聚会或社区中等待。主动联系并分享你的世界观——真正的连接总是从共同的愿景开始。', ja: '自由な魂同士が引き合う運命的な出会いの気運が今日は特に強く働いています。あなたのビジョンと自由への愛を共有する人が集まりやコミュニティで待っているかもしれません。先に手を伸ばして世界観を分かち合ってください。', es: 'Hay una energia fatal que atrae espiritus libres hoy de manera singularmente poderosa. Alguien que comparte tu vision puede estar esperando en una reunion o comunidad. Extiende la mano primero y comparte tu cosmosvision—la verdadera conexion siempre comienza con una vision compartida.' },
      { ko: '함께 성장하는 관계가 당신에게 가장 이상적인 사랑의 형태입니다. 파트너와 새로운 도전을 함께 시작하면 두 사람의 관계가 한층 깊어지는 것을 느낄 수 있을 것입니다. 함께 배울 수 있는 것이 있다면 오늘 바로 제안해 보세요—공동의 성장이 가장 강한 유대를 만들어냅니다.', en: 'Starting a new challenge with your partner deepens your relationship in the most meaningful way—you believe in growing together. Propose something you can both learn or explore today; this shared growth creates the strongest kind of bond. Together you become something neither of you could be alone.', zh: '与伴侣一起开始新挑战以最有意义的方式加深关系，因为你相信共同成长。今天提议一件你们都可以一起学习或探索的事情，这种共同成长创造了最强的纽带。在一起，你们成为了各自单独无法成为的存在。', ja: 'パートナーと一緒に新しい挑戦を始めれば関係が最も意味深い形で深まります。一緒に学べることを今日提案してください。この共有の成長が最も強い絆を作り出します。一緒にいることで二人はそれぞれ単独では成れないものになります。', es: 'Iniciar un nuevo desafio con tu pareja profundiza la relacion de la manera mas significativa—crees en crecer juntos. Propone algo que ambos puedan aprender o explorar hoy; este crecimiento compartido crea el vinculo mas fuerte. Juntos se convierten en algo que ninguno podria ser por separado.' },
      { ko: '세상 어디에도 없는 당신만의 독특한 매력이 오늘 가장 강하게 빛납니다. 남들처럼 보이려는 노력을 내려놓고 있는 그대로의 모습을 보여줄 때, 상대방은 그 진정성에 진심으로 끌리게 됩니다. 오늘은 당신다움이 최고의 연애 전략입니다—세상에서 가장 매력적인 것은 진짜 당신입니다.', en: 'Your unique charm is maximized to its fullest today, and your most magnetic quality is simply being authentically yourself. Letting go of the effort to seem like others, and showing up exactly as you are, is what draws people to you most powerfully. Today, being you is the greatest strategy—authenticity is irresistible.', zh: '你独特的魅力今天达到最大值，你最有磁力的品质就是真实地做自己。放弃努力显得像其他人，展示真实的自己，这是最有力地吸引别人的方式。今天，做你自己是最好的策略——真实性是无法抗拒的。', ja: 'あなたの独特な魅力が最大限に輝く日で、最も魅力的な品質は本当の自分でいることです。他者に似ようとする努力を手放して、ありのままの自分を見せることが最も強く人を引きつけます。今日は本当のあなたが最高の戦略です。', es: 'Tu encanto unico alcanza su maximo hoy, y tu cualidad mas magnetica es simplemente ser autentico/a. Soltar el esfuerzo de parecer como otros, y mostrarte exactamente como eres, es lo que mas atrae a las personas. Hoy, ser tu mismo/a es la mayor estrategia—la autenticidad es irresistible.' },
      { ko: '물병자리는 우정을 가장 깊은 사랑의 토대로 봅니다. 오랫동안 알고 지낸 사람에게서 오늘 전혀 다른 감정이 싹틀 수 있는 에너지가 감지됩니다. 익숙하다고 생각했던 그 사람을 오늘만큼은 처음 보는 눈으로 바라보세요—우정 위에 꽃피는 사랑이 가장 오래 갑니다.', en: 'Energy is detected for a long friendship to blossom into love—Aquarius believes friendship is the deepest foundation of love. Look at someone you think you know well with genuinely fresh eyes today. Love that flowers on the foundation of friendship is often the most enduring and meaningful kind.', zh: '感受到长久友谊发展为爱情的气息——水瓶座相信友谊是爱情最深的基础。今天用真正新鲜的眼光看你认为熟悉的人。建立在友谊基础上的爱情往往是最持久、最有意义的。', ja: '長い友情が恋に発展する可能性のある気運が感じられます。水瓶座は友情が愛の最も深い基盤だと信じています。よく知っていると思う人を今日は本当に新しい目で見てみてください。友情の上に咲く愛が最も長続きします。', es: 'Se detecta energia para que una larga amistad florezca en amor—Acuario cree que la amistad es el fundamento mas profundo del amor. Mira a alguien que crees conocer bien con ojos genuinamente frescos hoy. El amor que florece sobre la amistad suele ser el mas duradero y significativo.' },
      { ko: '자신의 자유를 소중히 여기는 만큼 파트너의 개성도 온전히 존중하는 당신의 마음이 오늘 관계에 신선한 바람을 불어넣습니다. 서로 다름을 위협이 아닌 풍요로움으로 바라보는 이 자세가 관계를 더욱 깊고 건강하게 만들어줍니다. 오늘 파트너의 독특한 면을 진심으로 칭찬해 보세요.', en: 'Your respect for your partner\'s individuality breathes fresh, revitalizing air into the relationship today. Seeing your differences as richness rather than threat is a rare and beautiful gift in love. Genuinely compliment something uniquely theirs today—this recognition deepens the bond in ways nothing else can.', zh: '你对伴侣个性的尊重今天为关系注入清新、充满活力的空气。把你们的差异视为丰富而非威胁是爱情中罕见而美丽的礼物。今天真诚地称赞他们独特的某个方面——这种认可以任何其他方式无法做到的方式加深纽带。', ja: 'パートナーの個性を尊重する心が関係に新鮮で活力ある空気を吹き込みます。違いを脅威ではなく豊かさとして見ることは愛における稀で美しい贈り物です。今日は相手のユニークな一面を心から褒めてみてください。', es: 'Tu respeto por la individualidad de tu pareja infunde aire fresco y revitalizador en la relacion hoy. Ver vuestras diferencias como riqueza en lugar de amenaza es un regalo raro y hermoso en el amor. Elogia genuinamente algo unico de tu pareja hoy—este reconocimiento profundiza el vinculo.' },
      { ko: '예측 불가능함을 사랑하는 당신에게 오늘 하늘이 가장 잘 어울리는 선물을 준비해 두었습니다. 예상 밖의 로맨틱한 이벤트가 어딘가에서 기다리고 있으니, 계획에 얽매이지 말고 열린 마음으로 오늘 하루를 맞이해 보세요. 가장 특별한 순간은 언제나 계획하지 않은 곳에서 찾아옵니다.', en: 'An unexpected romantic event awaits you today—a perfect gift for someone who loves the unpredictable. Do not cling to your plans; welcome the day with a truly open heart and allow surprise to work its magic. The most special moments always arrive unplanned and unannounced.', zh: '意想不到的浪漫事件今天在等着你——对一个喜爱不可预测性的人来说是最完美的礼物。不要执着于计划，以真正开放的心态迎接这一天，让惊喜发挥它的魔力。最特别的时刻总是在计划之外不期而至。', ja: '予想外のロマンチックなイベントがあなたを待っています。予測不可能を愛するあなたへの最高の贈り物です。計画に縛られずオープンな心で一日を迎えてください。最も特別な瞬間はいつも計画外にやってきます。', es: 'Un evento romantico inesperado te espera hoy—un regalo perfecto para alguien que ama lo impredecible. No te aferres a tus planes; recibe el dia con el corazon verdaderamente abierto y deja que la sorpresa haga su magia. Los momentos mas especiales siempre llegan sin aviso.' },
      { ko: '오늘 파트너와 서로의 가장 깊은 이상과 꿈을 나누는 대화를 나눠보세요. 이런 이야기를 주고받는 시간이 두 사람 사이의 유대를 그 어떤 것보다 강하게 단단히 해줍니다. 미래에 대한 공통된 비전을 발견하는 순간, 당신들의 관계는 완전히 새로운 차원으로 올라갑니다.', en: 'Sharing your deepest ideals and dreams with your partner strengthens the bond between you in a way nothing else can. Make time for this kind of conversation today—discovering shared visions of the future elevates your relationship to an entirely new dimension. This is the intimacy your Aquarian soul craves most.', zh: '今天与伴侣分享你们最深的理想和梦想，以任何其他方式无法做到的方式加强纽带。今天为这种对话留出时间——发现对未来的共同愿景将你们的关系提升到全新维度。这是你水瓶座灵魂最渴望的亲密。', ja: '最も深い理想と夢をパートナーと分かち合うことで、他の何ものにも代えられない形で絆が強化されます。今日はこういった会話の時間を作ってください。未来への共通のビジョンを発見する瞬間、二人の関係は全く新しい次元に上がります。', es: 'Compartir tus ideales y suenos mas profundos con tu pareja fortalece el vinculo de una manera que nada mas puede. Dedica tiempo a este tipo de conversacion hoy—descubrir visiones compartidas del futuro eleva tu relacion a una dimension completamente nueva.' },
      { ko: '물병자리의 사랑 표현은 세상의 공식을 따르지 않습니다. 오늘 당신만이 할 수 있는 방식으로 상대에게 마음을 전하면, 그 진정성이 상대의 마음 가장 깊은 곳까지 닿게 됩니다. 형식이 아닌 진심이 담긴 당신만의 표현이 오늘 최고의 선물이 됩니다.', en: 'Your unique way of expressing love melts their heart today in a way conventional gestures never could. Aquarius love does not follow the world\'s formulas, and that originality is what makes it extraordinary. Convey your feelings in your own sincere, one-of-a-kind way—your authenticity is the greatest gift you can give.', zh: '你独特的爱情表达方式今天以传统姿态永远无法做到的方式融化他们的心。水瓶座的爱不遵循世界的公式，这种独创性正是它非凡之处。用你自己真诚独一无二的方式传达感情——你的真实性是你能给予的最大礼物。', ja: 'あなた独自の愛の表現が相手の心を溶かす日で、従来のジェスチャーには決してできない方法で。水瓶座の愛は世界の公式に従わず、その独創性こそが特別な理由です。あなた独自の真心を込めた方法で気持ちを伝えてください。', es: 'Tu forma unica de expresar amor derrite su corazon hoy de una manera que los gestos convencionales nunca podrian. El amor de Acuario no sigue las formulas del mundo, y esa originalidad es lo que lo hace extraordinario. Transmite tus sentimientos de tu manera autentica y unica.' },
      { ko: '오늘 당신의 정신적 동반자와의 연결이 어느 때보다 강해지는 시간이 찾아옵니다. 표면적인 이야기를 넘어 영혼 깊은 곳에서 울리는 대화를 나눠보세요. 이런 연결의 경험은 삶에서 가장 소중한 기억 중 하나가 될 것이며, 두 사람의 관계를 완전히 새로운 수준으로 끌어올립니다.', en: 'Connection with your spiritual companion strengthens powerfully today, creating space for conversations that resonate at the level of the soul. Go beyond surface talk and share what truly moves you. These moments of deep connection are among life\'s most precious, and they elevate your relationship to a completely new level.', zh: '你与精神伴侣的连接今天有力地加强，为灵魂深处共鸣的对话创造空间。超越表面话题，分享真正触动你的东西。这些深刻连接的时刻是生命中最宝贵的，它们将你们的关系提升到全新水平。', ja: '精神的な伴侶との繋がりが今日は力強く強まり、魂の深みで共鳴する会話のための空間を作ります。表面的な話を超えて本当に心を動かすことを分かち合ってください。これらの深い繋がりの瞬間は二人の関係を全く新しいレベルへ引き上げます。', es: 'La conexion con tu companero espiritual se fortalece poderosamente hoy, creando espacio para conversaciones que resuenan a nivel del alma. Ve mas alla de lo superficial y comparte lo que realmente te conmueve. Estos momentos de profunda conexion elevan tu relacion a un nivel completamente nuevo.' },
    ],
    medium: [
      { ko: '마음속에 있는 것을 언어로 정확히 옮기는 것이 오늘따라 더 어렵게 느껴질 수 있습니다. 감정 표현이 서툰 것처럼 보여 오해가 생길 수 있지만, 완벽한 문장보다 진심이 담긴 서툰 말이 훨씬 더 깊이 전달됩니다. 논리를 잠시 내려놓고 지금 느끼는 것을 그대로 전해보세요.', en: 'Clumsy emotional expression may cause misunderstanding today, but know that imperfect words carrying real sincerity reach far deeper than perfect logic ever could. Set aside the analytical part of your mind for a moment and just let what you genuinely feel come through—authenticity will bridge any gap.', zh: '今天不善表达感情可能产生误解，但要知道携带真心的不完美话语比完美的逻辑传达得更深远。暂时放下你分析的思维，只让你真正感受到的东西流露出来——真实性会弥合任何差距。', ja: '感情表現が下手で誤解が生じる可能性があります。しかし真心のこもった不完全な言葉は完璧な論理よりもはるかに深く伝わります。分析的な心を少し置いておいて、本当に感じていることをそのまま伝えてください。', es: 'La expresion emocional torpe puede causar malentendidos hoy, pero las palabras imperfectas con sinceridad genuina llegan mucho mas profundo que la logica perfecta. Pon a un lado la parte analitica de tu mente y simplemente deja que fluya lo que realmente sientes—la autenticidad cerrara cualquier brecha.' },
      { ko: '자유를 원하는 마음과 안정적인 관계를 원하는 마음이 오늘 팽팽하게 맞서고 있습니다. 이 둘은 반드시 충돌해야 하는 것이 아니라, 서로를 더 깊게 만드는 보완 관계가 될 수 있습니다. 상대방에게 당신이 필요로 하는 자유의 의미를 솔직하게 설명해 보세요—진정한 이해가 시작됩니다.', en: 'A day to balance the desire for freedom with the stability your relationship needs—these two forces are in active tension right now. They need not be in conflict; with honest conversation, they can become complementary. Explain to your partner what freedom genuinely means to you; understanding begins there.', zh: '需要在对自由的渴望和关系需要的稳定之间取得平衡的一天——这两种力量现在处于主动张力中。它们不必冲突，通过诚实的对话，它们可以变得互补。向伴侣解释自由对你真正意味着什么，理解从那里开始。', ja: '自由への欲求と関係の安定の間でバランスを取る必要がある日で、この二つの力が今活発な緊張状態にあります。対立する必要はなく、誠実な会話でお互いを補完するものになれます。自由が本当に何を意味するかをパートナーに説明してください。', es: 'Un dia para equilibrar el deseo de libertad con la estabilidad que tu relacion necesita—estas dos fuerzas estan en tension activa ahora. No tienen que estar en conflicto; con una conversacion honesta, pueden volverse complementarias. Explica a tu pareja lo que la libertad genuinamente significa para ti.' },
      { ko: '자신의 생각과 프로젝트에 몰두하다 보면, 파트너에게 충분한 시간과 에너지를 주지 못하고 있음을 잊기 쉽습니다. 오늘은 잠시 멈추고 솔직하게 돌아볼 필요가 있습니다. 작더라도 온전한 존재감으로 함께하는 30분이 분산된 마음으로 보내는 몇 시간보다 훨씬 소중합니다.', en: 'You need to honestly reflect on whether you are giving your partner enough of your time and genuine presence today. It is easy to get absorbed in your thoughts and projects, forgetting that relationships need regular attention. Even thirty minutes of fully focused presence is worth far more than hours of distracted togetherness.', zh: '今天你需要诚实地反思是否给了伴侣足够的时间和真正的陪伴。很容易被自己的想法和项目所吸引，忘记关系需要定期关注。即使是30分钟的全情专注陪伴，也远胜于几个小时的心不在焉的在一起。', ja: 'パートナーに十分な時間と真の存在感を与えているか今日は誠実に振り返る必要があります。自分の思いやプロジェクトに没頭して関係が定期的な関心を必要としていることを忘れがちです。完全に集中した30分はぼんやりした数時間よりはるかに価値があります。', es: 'Necesitas reflexionar honestamente si le estas dando a tu pareja suficiente tiempo y presencia genuina hoy. Es facil absorverse en tus pensamientos y proyectos, olvidando que las relaciones necesitan atencion regular. Incluso treinta minutos de presencia completamente enfocada vale mucho mas que horas de estar juntos distraidos.' },
      { ko: '머릿속의 완벽한 연애와 눈앞의 현실 관계 사이의 간극이 오늘 유독 크게 느껴질 수 있습니다. 완벽한 관계는 찾는 것이 아니라 함께 만들어가는 것임을 기억하세요. 작은 노력 하나하나가 그 간극을 조금씩 좁혀가며, 그 과정 자체가 사랑의 본질입니다.', en: 'It is time to make efforts to bridge the gap between your ideal of romance and the real relationship in front of you. The gap may feel large today, but remember that a perfect relationship is not something you find—it is something you build together, one small effort at a time. The building process itself is the essence of love.', zh: '现在需要努力缩小理想恋爱与眼前现实关系之间的差距。今天差距可能感觉很大，但记住完美的关系不是你发现的，而是你们一起建造的，一次一个小努力。建造过程本身就是爱的本质。', ja: '理想的な恋愛と目の前の現実の関係の間のギャップを縮める努力が必要な時です。今日はギャップが大きく感じられるかもしれませんが、完璧な関係は見つけるものではなく一緒に作り上げるものだということを覚えておいてください。', es: 'Es momento de esforzarte por cerrar la brecha entre tu ideal romantico y la relacion real frente a ti. La brecha puede sentirse grande hoy, pero recuerda que una relacion perfecta no es algo que encuentras—es algo que construyen juntos, un pequeño esfuerzo a la vez. El proceso mismo es la esencia del amor.' },
      { ko: '새로운 자극을 찾고 싶은 마음이 굴뚝같지만, 오늘은 이미 당신 곁에 있는 소중한 인연에게 관심과 에너지를 쏟는 것이 훨씬 가치 있습니다. 오래되었지만 소홀히 한 관계에 연락을 해보세요—관심이 식기 전에 되살리는 것이 새 인연을 찾는 것보다 훨씬 깊은 만족을 줍니다.', en: 'A day better spent nurturing existing bonds than seeking new encounters—the connections you already have deserve more attention and care right now. Reach out to someone you have been neglecting; reviving a warm relationship before it cools gives far deeper satisfaction than pursuing new ones.', zh: '比起寻求新的邂逅，今天把精力花在培育现有缘分上更好——你已经拥有的联系现在需要更多关注和照顾。联系一个你一直忽视的人，在关系冷却前使其重新焕发活力，比追求新关系给予更深的满足感。', ja: '新しい出会いより既存の縁を大切にすることにエネルギーを使うと良い一日です。疎かにしていた関係に連絡してみてください。冷える前に関係を再活性化させることは新しい縁を追うよりはるかに深い満足感を与えます。', es: 'Un dia mejor invertido en cultivar vinculos existentes que en buscar nuevos encuentros—las conexiones que ya tienes merecen mas atencion ahora. Contacta a alguien que has descuidado; revivir una relacion calida antes de que se enfrie da mucha mas satisfaccion que perseguir nuevas.' },
      { ko: '논리적인 당신이 때로 간과하기 쉬운 것이 상대방의 감정적 필요입니다. 오늘은 분석보다 공감에 집중하며 상대의 감정 상태에 조금 더 섬세하게 반응해 보세요. 그 작은 차이가 관계의 온도를 부드럽게 만들고, 상대방이 진심으로 이해받고 있다는 느낌을 갖게 해줍니다.', en: 'Paying a little more attention to your partner\'s emotional needs smooths the relationship in meaningful ways today. Your analytical mind sometimes overlooks what the heart needs most—empathy over analysis. Respond a little more sensitively to their emotional state, and that small shift will make them feel genuinely understood.', zh: '今天多关注一些伴侣的情感需求以有意义的方式让关系更顺畅。你的分析思维有时会忽略心灵最需要的东西——共情胜于分析。对他们的情感状态回应得更敏感一些，这个小小的转变会让他们感到真正被理解。', ja: '相手の感情的なニーズにもう少し関心を払えば関係がスムーズになります。分析的な心は時に心が最も必要とするものを見落とします。相手の感情状態にもう少し繊細に反応してみてください。その小さな変化が本当に理解されていると感じさせます。', es: 'Prestar un poco mas de atencion a las necesidades emocionales de tu pareja suaviza la relacion de maneras significativas hoy. Tu mente analitica a veces pasa por alto lo que el corazon mas necesita—empatia sobre analisis. Responde un poco mas sensiblemente a su estado emocional; ese pequeno cambio los hara sentir genuinamente comprendidos.' },
      { ko: '혼자만의 시간은 당신에게 선택이 아니라 필수입니다. 이것을 숨기거나 미안해하지 말고, 솔직하게 말해보세요. 진정으로 당신을 이해하는 사람은 이 필요를 받아들이고 존중해 줄 것입니다. 솔직한 소통이 이 상황을 오해에서 이해로 바꿔줄 것입니다.', en: 'If you need alone time, say so honestly—for you it is not a preference but a necessity. Do not hide it or apologize for it. Someone who truly understands you will accept and respect this need. Honest communication about what you need will transform this situation from potential misunderstanding into genuine understanding.', zh: '如果你需要独处时间，坦诚地说——对你来说这不是偏好而是必需。不要隐藏它或为此道歉。真正理解你的人会接受并尊重这种需要。关于你需要什么的诚实沟通将把这种情况从潜在误解转化为真正的理解。', ja: '一人の時間が必要なら素直に言ってください。あなたにとってそれは好みではなく必要です。隠したり謝ったりしないでください。本当にあなたを理解する人はこのニーズを受け入れ尊重してくれます。正直なコミュニケーションが誤解を理解に変えてくれます。', es: 'Si necesitas tiempo a solas, dilo honestamente—para ti no es una preferencia sino una necesidad. No lo ocultes ni te disculpes. Alguien que verdaderamente te comprenda aceptara y respetara esta necesidad. La comunicacion honesta sobre lo que necesitas transformara posibles malentendidos en comprension genuina.' },
      { ko: '사소한 마찰이 생기더라도 오늘은 크게 번지지 않고 마무리될 수 있는 좋은 에너지가 흐릅니다. 침착함을 유지하고 대화로 풀어가면, 오히려 이 작은 다툼이 서로를 더 깊이 이해하는 기회가 될 수 있습니다. 갈등을 피하지 말고 건강하게 다루는 방법을 연습해 보세요.', en: 'Even if small quarrels arise today, they will not escalate—good energy is flowing that keeps friction manageable. Stay calm and resolve them through honest dialogue, because these minor disagreements can actually become opportunities to understand each other more deeply. Practice handling conflict healthily rather than avoiding it.', zh: '即使今天发生小争吵也不会扩大——流动的好能量让摩擦保持可控。保持冷静，通过诚实对话解决，因为这些小分歧实际上可以成为更深入了解彼此的机会。练习健康地处理冲突而不是回避它。', ja: '些細な口論があっても大きくならないので冷静に対話で解決してください。良いエネルギーが流れていて摩擦を管理可能に保ちます。小さな意見の相違が実はお互いをより深く理解する機会になることがあります。', es: 'Aunque surjan pequenas peleas hoy, no escalaran—fluye buena energia que mantiene la friccion manejable. Manten la calma y resuelvelas mediante dialogo honesto, porque estos pequenos desacuerdos pueden convertirse en oportunidades para comprenderse mas profundamente. Practica manejar el conflicto sanamente en lugar de evitarlo.' },
      { ko: '높은 기대가 언제나 좋은 것은 아닙니다. 오늘은 연애에 대한 기대치를 의도적으로 조금 낮춰보면, 오히려 지금 이 순간의 아름다움을 더 선명하게 볼 수 있게 됩니다. 눈앞에 있는 현실의 소중함이 기대로 흐려지지 않도록, 지금 이 순간에 집중해 보세요.', en: 'Lowering romantic expectations slightly actually increases satisfaction today in a surprising way. High expectations can blind you to the genuine beauty of the present moment. Intentionally step back from your ideals and see the real person in front of you with clear eyes—what you find may genuinely delight you.', zh: '稍微降低恋爱期望今天实际上以令人惊讶的方式提高了满意度。高期望可能会让你对当下真实之美视而不见。有意识地从你的理想退一步，用清晰的眼光看面前的真实的人——你发现的东西可能真的会让你愉快。', ja: '恋愛への期待値を少し下げると今日はかえって満足感が高まります。高い期待が現在の瞬間の本物の美しさを見えなくすることがあります。意図的に理想から一歩引いて目の前の本当の人を澄んだ目で見てみてください。', es: 'Bajar un poco las expectativas romanticas en realidad aumenta la satisfaccion hoy de manera sorprendente. Las grandes expectativas pueden cegarte a la belleza genuina del momento presente. Da un paso atras de tus ideales intencionalmente y ve a la persona real frente a ti con ojos claros—lo que encuentres puede deleitarte genuinamente.' },
      { ko: '물병자리에게 우정은 연애만큼이나 깊은 의미를 갖습니다. 오늘 친구들로부터 오는 따뜻함이 연애에서 채워지지 않은 빈자리를 충분히 메워줄 수 있습니다. 사랑하는 친구와의 깊은 대화나 함께하는 시간이 오늘 당신에게 필요한 정서적 충전이 됩니다.', en: 'Warmth from friendships can beautifully fill the gap of romance today—for Aquarius, friendship carries meaning as deep as love. A heartfelt conversation or shared time with a dear friend is exactly the emotional recharge you need right now. Do not underestimate how nourishing this kind of connection truly is.', zh: '来自友情的温暖今天可以美好地填补恋爱的空缺——对水瓶座来说，友谊承载着与爱情一样深刻的意义。与亲爱的朋友进行一次真诚的对话或共度时光，正是你现在需要的情感充电。不要低估这种连接真正的滋养程度。', ja: '友人関係から来る温かさが今日は恋愛の空白を美しく埋めてくれます。水瓶座にとって友情は愛と同じくらい深い意味を持ちます。大切な友人との心からの会話や共に過ごす時間が今必要な感情的な充電です。', es: 'La calidez de las amistades puede llenar hermosamente el vacio romantico hoy—para Acuario, la amistad lleva significado tan profundo como el amor. Una conversacion sincera o tiempo compartido con un amigo querido es exactamente la recarga emocional que necesitas ahora. No subestimes lo nutritivo que es este tipo de conexion.' },
    ],
    low: [
      { ko: '오늘 당신의 내향적인 에너지가 상대방에게 감정적 거리감으로 전달될 수 있습니다. 이것은 당신의 의도가 아니지만, 상대방은 혼란스러울 수 있습니다. 잠시 자신의 내면에서 벗어나 상대방의 입장에서 먼저 생각해 보는 것이 이 순간을 부드럽게 넘길 수 있는 가장 효과적인 방법입니다.', en: 'Emotional distance may grow easily today as your inward-pulling energy is misread as withdrawal by your partner. This is not your intention, but confusion is natural. Step outside your inner world for a moment and consciously think from your partner\'s perspective first—that small shift will soften this moment significantly.', zh: '今天情感距离容易拉大，因为你向内的能量被伴侣误解为退缩。这不是你的意图，但困惑是自然的。暂时走出你的内心世界，先从伴侣的角度有意识地思考——这个小小的转变将显著软化这个时刻。', ja: '感情的な距離感が広がりやすい日です。内向きのエネルギーがパートナーには引きこもりとして誤解される可能性があります。これはあなたの意図ではありませんが混乱は自然です。少し内なる世界から出てパートナーの立場から先に考えてみてください。', es: 'La distancia emocional puede crecer facilmente hoy ya que tu energia hacia adentro es mal interpretada como alejamiento. Esta no es tu intencion, pero la confusion es natural. Sal de tu mundo interior por un momento y piensa conscientemente desde la perspectiva de tu pareja primero—ese pequeno cambio suavizara este momento.' },
      { ko: '당신의 독립심은 아름다운 자질이지만, 지나치면 파트너에게 혼자라는 느낌을 줄 수 있습니다. 관계 안에서의 자유와 연결의 균형을 찾는 것이 지금 필요합니다. 오늘 하루 작은 관심 표현 하나를 더해보세요—짧은 문자 하나, 따뜻한 눈빛 하나가 파트너의 마음을 크게 변화시킬 수 있습니다.', en: 'Excessive independence may leave your partner feeling lonely today—your beautiful self-sufficiency can read as indifference from the outside. The balance between freedom and connection within a relationship is what you need to find now. One extra small gesture of attention can create a surprisingly big difference in how your partner feels.', zh: '过度独立今天可能让伴侣感到孤独——你美丽的自足从外面看来可能像冷漠。在关系中找到自由与连接之间的平衡是你现在需要的。一个额外的小关心表达对伴侣的感受可以产生令人惊讶的巨大差异。', ja: '過度な独立心がパートナーに寂しさを与える可能性があります。あなたの美しい自立心は外から見ると無関心に見えることがあります。関係の中での自由と繋がりのバランスを見つけることが今必要です。小さな関心の表現一つが大きな違いを生みます。', es: 'La independencia excesiva puede dejar a tu pareja sintiendose sola hoy—tu hermosa autosuficiencia puede leerse como indiferencia desde afuera. El equilibrio entre libertad y conexion dentro de la relacion es lo que necesitas encontrar ahora. Un pequeno gesto de atencion extra puede crear una sorprendentemente gran diferencia.' },
      { ko: '현실의 관계가 당신이 상상해온 이상적인 모습과 달라 실망스러울 수 있습니다. 그 실망감은 당신의 섬세함에서 오는 자연스러운 반응이지, 현재 관계가 실패라는 신호가 아닙니다. 완벽한 관계는 세상에 없지만, 서로 노력하는 불완전한 관계가 가장 아름다울 수 있다는 것을 기억하세요.', en: 'You may be disappointed by the reality of your relationship differing from your ideals today, but this disappointment reflects your sensitivity, not a failed relationship. No relationship in the world is perfect—but an imperfect relationship where both people genuinely try is often the most beautiful thing in the world.', zh: '今天你可能对关系的现实与你的理想不同而感到失望，但这种失望反映了你的敏感性，而不是失败的关系。世界上没有完美的关系——但双方都真诚努力的不完美关系往往是世界上最美丽的事情。', ja: '理想と違う現実に失望するかもしれませんが、この失望はあなたの繊細さを反映しており、失敗した関係のサインではありません。世界に完璧な関係はありません。しかし双方が真剣に努力する不完全な関係が最も美しいものであることが多いです。', es: 'Puedes decepcionarte porque la realidad de tu relacion difiere de tus ideales hoy, pero esta decepcion refleja tu sensibilidad, no una relacion fallida. No existe una relacion perfecta en el mundo—pero una relacion imperfecta donde ambos genuinamente se esfuerzan es a menudo lo mas hermoso.' },
      { ko: '천왕성의 변덕스러운 에너지가 오늘 당신의 감정에도 영향을 미쳐 갑작스러운 마음의 변화가 찾아올 수 있습니다. 이 변화를 즉시 행동으로 옮기기 전에 하루 정도 마음을 가라앉히는 시간을 가져보세요. 충동적인 결정이 상대방을 깊이 혼란스럽게 만들 수 있으므로 신중하게 행동하는 것이 지금 가장 현명합니다.', en: 'Sudden changes of heart may confuse your partner today as Uranus\'s unpredictable energy influences your emotions. Before acting on any change of feeling, take at least a day to let things settle. Impulsive decisions in relationships rarely end well—careful, thoughtful action is the wisest approach right now.', zh: '今天突然的心理变化可能让伴侣困惑，因为天王星不可预测的能量影响着你的情绪。在对任何感情变化采取行动之前，至少花一天时间让事情平息。在关系中的冲动决定很少有好结果——现在谨慎、深思熟虑的行动是最明智的方法。', ja: '天王星の予測不可能なエネルギーが感情に影響を与え、急な心の変化が相手を混乱させる可能性があります。感情の変化に基づいて行動する前に少なくとも一日落ち着く時間を取ってください。衝動的な決定は相手を深く混乱させます。慎重に行動してください。', es: 'Cambios repentinos de corazon pueden confundir a tu pareja hoy mientras la energia impredecible de Urano influye en tus emociones. Antes de actuar sobre cualquier cambio de sentimiento, toma al menos un dia para que las cosas se asienten. Las decisiones impulsivas en relaciones rara vez terminan bien—actua con cuidado y reflexion ahora.' },
      { ko: '논리적인 당신이 가장 빠지기 쉬운 함정이 바로 관계에서의 옳고 그름 싸움입니다. 오늘은 승리보다 연결을 선택해야 할 때입니다. 당신이 맞더라도 상대방이 상처받는다면, 그것은 진짜 이긴 것이 아닙니다. 관계에서 두 사람 모두의 감정이 논리보다 훨씬 더 중요하다는 것을 기억하세요.', en: 'Do not try to win arguments today—the trap you fall into most easily is fighting over right and wrong in relationships. Choose connection over victory right now. Even if you are correct, if your partner is hurt, you have not truly won anything. In relationships, both people\'s feelings matter far more than any logical argument.', zh: '今天不要试图在争论中获胜——你最容易陷入的陷阱正是在关系中争论对错。现在选择连接而不是胜利。即使你是对的，如果伴侣受伤了，你也没有真正赢得任何东西。在关系中，双方的感受远比任何逻辑论点重要。', ja: '議論で勝とうとしないでください。あなたが最も陥りやすい罠は関係における正しさ争いです。今は勝利より繋がりを選んでください。あなたが正しくてもパートナーが傷つくなら本当に勝ったことにはなりません。関係では双方の感情が論理よりはるかに重要です。', es: 'No intentes ganar discusiones hoy—la trampa en la que mas facilmente caes es pelear sobre el bien y el mal en relaciones. Elige conexion sobre victoria ahora mismo. Incluso si tienes razon, si tu pareja esta herida, no has ganado realmente nada. En relaciones, los sentimientos de ambos importan mucho mas que cualquier argumento logico.' },
      { ko: '관계 안에서 자유가 제한된다는 느낌이 오늘 특히 강하게 들 수 있습니다. 그 답답함은 진짜이지만, 지금 감정적으로 폭발하는 것은 상황을 더 어렵게 만들 뿐입니다. 이 감정을 잠시 내면에서 정리한 뒤, 차분하게 자신의 필요를 표현하는 것이 훨씬 효과적입니다.', en: 'You may feel stifled by a sense of constraint in your relationship today, and that feeling is genuine and valid. However, an emotional outburst right now will only complicate things further. Take a moment to process this feeling internally, then express your needs calmly and clearly—that approach is far more effective.', zh: '今天你可能强烈地感受到关系中自由受限，这种感觉是真实有效的。然而，现在的情绪爆发只会使事情更加复杂。花点时间在内心处理这种感觉，然后冷静清晰地表达你的需求——这种方法要有效得多。', ja: '関係における束縛の感覚が今日は特に強く感じられるかもしれません。その感覚は本物で有効です。しかし感情的な爆発は事態をさらに複雑にするだけです。一瞬内面でこの感情を整理してから冷静に必要なことを表現してください。その方がはるかに効果的です。', es: 'Puedes sentirte agobiado/a por restricciones en tu relacion hoy, y ese sentimiento es genuino y valido. Sin embargo, un estallido emocional ahora solo complicara las cosas. Toma un momento para procesar este sentimiento internamente, luego expresa tus necesidades con calma y claridad—ese enfoque es mucho mas efectivo.' },
      { ko: '역사는 반성하지 않으면 반복됩니다. 오늘 과거의 연애 패턴이 다시 모습을 드러내려는 기운이 감지되니, 지금이 자기 성찰의 시간입니다. 같은 실수를 또 하기 전에 잠시 멈추어 "나는 왜 이 패턴을 반복하는가"를 정직하게 물어보세요—그 질문이 변화의 시작입니다.', en: 'Past relationship patterns may repeat today unless you consciously intervene—history repeats itself for those who do not reflect. Now is the time for genuine self-reflection. Before making the same mistake again, pause and honestly ask yourself why this pattern keeps recurring; that honest question is where real change begins.', zh: '今天过去的恋爱模式可能重复，除非你有意识地介入——历史对那些不反思的人来说会重复。现在是真正自我反省的时候了。在再次犯同样的错误之前，暂停并诚实地问自己为什么这种模式一直在重复；这个诚实的问题是真正改变开始的地方。', ja: '意識的に介入しなければ過去の恋愛パターンが繰り返される気運があります。今は本物の自己省察の時間です。同じ過ちを繰り返す前に一時停止して、なぜこのパターンが繰り返されるのか正直に自問してください。その正直な問いが本当の変化の始まりです。', es: 'Los patrones de relaciones pasadas pueden repetirse hoy a menos que intervengas conscientemente—la historia se repite para quienes no reflexionan. Ahora es el momento de la genuina autorreflexion. Antes de cometer el mismo error nuevamente, pausa y preguntate honestamente por que este patron sigue ocurriendo—esa pregunta honesta es donde comienza el verdadero cambio.' },
      { ko: '상처받았을 때 마음의 문을 완전히 닫아버리는 것이 당신의 오래된 방어 기제일 수 있습니다. 오늘 그 충동이 강하게 올 수 있지만, 소통의 끈을 놓지 않는 것이 중요합니다. 마음의 문을 완전히 닫은 뒤에 다시 여는 것은 처음보다 훨씬 어렵습니다—지금 이 한 가닥의 연결을 지켜보세요.', en: 'You may feel the urge to close off completely today, but do not let go of the thread of communication—once the door is shut entirely, reopening it is far harder than it was to start. This impulse to withdraw is a defense mechanism, not wisdom. Keep one thread of connection alive; that line can save what matters most.', zh: '今天你可能感到完全封闭的冲动，但不要放弃沟通的纽带——一旦门完全关上，重新打开它比一开始要难得多。这种退缩的冲动是防御机制，而不是智慧。保持一根连接的线活着，那条线可以拯救最重要的东西。', ja: '完全に心を閉ざしたい衝動が来るかもしれませんが、コミュニケーションの糸は手放さないでください。一度扉が完全に閉まると再び開けるのは最初より遥かに難しいです。この引きこもりへの衝動は防衛機制であり知恵ではありません。一本の繋がりの糸を生かし続けてください。', es: 'Puede que sientas el impulso de cerrarte completamente hoy, pero no sueltes el hilo de la comunicacion—una vez que la puerta se cierra por completo, reabrirla es mucho mas dificil que al principio. Este impulso de retirarte es un mecanismo de defensa, no sabiduria. Mantén vivo un hilo de conexion; esa linea puede salvar lo que mas importa.' },
      { ko: '완벽한 사랑의 그림에 너무 집착하다 보면, 지금 당신 앞에 있는 충분히 아름다운 현실의 사랑을 놓칠 수 있습니다. 오늘 그 집착이 현재의 행복을 방해하고 있다면, 잠시 기대를 내려놓고 지금 이 순간에 집중해 보세요. 행복은 완벽에 있는 것이 아니라 지금 여기에서 발견됩니다.', en: 'Obsession with ideal love may hinder your present happiness today—fixating on a perfect romantic picture can cause you to miss the genuinely beautiful love right in front of you. If that obsession is blocking you now, set down your expectations for a moment and focus on this present moment. Happiness is not found in perfection; it exists right here.', zh: '对理想爱情的执着今天可能妨碍你当前的幸福——执着于完美的爱情画面可能让你错过眼前真正美丽的爱情。如果这种执着现在阻碍了你，暂时放下期望，专注于此刻。幸福不在完美中，就存在于此处。', ja: '理想的な愛への執着が現在の幸福を妨げる可能性があります。完璧な愛情の絵に固執することで目の前の本当に美しい現実の愛を見逃す可能性があります。その執着が今邪魔をしているなら期待を少し下ろして今この瞬間に集中してください。幸福は完璧にあるのではなく今ここにあります。', es: 'La obsesion con el amor ideal puede impedir tu felicidad presente hoy—fijarte en una imagen romantica perfecta puede hacerte perder el amor genuinamente hermoso frente a ti. Si esa obsesion te bloquea ahora, pon a un lado tus expectativas y enfocate en este momento presente. La felicidad no se encuentra en la perfeccion; existe aqui mismo.' },
      { ko: '"혼자 있고 싶지만 외롭다"는 이 모순된 감정이 오늘 동시에 밀려올 수 있습니다. 이것은 당신이 약해서가 아니라, 인간으로서 가장 복잡하고 섬세한 감정 지형을 살아가고 있다는 증거입니다. 지금 가장 중요한 것은 자기 자신을 돌보는 것—그 복잡한 마음 그대로를 따뜻하게 안아주세요.', en: 'A complex day where wanting to be alone and loneliness arrive together simultaneously—this paradox is not weakness but evidence that you inhabit the most nuanced emotional landscape of any sign. What matters most right now is self-care. Hold your complex feelings with warmth and tenderness; you deserve that gentleness.', zh: '想独处的心和孤独同时到来的复杂一天——这种悖论不是软弱，而是你居住在所有星座中最微妙情感地形的证明。现在最重要的是自我照顾。用温暖和温柔抱住你复杂的感受，你值得那份温柔。', ja: '一人でいたい気持ちと寂しさが同時に訪れる複雑な日です。この逆説は弱さではなく、最も繊細な感情の地形に生きている証拠です。今最も重要なのはセルフケアです。複雑な気持ちをそのまま温かく抱いてあげてください。', es: 'Un dia complejo donde querer estar solo/a y la soledad llegan juntos simultaneamente—esta paradoja no es debilidad sino evidencia de que habitas el panorama emocional mas matizado. Lo mas importante ahora es el autocuidado. Abraza tus sentimientos complejos con calidez y ternura; mereces esa gentileza.' },
    ],
  },
  career: {
    high: [
      { ko: '당신이 가진 혁신적인 사고방식이 오늘 프로젝트를 이끄는 핵심 동력으로 인정받습니다. 주도적 역할을 맡을 수 있는 에너지와 기회가 갖춰져 있으니, 자신감을 가지고 전면에 나서세요. 당신의 색깔로 이 프로젝트에 새로운 방향을 제시하는 것이 지금 가장 필요한 일입니다.', en: 'Energy for taking a leading role in innovative projects is strongly present today, with your unconventional thinking recognized as the driving force. Step confidently to the front—the project needs your unique direction. This is the moment to lead with your Aquarian vision and show what genuine innovation looks like.', zh: '今天在创新项目中担任主导角色的气运强劲，你的非传统思维被认可为驱动力。自信地走到前台——项目需要你独特的方向。这是用你的水瓶座愿景领导，展示真正创新是什么样子的时刻。', ja: '革新的なプロジェクトで主導的な役割を担う気運が強くあります。あなたの型破りな考え方が推進力として認められています。自信を持って前に出てください。このプロジェクトはあなた独自の方向性を必要としています。', es: 'Hay fuerte energia para asumir un rol principal en proyectos innovadores hoy, con tu pensamiento no convencional reconocido como la fuerza motriz. Da un paso confiado al frente—el proyecto necesita tu direccion unica. Este es el momento de liderar con tu vision acuariana.' },
      { ko: '당신이 오래 품어왔던 파격적인 아이디어가 오늘 상사의 눈길을 사로잡을 수 있는 완벽한 타이밍이 찾아왔습니다. 거절당할까 봐 말하지 못했던 그 아이디어를 오늘 과감하게 제안해 보세요. 세상을 바꾼 모든 혁신은 누군가 용기를 내어 처음 입 밖에 낸 아이디어에서 시작되었습니다.', en: 'An idea that overturns convention catches your boss\'s eye today—the perfect timing has arrived for that bold idea you have been holding back. Propose it fearlessly, because every world-changing innovation started with someone brave enough to speak it out loud for the first time. Your moment has come; seize it boldly.', zh: '颠覆现有方式的想法今天引起上司注意——那个你一直压着的大胆想法有了完美的时机。无畏地提议它，因为每一个改变世界的创新都始于有人足够勇敢地第一次大声说出来。你的时刻已经到来，大胆抓住它。', ja: '既存の方式を覆すアイデアが上司の目に留まる日で、ずっと抑えてきた大胆なアイデアを提案する完璧なタイミングが来ました。恐れずに提案してください。世界を変えたすべての革新は誰かが勇気を持って初めて声に出したアイデアから始まりました。', es: 'Una idea que rompe lo convencional llama la atencion de tu jefe hoy—ha llegado el momento perfecto para esa idea audaz que has estado guardando. Propónla sin miedo, porque toda innovacion que cambio el mundo comenzo con alguien lo suficientemente valiente para decirla en voz alta por primera vez.' },
      { ko: '팀 내에서 당신의 독창성이 마침내 인정받는 순간이 찾아왔습니다. 이 인정을 발판 삼아 네트워크를 더 적극적으로 활용하세요. 지금 당신을 알아보는 사람들과 연결되면, 그것이 커리어에서 가장 중요한 전환점 중 하나가 될 수 있습니다.', en: 'Your originality is recognized within the team today in a meaningful and validating way. Use this recognition as a launchpad to actively leverage your professional network. Connecting now with those who truly see your value may become one of the most important turning points in your career.', zh: '你的独创性今天在团队内以有意义和令人认可的方式得到认可。以这种认可为跳板，积极利用你的专业人脉。现在与那些真正看到你价值的人联系，可能成为你职业生涯中最重要的转折点之一。', ja: 'チーム内であなたの独創性が意味のある形で認められます。この認識を足がかりにしてネットワークを積極的に活用してください。今あなたの価値を本当に見てくれる人と繋がることが、キャリアの最も重要な転換点の一つになるかもしれません。', es: 'Tu originalidad es reconocida en el equipo hoy de manera significativa y validadora. Usa este reconocimiento como trampolín para aprovechar activamente tu red profesional. Conectar ahora con quienes genuinamente ven tu valor puede convertirse en uno de los puntos de inflexion mas importantes en tu carrera.' },
      { ko: '디지털과 기술에 남다른 친화력을 가진 당신에게 오늘은 그 능력이 최대치로 빛나는 날입니다. 기술 관련 업무에서 놀라운 성과를 낼 수 있는 에너지가 넘치니, 평소 아껴두었던 디지털 역량을 오늘 마음껏 발휘해 보세요. 당신의 기술력이 팀 전체의 퍼포먼스를 끌어올릴 것입니다.', en: 'You can achieve amazing results in tech-related work today—your natural affinity for digital technology is at its peak. The energy for technical excellence is overflowing right now, so unleash your digital capabilities fully and without restraint. Your technical abilities will elevate the entire team\'s performance to a new level.', zh: '今天你可以在技术相关工作中取得惊人成果——你对数字技术的天然亲和力达到峰值。技术卓越的能量现在溢满，所以充分释放你的数字能力，毫无保留。你的技术能力将把整个团队的表现提升到新水平。', ja: '技術関連の業務で驚くべき成果を上げることができます。デジタル技術への自然な親和性が最高潮に達しています。今技術的卓越へのエネルギーが溢れているので、デジタル能力を完全に発揮してください。あなたの技術力がチーム全体のパフォーマンスを新しいレベルへ引き上げます。', es: 'Puedes lograr resultados asombrosos en trabajo tecnologico hoy—tu afinidad natural por la tecnologia digital esta en su pico. La energia para la excelencia tecnica desborda ahora, asi que despliega tus capacidades digitales completamente. Tus habilidades tecnicas elevaran el rendimiento de todo el equipo.' },
      { ko: '예상치 못한 방향에서 흥미로운 협업 기회가 모습을 드러낼 수 있습니다. 처음에는 낯설거나 어색하게 느껴질 수 있지만, 열린 자세를 유지하는 것이 핵심입니다. 당신의 독창성과 상대의 강점이 만날 때 혼자서는 절대 만들 수 없는 시너지가 탄생합니다.', en: 'New collaboration opportunities arrive from unexpected places today, and they may feel unfamiliar or surprising at first. Staying open is the key—when your originality meets another\'s strengths, a synergy is born that neither of you could ever create alone. Embrace what surprises you today.', zh: '今天新的合作机会从意想不到的地方到来，一开始可能感觉陌生或令人惊讶。保持开放是关键——当你的独创性遇到另一个人的优势时，产生的协同效应是你们任何一个单独都无法创造的。拥抱今天让你惊讶的事情。', ja: '新しい協業の機会が予想外の場所からやってきます。最初は見慣れなかったり驚くかもしれません。オープンな姿勢を維持することが鍵です。あなたの独創性と相手の強みが出会う時、どちらか一人では決して作れないシナジーが生まれます。', es: 'Nuevas oportunidades de colaboracion llegan de lugares inesperados hoy, y pueden sentirse desconocidas o sorprendentes al principio. Mantenerse abierto/a es la clave—cuando tu originalidad se encuentra con las fortalezas de otro, nace una sinergia que ninguno de los dos podria crear solo. Abraza lo que te sorprende hoy.' },
      { ko: '단순히 돈을 버는 것 이상의 가치를 추구하는 것이 당신의 직업 철학입니다. 오늘 사회적 가치를 창출하는 프로젝트에 참여할 기회가 생긴다면 주저 말고 뛰어드세요. 이 참여가 커리어의 중요한 전환점이 될 수 있으며, 당신의 인도주의적 정신이 가장 강력한 직업적 무기가 됩니다.', en: 'Participating in socially valuable projects can be a genuine career turning point today—your work philosophy goes beyond simply earning money. If an opportunity to join a socially impactful project appears, embrace it without hesitation. Your humanitarian spirit is not just a personality trait; it is your most powerful professional asset.', zh: '今天参与具有社会价值的项目可以成为真正的职业转折点——你的工作哲学超越了简单地赚钱。如果出现加入具有社会影响力的项目的机会，毫不犹豫地接受它。你的人道主义精神不只是个性特征，它是你最强大的职业资产。', ja: '社会的価値を追求するプロジェクトに参加すれば本当のキャリアの転換点になり得ます。あなたの仕事の哲学は単に金を稼ぐことを超えています。社会的インパクトのあるプロジェクトに参加する機会が現れたら躊躇わずに受け入れてください。あなたの人道主義的精神は最も強力な職業的資産です。', es: 'Participar en proyectos de valor social puede ser un verdadero punto de inflexion en tu carrera hoy—tu filosofia de trabajo va mas alla de simplemente ganar dinero. Si aparece una oportunidad de unirte a un proyecto de impacto social, embracela sin dudarlo. Tu espiritu humanitario es tu activo profesional mas poderoso.' },
      { ko: '오늘 천왕성의 강력한 에너지가 당신의 커리어에 새로운 돌파구를 열어줍니다. 오늘 씨앗처럼 시작한 일이 나중에 큰 흐름을 만드는 파도가 될 것입니다. 작더라도 의미 있는 첫 발을 내딛어 보세요—시작하는 자만이 그 결실을 누릴 수 있습니다.', en: 'Uranus\' powerful energy opens professional breakthroughs today, creating new momentum in your career. What you start today—even something small—will grow into a significant wave of change. Take that meaningful first step now; only those who begin can harvest the results that follow.', zh: '今天天王星强大的能量打开了你职业生涯的突破口，在你的事业中创造新的动力。你今天开始的事情——即使是小事——将成长为重大的变革浪潮。现在迈出那有意义的第一步，只有开始的人才能收获随后的成果。', ja: '天王星の強力なエネルギーが職業的な突破口を開き、キャリアに新しい勢いを作ります。今日始めたこと——小さなことでも——大きな変化の波に成長します。意味のある最初の一歩を今踏み出してください。始める者だけが後に続く成果を収穫できます。', es: 'La poderosa energia de Urano abre avances profesionales hoy, creando nuevo impulso en tu carrera. Lo que inicies hoy—incluso algo pequeno—crecera hasta convertirse en una ola significativa de cambio. Da ese primer paso significativo ahora; solo quienes comienzan pueden cosechar los resultados que siguen.' },
      { ko: '아무도 몰라줄 것 같아도 묵묵히 이어온 당신의 독립적인 작업이 오늘 드디어 큰 주목을 받게 됩니다. 꾸준함은 물병자리에게 가장 어려운 덕목이지만, 그것이 빛을 발하는 순간은 이처럼 달콤합니다. 오늘 받는 인정을 자신감의 연료로 삼아 계속 나아가세요.', en: 'Work you have been doing independently gains major attention today—the consistent effort you have quietly sustained finally shines its light. Perseverance is Aquarius\'s most challenging virtue, but when it finally pays off, the reward is uncommonly sweet. Let today\'s recognition fuel your confidence to keep moving forward.', zh: '你一直独立进行的工作今天获得了重大关注——你悄悄坚持的持续努力终于绽放光芒。坚持不懈是水瓶座最具挑战性的美德，但当它终于有所回报时，奖励异常甜蜜。让今天的认可为你继续前进的信心提供燃料。', ja: '独立して進めていた作業が今日大きな注目を浴びます。静かに続けてきた一貫した努力がついに光を放ちます。忍耐は水瓶座にとって最も難しい美徳ですが、実を結ぶ瞬間は格別に甘いです。今日の認知を自信の燃料にして前に進み続けてください。', es: 'El trabajo que has realizado independientemente recibe gran atencion hoy—el esfuerzo constante que has sostenido silenciosamente finalmente brilla. La perseverancia es la virtud mas desafiante de Acuario, pero cuando finalmente da frutos, la recompensa es extraordinariamente dulce. Deja que el reconocimiento de hoy alimente tu confianza.' },
      { ko: '오늘 어떤 문제가 닥쳐도 당신의 창의적 문제해결 능력이 가장 빠른 해법을 찾아냅니다. 모두가 이미 시도해 본 방법을 답습하지 말고, 당신만의 독창적인 접근법을 과감히 시도해 보세요. 남들이 보지 못한 각도에서 문제를 바라보는 것이 오늘 당신의 가장 강력한 경쟁력입니다.', en: 'Creative problem-solving skills shine brilliantly today—whatever challenge arises, your unconventional mind finds the fastest and most elegant solution. Do not copy approaches others have already tried; boldly deploy your uniquely original method. Seeing problems from angles others miss is your most powerful competitive advantage today.', zh: '今天创造性解决问题的能力大放异彩——无论出现什么挑战，你的非传统思维都能找到最快、最优雅的解决方案。不要模仿他人已经尝试过的方法，大胆使用你独特的原创方法。从他人错过的角度看问题是你今天最强大的竞争优势。', ja: '創造的な問題解決能力が今日は輝きます。どんな課題が現れても、あなたの型破りな思考が最も速くエレガントな解決策を見つけます。他の人がすでに試したアプローチを真似せず、独自の方法を大胆に展開してください。', es: 'Las habilidades de resolucion creativa brillan intensamente hoy—cualquier desafio que surja, tu mente no convencional encuentra la solucion mas rapida y elegante. No copies enfoques que otros ya han intentado; despliega audazmente tu metodo original. Ver problemas desde angulos que otros no ven es tu mayor ventaja competitiva hoy.' },
      { ko: '미래를 먼저 보는 당신에게 어울리는 분야에서 새로운 기회의 문이 열립니다. 새로운 기술이나 떠오르는 트렌드에 주목하면, 남들보다 한 발 앞서 그 기회를 잡을 수 있습니다. 미래는 예측하는 사람이 아니라 선점하는 사람의 것이라는 것을 기억하세요.', en: 'Opportunities in future-oriented fields open up today, perfectly suited to your forward-seeing nature. Pay attention to new technologies or emerging trends, because you can grasp these opportunities one step ahead of everyone else. Remember—the future belongs not to those who predict it but to those who claim it first.', zh: '今天在面向未来的领域中机会打开，非常适合你的前瞻性本质。关注新技术或新兴趋势，因为你可以比其他所有人提前一步抓住这些机会。记住——未来属于不是预测它的人，而是最先占据它的人。', ja: '未来志向の分野での機会が今日開かれます。あなたの先見性の本質に完璧に適しています。新しい技術や新興のトレンドに注目してください。他の誰よりも一歩先にこれらの機会を掴むことができます。未来は予測する者ではなく先占する者のものです。', es: 'Se abren oportunidades en campos orientados al futuro hoy, perfectamente adecuadas a tu naturaleza visionaria. Presta atencion a nuevas tecnologias o tendencias emergentes, porque puedes captar estas oportunidades un paso por delante de los demas. Recuerda—el futuro no pertenece a quienes lo predicen sino a quienes lo reclaman primero.' },
    ],
    medium: [
      { ko: '혁신을 갈망하는 당신에게 오늘의 루틴한 업무는 특히 답답하게 느껴질 수 있습니다. 하지만 작은 혁신 하나라도 시도해 보면 그 지루함이 활력으로 바뀌는 것을 경험할 수 있습니다. 프로세스를 조금만 바꾸거나 더 효율적인 방법을 찾아보세요—작은 변화가 큰 에너지를 만듭니다.', en: 'Routine work may feel particularly boring today for someone who craves innovation like you. But even one small attempt at innovation can transform that boredom into genuine vitality. Try changing a process slightly or finding a more efficient method—small changes generate surprising amounts of energy.', zh: '对于像你这样渴望创新的人来说，今天的例行工作可能感觉特别无聊。但即使一个小小的创新尝试也能将那种无聊变成真正的活力。尝试稍微改变一个流程或找到更高效的方法——小改变产生令人惊讶的大量能量。', ja: '革新を望むあなたにとって今日のルーティンな業務は特に退屈に感じるかもしれません。しかし小さな革新でも試せば退屈が本物の活力に変わります。プロセスを少し変えてみるか、より効率的な方法を探してください。小さな変化が大きなエネルギーを生みます。', es: 'El trabajo rutinario puede sentirse particularmente aburrido hoy para alguien que anhela la innovacion como tu. Pero incluso un pequeno intento de innovacion puede transformar ese aburrimiento en vitalidad genuina. Intenta cambiar ligeramente un proceso o encontrar un metodo mas eficiente—los pequenos cambios generan grandes cantidades de energia.' },
      { ko: '당신의 독창적인 아이디어와 동료의 관점 사이에서 의견 차이가 생길 수 있습니다. 당신이 옳을 수도 있지만, 경청과 타협의 자세를 보여주는 것이 장기적으로 더 현명한 전략입니다. 최고의 결과는 혼자 고집하는 것이 아니라 서로 다른 관점이 융합될 때 탄생합니다.', en: 'Differences of opinion with colleagues may arise today, creating tension between your creative vision and theirs. You may well be right—but demonstrating listening and compromise is the wiser long-term strategy. The best outcomes are born not from insisting alone, but from the fusion of genuinely different perspectives.', zh: '今天与同事合作中可能出现意见分歧，在你的创意愿景和他们的愿景之间产生张力。你可能是对的——但表现出倾听和妥协是更明智的长期策略。最好的结果不是来自坚持独断，而是来自真正不同观点的融合。', ja: '同僚との協業で意見の違いが生じる可能性があります。あなたの創造的なビジョンと相手のビジョンの間に緊張が生まれます。あなたが正しいかもしれませんが、傾聴と妥協の姿勢を示すことが長期的により賢明な戦略です。最良の結果は一人で固執することではなく異なる視点の融合から生まれます。', es: 'Pueden surgir diferencias de opinion con colegas hoy, creando tension entre tu vision creativa y la de ellos. Puede que tengas razon—pero demostrar escucha y compromiso es la estrategia a largo plazo mas sabia. Los mejores resultados no nacen de insistir solo, sino de la fusion de perspectivas genuinamente diferentes.' },
      { ko: '아이디어를 만드는 것이 당신의 가장 큰 재능이지만, 오늘은 그것을 실행 가능한 계획으로 연결하는 것이 더 중요합니다. 숫자, 일정, 담당자를 구체적으로 적어보는 것이 오늘 가장 필요한 작업입니다. 아이디어에 실행 계획이 붙으면, 비로소 진짜 힘을 갖게 됩니다.', en: 'Plenty of ideas arise today but execution remains hard to reach—your greatest talent is ideation, but right now converting those ideas into actionable plans is more important. Write down numbers, timelines, and responsible parties in specific terms. An idea equipped with an execution plan finally has real power.', zh: '今天想法很多但执行仍然难以到达——你最大的才能是想法生成，但现在将那些想法转化为可行计划更重要。用具体的数字、时间表和负责人写下来。配备执行计划的想法终于拥有了真正的力量。', ja: 'アイデアは多いですが実行に至るのが難しい日です。最大の才能はアイデアを生み出すことですが、今はそれを実行可能な計画に変えることの方が重要です。数字、スケジュール、担当者を具体的に書き出してください。実行計画を備えたアイデアがようやく本物の力を持ちます。', es: 'Surgen muchas ideas hoy pero la ejecucion es dificil de alcanzar—tu mayor talento es la ideacion, pero ahora convertir esas ideas en planes accionables es mas importante. Escribe numeros, plazos y responsables en terminos especificos. Una idea equipada con un plan de ejecucion finalmente tiene poder real.' },
      { ko: '자유로운 영혼인 당신에게 일방적인 지시와 권위는 특히 저항감을 불러일으킵니다. 오늘 그 감정이 강하게 올라올 수 있지만, 감정적으로 반발하는 것보다 전략적으로 대응하는 것이 훨씬 현명합니다. 지금 당장 싸우지 않아도 됩니다—더 좋은 타이밍과 방법으로 변화를 만들어낼 수 있습니다.', en: 'Resistance to authoritative orders may arise today—one-sided directives trigger your independent spirit especially strongly. While this feeling is understandable, responding strategically is far wiser than reacting emotionally. You do not have to fight right now; better timing and better methods will create more lasting change.', zh: '今天对权威指示可能产生抵触心理——单方面的指令特别强烈地触发你的独立精神。虽然这种感觉是可以理解的，但战略性应对比情绪性反应明智得多。你现在不必战斗——更好的时机和方法会创造更持久的变化。', ja: '権威的な指示に反発心が生じる可能性があります。一方的な指示はあなたの独立した精神を特に強く刺激します。この感情は理解できますが、感情的に反応するより戦略的に対応する方がはるかに賢明です。今すぐ戦わなくていいです。より良いタイミングと方法で変化を作り出せます。', es: 'Puede surgir resistencia a ordenes autoritarias hoy—las directivas unilaterales activan tu espiritu independiente especialmente fuerte. Aunque este sentimiento es comprensible, responder estrategicamente es mucho mas sabio que reaccionar emocionalmente. No tienes que pelear ahora—mejores momentos y metodos crearan cambios mas duraderos.' },
      { ko: '당신의 광범위한 관심사가 오늘 업무 집중력을 방해할 수 있습니다. 여러 일을 동시에 처리하고 싶어도, 오늘만큼은 한 가지에 완전히 집중하는 것이 훨씬 효율적입니다. 깊이 파고드는 집중이 멀티태스킹보다 훨씬 강력한 성과를 만들어냅니다.', en: 'Focusing on one thing is significantly more efficient than multitasking today—your wide interests may be pulling your attention in many directions. Even if you want to handle multiple things at once, complete focus on a single task will produce far stronger results. Deep concentration beats spread-thin multitasking every time.', zh: '今天专注于一件事比多任务处理效率高得多——你广泛的兴趣可能将你的注意力拉向多个方向。即使你想同时处理多件事，完全专注于单个任务将产生更强的结果。深度专注每次都胜过分散的多任务处理。', ja: 'マルチタスクより一つに集中する方が今日は効率的です。広い関心が注意をあちこちに引いているかもしれません。複数のことを同時にこなしたくても、一つのタスクへの完全な集中がはるかに強い成果を生みます。', es: 'Enfocarte en una cosa es significativamente mas eficiente que hacer multitarea hoy—tus amplios intereses pueden estar tirando tu atencion en muchas direcciones. Incluso si quieres manejar multiples cosas a la vez, el enfoque completo en una sola tarea producira resultados mucho mas fuertes.' },
      { ko: '새로운 것에 끌리는 본능을 오늘은 잠시 내려놓고, 이미 시작한 일들을 먼저 마무리하는 데 집중하세요. 미완성 작업이 쌓이면 에너지가 분산되고 성취감도 줄어듭니다. 하나를 완성하는 만족감이 새 것을 시작하는 흥분보다 지금 훨씬 더 가치 있습니다.', en: 'Focus on finishing ongoing work rather than starting new projects today—the instinct to chase new things is strong in you, but let it rest for now. Unfinished work drains energy and diminishes your sense of achievement. The satisfaction of completing one thing is worth far more than the excitement of beginning another.', zh: '今天专注于完成进行中的工作而不是开始新项目——追逐新事物的本能在你身上很强，但现在让它休息一下。未完成的工作会消耗能量并减少你的成就感。完成一件事的满足感远比开始另一件事的兴奋更有价值。', ja: '新しいプロジェクトを始めるより進行中の仕事を仕上げることに今日は焦点を当ててください。新しいものを追う本能が強くても今は休ませてください。未完成の仕事はエネルギーを消耗させ達成感を減らします。一つを完成させる満足感が新しいものを始める興奮よりはるかに価値があります。', es: 'Enfocate en terminar trabajo en curso en vez de iniciar nuevos proyectos hoy—el instinto de perseguir cosas nuevas es fuerte en ti, pero dejalo descansar por ahora. El trabajo inacabado drena energia y disminuye tu sentido de logro. La satisfaccion de completar una cosa vale mucho mas que la emocion de comenzar otra.' },
      { ko: '업무 도중 갑자기 번뜩이는 아이디어가 찾아올 수 있습니다. 지금 당장 그것을 실행하지 못하더라도 반드시 메모해 두세요. 오늘의 씨앗이 나중에 가장 빛나는 결실이 될 수 있으니, 아이디어 노트를 항상 가까이에 두는 습관을 만들어보세요.', en: 'If a brilliant idea strikes during work today, note it down immediately—even if you cannot act on it right now. Today\'s seed idea may become your brightest future achievement. Build the habit of always keeping an idea notebook nearby; you never know when your next breakthrough will arrive unexpectedly.', zh: '如果工作中今天出现一个绝妙的想法，立即记下来——即使你现在不能行动。今天的种子想法可能成为你最辉煌的未来成就。建立随时将想法记录本放在手边的习惯，你永远不知道下一个突破何时不期而至。', ja: '業務中に素晴らしいアイデアが浮かんだら今すぐ行動できなくてもすぐメモしてください。今日の種のアイデアが将来最も輝く成果になるかもしれません。アイデアノートを常に手元に置く習慣を作ってください。', es: 'Si una idea brillante surge durante el trabajo hoy, anotala inmediatamente—incluso si no puedes actuar sobre ella ahora. La idea semilla de hoy puede convertirse en tu logro futuro mas brillante. Crea el habito de tener siempre un cuaderno de ideas cerca; nunca sabes cuando llegara tu proximo avance inesperadamente.' },
      { ko: '네트워킹 기회가 여럿 있지만, 모든 자리에 참석할 필요는 없습니다. 오늘 에너지를 한 곳에 집중하기 위해 가장 의미 있는 연결에만 선별적으로 참여하는 지혜가 필요합니다. 깊은 한 번의 연결이 얕은 열 번의 만남보다 훨씬 더 큰 가치를 지닙니다.', en: 'Networking opportunities exist today, but participating selectively to avoid spreading your energy thin is the wise approach. Not every gathering deserves your presence. Focus your energy on the one most meaningful connection—deep one meeting is worth far more than shallow ten encounters in terms of real professional value.', zh: '今天有社交机会，但选择性参与以避免分散精力是明智的方法。不是每个聚会都值得你出席。将精力集中在最有意义的一个联系上——在真正的职业价值方面，一次深度会面远比十次浅层相遇更有价值。', ja: 'ネットワーキングの機会がありますが、エネルギーを分散させないよう選択的に参加することが賢明です。すべての集まりに参加する必要はありません。最も意味のある一つの繋がりにエネルギーを集中してください。深い一度の繋がりが浅い十度の出会いよりはるかに価値があります。', es: 'Hay oportunidades de networking hoy, pero participar selectivamente para no dispersar energia es el enfoque sabio. No todo encuentro merece tu presencia. Enfoca tu energia en la conexion mas significativa—una reunion profunda vale mucho mas que diez encuentros superficiales en terminos de valor profesional real.' },
      { ko: '직장 내에서 변화의 조짐이 감지됩니다. 변화를 사랑하는 당신이지만, 충분한 정보 없이 성급하게 반응하면 유리한 상황을 불리하게 만들 수 있습니다. 지금은 상황을 차분히 관망하며 정보를 모으는 것이 최선입니다—정보가 충분해지면 더 강력한 대응이 가능합니다.', en: 'Signs of workplace change appear today, and while you love change, reacting hastily without sufficient information can turn an advantageous situation against you. For now, calmly observe the situation and gather information—the more informed you are, the more powerful your eventual response will be.', zh: '今天出现职场变化的迹象，虽然你喜欢变化，但在没有足够信息的情况下草率反应可能会将有利形势转为不利。现在，冷静地观望情况并收集信息——你的信息越充分，最终的回应就越有力。', ja: '職場内の変化の兆しが見えます。変化が好きなあなたですが、十分な情報なしに急いで反応すると有利な状況を不利に変えてしまう可能性があります。今は状況を落ち着いて見守り情報を集めるのが最善です。情報が十分になれば、より強力な対応が可能です。', es: 'Aparecen senales de cambio en el trabajo hoy, y aunque amas el cambio, reaccionar apresuradamente sin informacion suficiente puede convertir una situacion ventajosa en tu contra. Por ahora, observa calmadamente la situacion y recopila informacion—cuanto mas informado/a estes, mas poderosa sera tu respuesta eventual.' },
      { ko: '당신이 가장 창의적으로 일하는 환경은 간섭 없는 자율의 시간입니다. 오늘은 그 자율적 시간을 의도적으로 확보하는 것이 생산성을 크게 높여줍니다. 회의나 불필요한 방해 없이 오롯이 집중할 수 있는 시간대를 미리 확보해 보세요—그 한두 시간이 하루 전체의 성과를 결정합니다.', en: 'Securing autonomous work time boosts productivity significantly today—you are most creative and productive when working without interference. Intentionally protect a block of uninterrupted focus time in your schedule. Those one or two hours of pure concentration will determine the quality of your entire day\'s output.', zh: '今天确保自主工作时间会显著提升生产力——你在不受干扰地工作时最具创造力和生产力。有意识地在你的日程中保护一段不受打扰的专注时间。那一两个小时的纯专注将决定你整天产出的质量。', ja: '自律的に仕事ができる時間を確保すれば今日は生産性が大幅に上がります。干渉なく仕事をするとき最も創造的で生産的です。スケジュールに邪魔されない集中時間を意図的に確保してください。その一二時間の純粋な集中が一日全体の成果の質を決めます。', es: 'Asegurar tiempo de trabajo autonomo aumenta significativamente la productividad hoy—eres mas creativo/a y productivo/a cuando trabajas sin interferencias. Protege intencionalmente un bloque de tiempo de concentracion sin interrupciones. Esas una o dos horas de concentracion pura determinaran la calidad de la produccion de todo tu dia.' },
    ],
    low: [
      { ko: '변화를 갈망하는 당신에게 조직의 보수적인 분위기가 오늘 특히 숨막히게 느껴질 수 있습니다. 이 답답함은 당신이 그 조직보다 더 앞서 생각하고 있다는 증거이기도 합니다. 지금은 인내심을 발휘하며 장기적으로 변화를 일으킬 수 있는 내부 영향력을 키워나가는 시간으로 삼으세요.', en: 'A day of great frustration with the organization\'s conservative atmosphere—for someone who craves change like you, rigid structure feels suffocating today. This frustration is also evidence that you think ahead of the organization. Use patience now to build the internal influence that will create change over the long term.', zh: '今天对组织保守氛围感到非常沮丧——对于像你这样渴望变化的人来说，僵化的结构今天感觉令人窒息。这种挫败感也证明你的思维超越了组织。现在用耐心来建立能够在长期内创造变化的内部影响力。', ja: '組織の保守的な雰囲気に大きな息苦しさを感じる日です。変化を求めるあなたには硬直した構造が窒息感を与えます。この挫折感はあなたが組織より先を考えていることの証拠でもあります。今は忍耐心を発揮して長期的に変化を起こす内部影響力を育てる時間にしてください。', es: 'Un dia de gran frustracion con el ambiente conservador de la organizacion—para alguien que anhela el cambio como tu, la estructura rigida se siente sofocante hoy. Esta frustracion es tambien evidencia de que piensas por delante de la organizacion. Usa la paciencia ahora para construir la influencia interna que creara cambio a largo plazo.' },
      { ko: '갑작스러운 업무 변경이나 일정 조정이 오늘 당신의 계획을 뒤흔들 수 있습니다. 변화를 좋아하는 당신이지만, 자신이 원하지 않는 변화는 저항감을 불러일으킬 수 있습니다. 불평하고 싶은 마음을 잠시 내려놓고 우선 적응하는 것이 에너지를 더 유용하게 쓰는 방법입니다.', en: 'Respond flexibly to sudden work changes or schedule adjustments today—even though you love change in general, unwanted change can trigger resistance. Set aside the urge to complain and prioritize adaptation first; channeling your energy into adapting is far more productive than spending it on frustration.', zh: '今天需要灵活应对突然的工作变更或日程调整——尽管你通常喜欢变化，但不需要的变化可能引发抵触。先放下抱怨的冲动，优先适应；将能量用于适应比花在沮丧上要有效得多。', ja: '突然の業務変更やスケジュール調整に柔軟に対応する必要があります。変化は好きなあなたでも、望まない変化には抵抗感が生まれます。不満の衝動を少し置いておいてまず適応することを優先してください。適応にエネルギーを向けることが不満に費やすよりはるかに生産的です。', es: 'Responde con flexibilidad a cambios repentinos de trabajo hoy—aunque generalmente amas el cambio, los cambios no deseados pueden desencadenar resistencia. Deja a un lado el impulso de quejarte y prioriza la adaptacion primero; canalizar tu energia en adaptarte es mucho mas productivo que gastarlo en frustracion.' },
      { ko: '독립적인 사고방식이 강점이지만, 오늘 독단적인 결정이 팀워크에 심각한 균열을 만들 수 있습니다. 더 좋은 아이디어가 있다고 느끼더라도 동료들의 의견을 먼저 구하는 과정을 거치세요. 다음에도 함께 일할 사람들이기 때문에, 관계를 유지하는 것이 지금 가장 중요한 투자입니다.', en: 'Unilateral decisions may harm teamwork today—your independent thinking is a strength, but acting without consultation can create serious rifts. Even if you feel your idea is better, go through the process of seeking colleagues\' input first. These are people you will work with again; maintaining the relationship is the most important investment right now.', zh: '今天独断的决定可能损害团队合作——你的独立思考是优势，但不经协商行动可能造成严重裂痕。即使你认为自己的想法更好，也要先经历征求同事意见的过程。这些是你将再次合作的人，维护关系是现在最重要的投资。', ja: '独断的な決定がチームワークに害を与える可能性があります。独立した思考は強みですが相談なく行動すると深刻な亀裂を生む可能性があります。自分のアイデアの方が良いと感じても、まず同僚の意見を求めるプロセスを経てください。一緒に仕事をし続ける人たちなので関係を維持することが今最も重要な投資です。', es: 'Las decisiones unilaterales pueden danar el trabajo en equipo hoy—tu pensamiento independiente es una fortaleza, pero actuar sin consulta puede crear grietas serias. Incluso si sientes que tu idea es mejor, pasa por el proceso de buscar opiniones de colegas primero. Son personas con quienes trabajaras de nuevo; mantener la relacion es la inversion mas importante ahora.' },
      { ko: '기술에 친화적인 당신이지만, 오늘은 예상치 못한 기술적 오류나 시스템 문제가 발생할 수 있습니다. 중요한 데이터는 지금 바로 백업해 두고, 작업 전에 이중 확인을 거치는 습관이 오늘 큰 손실을 막아줄 것입니다. 준비된 사람에게는 기술 오류도 큰 문제가 되지 않습니다.', en: 'Technical errors or system problems may occur today, even for someone as tech-savvy as you. Back up important data right now and build in extra verification steps before major tasks. For someone who is prepared, technical errors remain manageable—it is the unprepared who suffer the biggest losses.', zh: '今天可能出现技术错误或系统问题，即使对于像你这样精通技术的人也是如此。立即备份重要数据，并在主要任务前建立额外的验证步骤。对于有准备的人来说，技术错误是可管理的——是没有准备的人遭受最大损失。', ja: '技術的なエラーやシステム問題が今日は発生する可能性があります。技術に詳しいあなたでも同様です。今すぐ重要なデータをバックアップして主要なタスクの前に追加の確認ステップを設けてください。準備ができた人にとって技術エラーは対処可能です。準備していない人が最大の損失を被ります。', es: 'Pueden ocurrir errores tecnicos o problemas de sistema hoy, incluso para alguien tan conocedor de tecnologia como tu. Respalda datos importantes ahora mismo y agrega pasos de verificacion adicionales antes de tareas importantes. Para alguien preparado, los errores tecnicos son manejables—son los impreparados quienes sufren las mayores perdidas.' },
      { ko: '당신의 아이디어가 세상보다 앞서있다는 것은 재능이지만, 타이밍을 모르면 묻힐 수 있습니다. 오늘 너무 급진적인 아이디어가 현실에서 받아들여지지 않을 수 있으니, 조금 더 현실에 가까운 방식으로 포장해서 제안해 보세요. 혁신은 이해할 수 있는 언어로 설명될 때 비로소 힘을 갖게 됩니다.', en: 'Ideas too far ahead of their time may not be accepted in reality today—your visionary thinking is a talent, but timing is equally important. Repackage your most radical ideas in language closer to where your audience currently stands. Innovation gains real power only when it can be explained in terms others can understand.', zh: '今天太超前的想法可能在现实中不被接受——你的远见思维是才能，但时机同样重要。将你最激进的想法以更接近受众当前位置的语言重新包装。创新只有当它能以他人可以理解的术语解释时才获得真正的力量。', ja: '先を行き過ぎたアイデアが現実で受け入れられない可能性があります。先見の明のある思考は才能ですが、タイミングも同様に重要です。最も急進的なアイデアを聴衆が現在いる場所に近い言語で再包装してください。革新は他者が理解できる言葉で説明できて初めて本物の力を持ちます。', es: 'Ideas demasiado avanzadas pueden no ser aceptadas en la realidad hoy—tu pensamiento visionario es un talento, pero el momento es igualmente importante. Reempaqueta tus ideas mas radicales en lenguaje mas cercano a donde esta tu audiencia actualmente. La innovacion gana poder real solo cuando puede explicarse en terminos que otros puedan entender.' },
      { ko: '지루한 반복 작업이 계속되어 에너지가 소진될 수 있습니다. 하지만 이 시간이 낭비가 아님을 기억하세요—기본에 충실한 사람에게 곧 전환점이 찾아옵니다. 반복 속에서 작은 효율 개선점을 찾아보는 것이 지루함을 의미 있는 시간으로 바꾸는 좋은 방법입니다.', en: 'Tedious repetitive work may continue today, draining your energy gradually. But remember this time is not wasted—a turning point is coming soon for those who stay true to the basics. Try finding small efficiency improvements within the repetition; it transforms boredom into meaningful productive time.', zh: '今天可能继续无聊的重复工作，逐渐消耗你的能量。但请记住这段时间不是浪费——对于忠于基本功的人来说，转折点很快就会来临。尝试在重复中找到小的效率改进，它将无聊转化为有意义的生产时间。', ja: '退屈な繰り返し作業が続いてエネルギーが徐々に消耗するかもしれません。しかしこの時間が無駄ではないことを覚えておいてください。基本に忠実な人にはすぐに転換点が来ます。繰り返しの中で小さな効率改善を探してみてください。退屈を意味のある生産的な時間に変えられます。', es: 'El trabajo repetitivo tedioso puede continuar hoy, drenando tu energia gradualmente. Pero recuerda que este tiempo no es desperdiciado—pronto llegara un punto de inflexion para quienes se mantienen fieles a los fundamentos. Intenta encontrar pequenas mejoras de eficiencia dentro de la repeticion; transforma el aburrimiento en tiempo productivo significativo.' },
      { ko: '권위에 도전하는 물병자리의 성향이 오늘 상사와의 마찰로 이어질 수 있습니다. 감정이 앞서면 상황이 더 어려워질 수 있으니, 대화에서 사실과 데이터에 근거하여 논리적으로 이야기하세요. 당신의 관점을 지키면서도 상대를 존중하는 방식이 가장 강력한 설득력을 발휘합니다.', en: 'Friction with your boss is expected today as your authority-challenging Aquarian nature encounters resistance. Letting emotion lead will only make things harder—speak based on facts and data, and make your case logically. Defending your perspective while showing respect for the other person is the approach with the most persuasive power.', zh: '今天预计与上司发生摩擦，因为你挑战权威的水瓶座本性遇到了阻力。让情绪主导只会使事情更困难——基于事实和数据说话，逻辑地陈述你的理由。在坚守你的观点的同时尊重对方，是最有说服力的方法。', ja: '上司との摩擦が予想されます。権威に挑戦する水瓶座の本性が抵抗に遭います。感情が先に立つと状況がより困難になります。事実とデータに基づいて論理的に話してください。相手を尊重しながら自分の観点を守る方法が最も強い説得力を発揮します。', es: 'Se esperan fricciones con tu jefe hoy cuando tu naturaleza acuariana de desafiar la autoridad encuentra resistencia. Dejar que la emocion lidere solo hara las cosas mas dificiles—habla basandote en hechos y datos, y presenta tu caso logicamente. Defender tu perspectiva mientras muestras respeto es el enfoque con mas poder persuasivo.' },
      { ko: '프로젝트가 답보 상태에 빠진 것 같은 느낌이 오늘 유독 강하게 들 수 있습니다. 조급하게 속도를 내려 하면 오히려 취약한 부분이 드러날 수 있습니다. 지금은 빠른 전진보다 기초를 단단히 다지는 시간으로 삼으세요—기반이 강할수록 나중에 더 빠르고 높이 나아갈 수 있습니다.', en: 'You may feel project progress is stagnant today, creating frustration. Rushing to accelerate may actually expose weak foundations. Use this time to strengthen the fundamentals instead—the more solid the base, the faster and higher you will be able to move later. Patience with foundations is never wasted time.', zh: '今天你可能感觉项目进展停滞，产生挫败感。急于加速实际上可能暴露薄弱的基础。用这段时间来加强基础——基础越坚固，以后前进得越快越高。对基础的耐心从不是浪费的时间。', ja: 'プロジェクトの進行が停滞している感覚が今日は特に強く感じられるかもしれません。焦って速度を上げようとすると、脆弱な部分が露呈する可能性があります。今は基礎を固める時間として使ってください。基盤が強いほど後でより速く高く進めます。', es: 'Puedes sentir que el proyecto se estanca hoy, creando frustracion. Apresurarte a acelerar puede en realidad exponer cimientos debiles. Usa este tiempo para fortalecer los fundamentos—cuanto mas solida la base, mas rapido y alto podras moverte despues. La paciencia con los cimientos nunca es tiempo perdido.' },
      { ko: '변화에 대한 갈증이 오늘 직업적 결단을 충동적으로 내리도록 부추길 수 있습니다. 하지만 커리어 변화는 한 번 내리면 되돌리기 어려운 결정입니다. 지금은 충분한 정보를 수집하고 선택지들을 면밀히 비교하는 시기로 삼으세요—준비된 변화만이 진정한 도약이 됩니다.', en: 'Don\'t make impulsive career change decisions today—the thirst for change may be pushing you toward hasty choices, but career changes are difficult to reverse. Now is the time to gather information thoroughly and carefully compare your options. Only a well-prepared change becomes a genuine leap forward.', zh: '今天不要做出冲动的职业变化决定——对变化的渴望可能推动你做出草率的选择，但职业变化很难逆转。现在是彻底收集信息并仔细比较选项的时候。只有充分准备的变化才能成为真正的飞跃。', ja: '職業的な変化を衝動的に決めないでください。変化への渇望が性急な選択に向かわせるかもしれませんが、キャリアの変化は元に戻しにくいです。今は情報を徹底的に集めて選択肢を慎重に比較する時期です。準備された変化だけが真の飛躍になります。', es: 'No tomes decisiones impulsivas de cambio profesional hoy—la sed de cambio puede estar empujandote hacia elecciones apresuradas, pero los cambios de carrera son dificiles de revertir. Ahora es el momento de reunir informacion a fondo y comparar cuidadosamente tus opciones. Solo un cambio bien preparado se convierte en un verdadero salto adelante.' },
      { ko: '오늘 당신의 커리어 이상과 현실 사이의 거리가 유독 멀어 보일 수 있습니다. 그 간극에 압도되지 마세요—모든 위대한 커리어는 작은 한 걸음의 반복으로 이루어졌습니다. 지금 내딛을 수 있는 단 하나의 현실적인 발걸음을 찾아보세요—그 한 걸음이 결국 당신을 목적지로 데려다줍니다.', en: 'The gap between your career ideals and reality seems exceptionally large today—do not be overwhelmed by it. Every great career was built through the repetition of small individual steps. Find just one realistic step you can take right now; that single step is what will eventually carry you to your destination.', zh: '今天你的职业理想和现实之间的差距看起来特别大——不要被它压倒。每一个伟大的职业都是通过重复小的个人步骤建立的。找到你现在可以采取的一个现实步骤；那单一步骤最终会将你带到目的地。', ja: 'キャリアの理想と現実の乖離が今日は特に大きく見えます。それに圧倒されないでください。すべての偉大なキャリアは小さな一歩の繰り返しで作られました。今踏み出せる一つの現実的な一歩を見つけてください。その一歩があなたを最終的に目的地へ連れて行きます。', es: 'La brecha entre tus ideales de carrera y la realidad parece excepcionalmente grande hoy—no te dejes abrumar por ella. Toda gran carrera fue construida mediante la repeticion de pequenos pasos individuales. Encuentra solo un paso realista que puedas dar ahora mismo; ese unico paso es lo que eventualmente te llevara a tu destino.' },
    ],
  },
  health: {
    high: [
      { ko: '몸과 마음의 에너지 순환이 오늘 놀라울 만큼 원활합니다. 이 최고의 컨디션을 유산소 운동으로 더욱 강화해 보세요. 평소보다 조금 더 강도를 높여도 무리 없이 소화할 수 있는 날이니, 오늘의 에너지를 낭비하지 말고 신체 능력의 한계를 조금 더 밀어붙여 보세요.', en: 'Energy circulation flows remarkably smoothly today, giving you an excellent overall condition. Channel this peak state into aerobic exercise and push your physical capabilities a little further than usual—your body can handle it today. Do not waste this exceptional energy; use it to build strength that will carry you through harder days.', zh: '今天能量循环流动得出奇顺畅，给你一个出色的整体状态。将这种高峰状态引导到有氧运动中，比平时稍微推进你的身体能力——你的身体今天能够承受。不要浪费这种特殊能量，用它来建立能够支撑你度过艰难时期的力量。', ja: 'エネルギー循環が今日は驚くほど円滑で、優れた全体的なコンディションが得られます。この最高の状態を有酸素運動に向けていつもより少し身体能力を押し上げてください。今日は体がそれに対応できます。この特別なエネルギーを無駄にせずより困難な日々を乗り越える力を築いてください。', es: 'La circulacion de energia fluye notablemente suave hoy, dandote una excelente condicion general. Canaliza este estado pico en ejercicio aerobico y empuja tus capacidades fisicas un poco mas de lo usual—tu cuerpo puede manejarlo hoy. No desperdicies esta energia excepcional; usala para construir fuerza que te lleve a traves de dias mas dificiles.' },
      { ko: '오늘 당신의 정신적 맑음이 최고조에 달합니다. 복잡한 문제를 풀거나 창의적인 작업을 하기에 이보다 좋은 컨디션은 없습니다. 명상으로 이 맑음을 더욱 깊게 하거나, 두뇌를 최대한 활용하는 지적 활동에 집중해 보세요—오늘 당신의 사고력은 평소의 두 배입니다.', en: 'Mental clarity is maximized today, reaching its absolute peak. There is no better condition for solving complex problems or engaging in creative work. Deepen this clarity further through meditation, or dedicate yourself to intellectually demanding activities—your thinking power is operating at double its usual capacity today.', zh: '今天精神清晰度达到绝对巅峰。没有比这更好的状态来解决复杂问题或从事创意工作了。通过冥想进一步加深这种清晰，或专注于要求高的智力活动——你的思维能力今天以平常两倍的容量运作。', ja: '精神的な明晰さが今日は最大限に達し、絶対的なピークに達します。複雑な問題を解くか創造的な仕事をするのにこれ以上の状態はありません。瞑想でこの明晰さをさらに深めるか、知的に要求の高い活動に専念してください。思考力が今日は通常の倍の容量で動いています。', es: 'La claridad mental se maximiza hoy, alcanzando su pico absoluto. No hay mejor condicion para resolver problemas complejos o involucrarse en trabajo creativo. Profundiza esta claridad mediante meditacion, o dedicarte a actividades intelectualmente exigentes—tu poder de pensamiento opera al doble de su capacidad habitual hoy.' },
      { ko: '새로운 것을 시작하기 좋아하는 당신에게 오늘은 새로운 건강 루틴을 시작하기 위한 최고의 에너지가 주어집니다. 기존의 틀을 벗어난 혁신적인 운동법을 시도해 보세요. 오늘 시작한 건강 습관이 30일 후 당신의 몸을 완전히 바꿔놓을 수 있습니다.', en: 'A good day to start a new health routine—you are given the best energy today for initiating fresh beginnings. Try an innovative exercise method that breaks from convention. The health habit you start today has the potential to completely transform your body thirty days from now. Begin boldly.', zh: '今天是开始新健康习惯的好日子——你被给予了开始新鲜开端的最佳能量。尝试一种打破传统的创新运动方法。你今天开始的健康习惯有可能在30天后彻底改变你的身体。大胆开始吧。', ja: '新しい健康ルーティンを始めるのに良い日で、新鮮な始まりを開始するための最高のエネルギーが与えられています。型を破った革新的な運動法を試してみてください。今日始めた健康習慣が30日後にあなたの体を完全に変える可能性があります。大胆に始めてください。', es: 'Buen dia para iniciar una nueva rutina de salud—se te da la mejor energia hoy para iniciar nuevos comienzos. Prueba un metodo de ejercicio innovador que rompa con la convencion. El habito de salud que empieces hoy tiene el potencial de transformar completamente tu cuerpo treinta dias despues. Comienza con audacia.' },
      { ko: '항상 활발하게 달리는 당신의 신경계가 오늘 드디어 안정을 되찾으며 수면의 질이 높아지는 기운이 흐릅니다. 이 안정의 기운을 최대한 활용해 충분히 쉬어보세요. 양질의 수면이 당신의 혁신적인 능력을 다음 날 더욱 강하게 되살려줄 것입니다.', en: 'Your nervous system stabilizes today, improving sleep quality in a welcome shift. Your system is always running at high speed, so this stabilization is a precious gift—take full advantage of it and rest deeply. Quality sleep will restore and amplify your innovative abilities for the days ahead.', zh: '你的神经系统今天稳定，睡眠质量以令人欣喜的转变改善。你的系统总是以高速运转，所以这种稳定是珍贵的礼物——充分利用它，深度休息。高质量的睡眠将为未来的日子恢复和放大你的创新能力。', ja: '神経系が今日は安定して、睡眠の質が向上します。あなたのシステムは常に高速で動いているので、この安定は貴重な贈り物です。それを最大限に活用して深く休んでください。質の高い睡眠があなたの革新的な能力を翌日のためにさらに強く回復させてくれます。', es: 'Tu sistema nervioso se estabiliza hoy, mejorando la calidad del sueno en un cambio bienvenido. Tu sistema siempre corre a alta velocidad, asi que esta estabilizacion es un regalo precioso—aprovechalo al maximo y descansa profundamente. El sueno de calidad restaurara y amplificara tus capacidades innovadoras para los dias venideros.' },
      { ko: '오늘 하체의 에너지 순환이 특히 활발해지는 기운이 흐릅니다. 산책이나 조깅 같은 하체 중심 유산소 운동이 이 에너지를 최대한 활용하는 방법입니다. 30분이라도 걷거나 뛰어보세요—발끝부터 머리까지 기운이 돌아 하루 전체가 달라질 것입니다.', en: 'Energy for improved lower body circulation flows strongly today—harness this with walking or jogging for maximum benefit. These lower-body focused aerobic activities will amplify the natural energy surge. Even thirty minutes of movement will transform the way you feel from head to toe, energizing your entire day.', zh: '今天下半身循环改善的能量强劲流动——利用步行或慢跑来获得最大益处。这些以下半身为重点的有氧活动将放大自然的能量涌动。即使30分钟的运动也会从头到脚改变你的感觉，为你的整个一天注入能量。', ja: '下半身の循環が改善されるエネルギーが今日は強く流れています。散歩やジョギングでこれを最大限に活用してください。30分だけ動いても頭から足先まで全体が変わります。一日全体に活力が満ちてきます。', es: 'Fluye fuertemente energia para mejorar la circulacion del tren inferior hoy—aprovechala con caminata o trote para maximo beneficio. Incluso treinta minutos de movimiento transformaran como te sientes de pies a cabeza, energizando todo tu dia.' },
      { ko: '도시와 디지털에서 잠시 벗어나 자연 속에서 시간을 보내면 오늘 전신의 에너지가 완전히 리셋되는 것을 실감할 수 있습니다. 공원이나 숲길을 걸으며 자연의 리듬에 맞춰보세요. 자연은 혁신가에게 가장 강력한 재충전 환경입니다.', en: 'Spending time in nature lets you feel a full-body energy reset today—stepping away from the city and digital screens allows your whole system to recalibrate. Walk through a park or forest path and align yourself with nature\'s rhythm. For an innovator like you, nature is the most powerful recharging environment there is.', zh: '今天在大自然中度过时间让你感受到全身能量重置——远离城市和数字屏幕让你的整个系统重新校准。走在公园或森林小径上，与自然的节奏对齐。对于像你这样的创新者来说，自然是最强大的充电环境。', ja: '自然の中で時間を過ごすと全身のエネルギーがリセットされるのを感じられます。都市とデジタル画面から離れることでシステム全体が再調整されます。公園や森の道を歩いて自然のリズムに合わせてください。あなたのような革新家にとって自然は最も強力な充電環境です。', es: 'Pasar tiempo en la naturaleza te permite sentir un reinicio completo de energia corporal hoy—alejarte de la ciudad y las pantallas digitales permite que todo tu sistema se recalibre. Camina por un parque o sendero forestal y alineate con el ritmo de la naturaleza. Para un innovador como tu, la naturaleza es el entorno de recarga mas poderoso.' },
      { ko: '오늘 당신의 몸은 건강한 식단 변화에 특히 빠르게 반응합니다. 항산화 식품을 하나 더 추가해 보세요—베리류, 녹차, 다크초콜릿 같은 것들이 오늘 당신의 뇌와 몸에 직접적인 활력을 줄 것입니다. 먹는 것이 곧 생각하는 것이 되는 날입니다.', en: 'Healthy diet changes respond especially quickly in your body today—your system is highly receptive to nutritional input right now. Add antioxidant foods such as berries, green tea, or dark chocolate; these will give your brain and body direct vitality today. What you eat today literally becomes what you think tomorrow.', zh: '今天健康饮食变化在你体内的反应特别快——你的系统现在对营养输入高度敏感。添加抗氧化食品，如浆果、绿茶或黑巧克力，这些今天会给你的大脑和身体直接的活力。你今天吃的东西字面上成为你明天思考的东西。', ja: '健康的な食事の変化が今日は特に速く体に反応します。システムが今栄養摂取に非常に敏感です。ベリー類、緑茶、ダークチョコレートなどの抗酸化食品を追加してください。今日あなたの脳と体に直接活力を与えます。今日食べるものが明日考えるものになります。', es: 'Los cambios de dieta saludable responden especialmente rapido en tu cuerpo hoy—tu sistema es muy receptivo a los aportes nutricionales ahora. Anade alimentos antioxidantes como bayas, te verde o chocolate negro; estos daran vitalidad directa a tu cerebro y cuerpo hoy. Lo que comes hoy literalmente se convierte en lo que piensas manana.' },
      { ko: '오늘 스트레스가 빠르고 효과적으로 해소되는 좋은 기운이 흐릅니다. 좋아하는 취미 활동에 시간을 투자해 보세요—그것이 오늘 당신에게 어떤 약보다 강력한 치유제가 됩니다. 좋아하는 일에 몰입하는 시간이 몸과 마음을 동시에 회복시켜 줄 것입니다.', en: 'Stress relief works exceptionally well today, with the energy for natural healing flowing strongly. Invest time in your favorite hobby—it will be more powerful than any medicine today. Immersing yourself in something you love simultaneously restores both body and mind, leaving you refreshed and renewed.', zh: '今天压力释放效果特别好，自然愈合的能量强劲流动。在你最喜欢的爱好上投入时间——今天它将比任何药物都更有力量。沉浸在你喜爱的事物中同时恢复身心，让你精神焕发、焕然一新。', ja: 'ストレス解消が今日は特にうまくいきます。自然な回復のエネルギーが強く流れています。好きな趣味に時間を投資してください。今日はどんな薬よりも強力な治癒薬になります。好きなことに没頭する時間が心身を同時に回復させてくれます。', es: 'El alivio del estres funciona excepcionalmente bien hoy, con la energia para la sanacion natural fluyendo fuertemente. Invierte tiempo en tu pasatiempo favorito—sera mas poderoso que cualquier medicina hoy. Sumergirte en algo que amas restaura simultaneamente cuerpo y mente, dejandote revitalizado/a y renovado/a.' },
      { ko: '오늘 당신의 신체적 활력이 넘쳐 어느 운동이든 소화할 수 있을 것 같은 느낌이 듭니다. 평소보다 강도를 높인 운동을 시도해도 몸이 충분히 따라줄 것입니다. 이 에너지를 낭비하지 말고 체력의 새 경계를 발견하는 날로 삼아보세요—당신이 생각하는 것보다 훨씬 강합니다.', en: 'Physical vitality overflows today, giving you the sensation that you could handle anything. Increasing exercise intensity is not only fine—it is recommended. Do not waste this energy; make today the day you discover a new boundary of your physical strength. You are stronger than you think you are.', zh: '今天身体活力充沛，给你一种可以应对任何事情的感觉。不仅提高运动强度没问题——这是推荐的。不要浪费这种能量；让今天成为你发现身体力量新边界的日子。你比你以为的要强大得多。', ja: '身体的な活力が今日は溢れます。何でも対応できる感覚を与えてくれます。運動強度を上げることは問題ないだけでなく推奨されます。このエネルギーを無駄にしないでください。今日を身体的な強さの新しい境界を発見する日にしてください。あなたは思っているより強いです。', es: 'La vitalidad fisica desborda hoy, dandote la sensacion de que puedes manejar cualquier cosa. Aumentar la intensidad del ejercicio no solo esta bien—esta recomendado. No desperdicies esta energia; haz de hoy el dia en que descubras un nuevo limite de tu fuerza fisica. Eres mas fuerte de lo que crees.' },
      { ko: '기술을 사랑하는 당신이지만, 오늘은 디지털 기기에서 완전히 벗어나 아날로그적 휴식을 취해보세요. 책을 읽거나, 그림을 그리거나, 손으로 무언가를 만들어보세요. 화면에서 눈을 떼는 이 시간이 당신의 회복력을 놀라울 만큼 끌어올려줄 것입니다.', en: 'Stepping away from digital devices for analog rest brings amazing recovery today—even though you love technology, give your nervous system a full digital detox right now. Read a book, draw, or create something with your hands. Detaching from screens will lift your resilience to a surprisingly high level.', zh: '今天远离数字设备进行模拟休息带来惊人的恢复——尽管你喜欢技术，现在给你的神经系统一次完整的数字排毒。读书、画画或用手创造一些东西。脱离屏幕将使你的恢复力提升到令人惊讶的高水平。', ja: 'デジタル機器から離れてアナログ的な休息を取れば驚くべき回復力を経験します。テクノロジーが好きなあなたでも神経系に今完全なデジタルデトックスを与えてください。本を読んだり、絵を描いたり、手で何かを作ってみてください。画面から離れることで回復力が驚くほど高まります。', es: 'Alejarte de dispositivos digitales para un descanso analogico trae una recuperacion asombrosa hoy—aunque amas la tecnologia, dale a tu sistema nervioso un desintoxicacion digital completa ahora. Lee un libro, dibuja o crea algo con tus manos. Desconectarte de las pantallas elevara tu resiliencia a un nivel sorprendentemente alto.' },
    ],
    medium: [
      { ko: '물병자리는 다리와 발목이 약한 부위로, 오늘 종아리와 발목에 가벼운 피로감이 느껴질 수 있습니다. 운동 전후 스트레칭을 꼼꼼히 해주고, 장시간 서 있거나 앉아있는 자세를 피하세요. 작은 예방이 오늘 하루 컨디션 전체를 지켜줄 것입니다.', en: 'Mild fatigue in calves and ankles may occur today—the lower legs are Aquarius\'s vulnerable area. Stretch thoroughly before and after any activity, and avoid prolonged standing or sitting. Small preventative attention to this area will protect your entire day\'s condition.', zh: '今天小腿和脚踝可能出现轻微疲劳感——小腿是水瓶座的脆弱区域。在任何活动前后仔细伸展，避免长时间站立或坐着。对这个区域的小小预防性关注将保护你整天的状态。', ja: '今日はふくらはぎと足首に軽い疲労感があるかもしれません。下肢は水瓶座の脆弱な部位です。活動の前後にしっかりストレッチして長時間の立ちっぱなしや座りっぱなしを避けてください。この部位への小さな予防的な注意が一日全体のコンディションを守ります。', es: 'Puede haber fatiga leve en pantorrillas y tobillos hoy—las piernas inferiores son el area vulnerable de Acuario. Estira a fondo antes y despues de cualquier actividad, y evita estar parado/a o sentado/a por largos periodos. La pequena atencion preventiva a esta area protegera la condicion de todo tu dia.' },
      { ko: '항상 빠르게 돌아가는 당신의 두뇌가 오늘 과부하 상태에 접어들 수 있습니다. 집중력이 흐트러지기 시작했다면 그것은 뇌가 휴식을 요청하는 신호입니다. 25분 집중, 5분 휴식의 패턴으로 일하면 오늘 하루의 생산성을 유지하는 데 큰 도움이 됩니다.', en: 'Watch for brain overload today as your always-fast mind risks going into overdrive. If your concentration starts to fragment, that is your brain requesting rest. Working in cycles of 25 minutes of focus and 5 minutes of rest will significantly help maintain today\'s productivity without burning out.', zh: '今天要注意大脑过载，因为你一直快速运转的思维面临超速运转的风险。如果你的注意力开始分散，那是你的大脑在请求休息。以25分钟专注和5分钟休息的循环工作，将显著帮助在不耗尽的情况下维持今天的生产力。', ja: '今日は脳の過負荷に注意してください。常に速く動くあなたの思考がオーバードライブに入るリスクがあります。集中力が分散し始めたらそれは脳が休息を求めているサインです。25分集中、5分休息のサイクルで仕事をすれば燃え尽きることなく今日の生産性を維持するのに大いに役立ちます。', es: 'Cuidado con la sobrecarga cerebral hoy ya que tu mente siempre rapida corre el riesgo de entrar en sobremarcha. Si tu concentracion empieza a fragmentarse, esa es tu solicitud de descanso. Trabajar en ciclos de 25 minutos de enfoque y 5 minutos de descanso ayudara significativamente a mantener la productividad de hoy sin agotarte.' },
      { ko: '바쁘게 생각하고 움직이다 보면 물 마시는 것을 잊기 쉽습니다. 오늘은 수분 섭취에 의식적으로 신경 써보세요. 충분한 수분 공급이 순환계 건강을 지키고 당신의 사고력과 에너지 수준을 유지하는 데 직접적인 영향을 줍니다. 1시간마다 물 한 잔을 마시는 습관을 만들어보세요.', en: 'Paying attention to water intake helps circulatory health today—it is easy to forget to hydrate when your mind is racing. Make a conscious effort to drink water frequently. Adequate hydration has a direct positive impact on your thinking ability and energy level, helping you stay sharp throughout the day.', zh: '今天注意水分摄入有助于循环系统健康——当你的思维飞速运转时很容易忘记补水。有意识地努力频繁喝水。充足的水分补充对你的思维能力和能量水平有直接的积极影响，帮助你全天保持敏锐。', ja: '水分摂取に気を配れば今日の循環器系の健康に役立ちます。思考が速いときに水を飲むことを忘れがちです。意識的に頻繁に水を飲む努力をしてください。十分な水分補給は思考能力とエネルギーレベルに直接プラスの影響を与え、一日中鋭く保つのに役立ちます。', es: 'Prestar atencion a la ingesta de agua ayuda a la salud circulatoria hoy—es facil olvidar hidratarse cuando tu mente va rapido. Haz un esfuerzo consciente de beber agua frecuentemente. La hidratacion adecuada tiene un impacto positivo directo en tu capacidad de pensamiento y nivel de energia, ayudandote a mantenerte alerta.' },
      { ko: '자유로운 영혼인 당신은 규칙적인 생활 패턴이 어렵게 느껴질 수 있습니다. 하지만 불규칙한 일상이 오늘 컨디션에 영향을 미치고 있다면 작은 리듬을 만들어가는 것을 시작해보세요. 완벽한 루틴이 아니어도 됩니다—잠드는 시간과 일어나는 시간만 일정하게 해도 큰 차이가 납니다.', en: 'Irregular life patterns may affect your condition today—structure can feel limiting to a free spirit like you, but small rhythms protect your health. You do not need a perfect routine; even just keeping consistent sleep and wake times can make an enormous difference in how you feel and function every day.', zh: '今天不规律的生活模式可能影响你的状态——结构对于像你这样的自由灵魂可能感觉受限，但小的节奏可以保护你的健康。你不需要完美的常规；即使只是保持一致的睡眠和起床时间，对你每天的感受和功能也会产生巨大差异。', ja: '不規則な生活パターンが今日のコンディションに影響を与える可能性があります。自由な魂のあなたには構造が制限的に感じるかもしれません。しかし小さなリズムが健康を守ります。完璧なルーティンは必要ありません。就寝時間と起床時間を一定にするだけで大きな違いが生まれます。', es: 'Los patrones de vida irregulares pueden afectar tu condicion hoy—la estructura puede sentirse limitante para un espiritu libre como tu, pero los pequenos ritmos protegen tu salud. No necesitas una rutina perfecta; incluso solo mantener horarios consistentes de sueno puede hacer una enorme diferencia en como te sientes y funcionas cada dia.' },
      { ko: '빠르게 달리는 두뇌에 비해 몸이 뒤처지고 있다고 느낄 수 있습니다. 오늘 가벼운 요가나 필라테스가 몸과 마음의 균형을 되찾아주는 데 특히 효과적입니다. 호흡과 움직임에 집중하는 시간이 흩어진 에너지를 하나로 모아줄 것입니다.', en: 'Light yoga or Pilates is particularly effective for balancing mind and body today—your fast-running brain may be outpacing your physical body. Focusing on breath and movement will gather your scattered energy into a unified whole, restoring the equilibrium that your body needs to support your brilliant mind.', zh: '今天轻度瑜伽或普拉提对平衡身心特别有效——你快速运转的大脑可能超过了你的身体。专注于呼吸和运动将把你分散的能量聚集成统一的整体，恢复你的身体需要支持你出色思维的平衡。', ja: '軽いヨガやピラティスが今日は心身のバランスを整えるのに特に効果的です。速く動く脳が身体を追い越しているかもしれません。呼吸と動きに集中する時間が散らばったエネルギーを一つにまとめ、輝く心を支えるために体が必要とする均衡を取り戻させてくれます。', es: 'El yoga ligero o Pilates es particularmente efectivo para equilibrar mente y cuerpo hoy—tu cerebro de rapido funcionamiento puede estar superando a tu cuerpo fisico. Enfocarte en la respiracion y el movimiento reunira tu energia dispersa en un todo unificado, restaurando el equilibrio que tu cuerpo necesita para apoyar tu mente brillante.' },
      { ko: '오늘 카페인이 신경계를 과도하게 자극할 수 있으니 섭취를 줄이는 것이 좋습니다. 허브차로 대체하면 각성 효과는 유지하면서 신경계의 과부하를 막을 수 있습니다. 캐모마일, 라벤더, 페퍼민트 중 하나를 선택해 보세요—오늘 하루가 훨씬 편안하고 집중력도 더 오래 유지됩니다.', en: 'Reducing caffeine and switching to herbal tea benefits the nervous system today—caffeine may over-stimulate an already active system. Choose chamomile, lavender, or peppermint tea as a substitute. The alertness benefit is maintained while preventing nervous system overload, and your focus will last longer throughout the day.', zh: '今天减少咖啡因并改用草本茶有益于神经系统——咖啡因可能过度刺激已经活跃的系统。选择洋甘菊、薰衣草或薄荷茶作为替代品。保持警觉性的同时防止神经系统过载，你的专注力将在一天中持续更长时间。', ja: 'カフェイン摂取を減らしてハーブティーに替えると神経系に良い日です。すでに活発なシステムをカフェインが過剰に刺激する可能性があります。カモミール、ラベンダー、ペパーミントティーを代替に選んでください。覚醒効果を維持しながら神経系の過負荷を防ぎ、集中力が一日中より長く続きます。', es: 'Reducir la cafeina y cambiar a te herbal beneficia al sistema nervioso hoy—la cafeina puede sobre-estimular un sistema ya activo. Elige te de manzanilla, lavanda o menta como sustituto. Se mantiene el beneficio de alerta mientras se previene la sobrecarga del sistema nervioso, y tu concentracion durara mas durante el dia.' },
      { ko: '실내에만 머물다 보면 에너지가 정체되고 생각도 함께 갇히게 됩니다. 잠깐이라도 바깥으로 나가 신선한 공기를 마셔보세요. 10분의 야외 활동이 한 시간의 실내 휴식보다 훨씬 강한 기분 전환 효과를 줍니다. 하늘을 보는 것만으로도 당신의 넓은 시야가 회복됩니다.', en: 'Do not just stay indoors today—when confined inside, both your energy and your thinking can become stagnant. Even a brief trip outside for fresh air will do more for your mood than an hour of indoor rest. Ten minutes outdoors restores your naturally wide perspective and gives you the reset you need.', zh: '今天不要只待在室内——被困在室内时，你的能量和思维都可能变得停滞。即使短暂外出呼吸新鲜空气，对你的心情也比一小时的室内休息做得更多。10分钟的户外活动恢复你天然宽广的视野，给你所需的重置。', ja: '室内にいるだけでなく少しでも外の空気を吸いましょう。室内に閉じこもっているとエネルギーも思考も停滞します。短い外出でも室内での一時間の休息より気分転換に効果的です。10分の屋外活動があなたの自然に広い視野を回復させリセットをもたらします。', es: 'No te quedes solo adentro hoy—cuando estas confinado adentro, tanto tu energia como tu pensamiento pueden estancarse. Incluso una breve salida al aire fresco hara mas por tu estado de animo que una hora de descanso interior. Diez minutos afuera restaura tu perspectiva naturalmente amplia y te da el reinicio que necesitas.' },
      { ko: '두뇌를 과도하게 사용한 뒤에는 반드시 몸을 움직이는 활동으로 균형을 잡아주어야 합니다. 정신과 신체의 균형이 무너지면 두뇌 피로가 더 오래 지속됩니다. 스트레칭, 산책, 댄스 등 즐거운 신체 활동을 10~20분만 해도 정신 에너지가 신기하게 회복됩니다.', en: 'After excessive mental activity, balance with physical movement—without this balance, mental fatigue can last much longer. Stretching, walking, or even dancing for just 10 to 20 minutes of enjoyable physical activity will mysteriously restore your mental energy. The body-mind connection is one of your most powerful health tools.', zh: '过度精神活动后，用身体运动来平衡是必须的——没有这种平衡，精神疲劳会持续更长时间。伸展、散步或甚至跳舞，只需10到20分钟的愉快身体活动就能神奇地恢复你的精神能量。身心连接是你最强大的健康工具之一。', ja: '過度な精神活動の後は体を動かす活動でバランスを取ることが必要です。このバランスがなければ精神的な疲労がより長く続きます。ストレッチ、散歩、ダンスなど10〜20分の楽しい身体活動だけで精神エネルギーが不思議と回復します。心身のつながりはあなたの最も強力な健康ツールの一つです。', es: 'Despues de actividad mental excesiva, equilibra con movimiento fisico—sin este equilibrio, la fatiga mental puede durar mucho mas. Estirar, caminar, o incluso bailar durante solo 10 a 20 minutos de actividad fisica agradable restaurara misteriosamente tu energia mental. La conexion cuerpo-mente es una de tus herramientas de salud mas poderosas.' },
      { ko: '화면에 많은 시간을 보내는 당신에게 눈의 피로는 쉽게 축적됩니다. 20분마다 화면에서 눈을 떼고 최소 6미터 이상 먼 곳을 20초 바라보는 20-20-20 법칙을 실천해 보세요. 눈이 피로하지 않으면 두뇌도 더 오래 맑게 유지됩니다.', en: 'Eye fatigue accumulates easily for someone who spends much time on screens—build the habit of looking into the distance every 20 minutes. Practice the 20-20-20 rule: every 20 minutes, look at something 20 feet away for 20 seconds. When your eyes are not fatigued, your brain stays sharper for much longer.', zh: '对于花大量时间在屏幕上的人来说，眼睛疲劳容易积累——养成每20分钟看远处的习惯。练习20-20-20规则：每20分钟，看20英尺外的东西20秒。当你的眼睛不疲劳时，你的大脑会保持清醒更长时间。', ja: 'スクリーンに多くの時間を費やすあなたには目の疲れが蓄積しやすいです。20分ごとに遠くを見る習慣をつけてください。20-20-20ルールを実践してください：20分ごとに6メートル以上先のものを20秒見ます。目が疲れないと脳もずっと長く明晰に保てます。', es: 'La fatiga ocular se acumula facilmente para alguien que pasa mucho tiempo en pantallas—crea el habito de mirar lejos cada 20 minutos. Practica la regla 20-20-20: cada 20 minutos, mira algo a 6 metros de distancia durante 20 segundos. Cuando tus ojos no estan fatigados, tu cerebro se mantiene mas agudo por mucho mas tiempo.' },
      { ko: '오늘 전체적인 건강 상태는 무난한 수준입니다. 더 활기찬 컨디션을 원한다면 물병자리의 약한 부위인 하체를 강화하는 근력 운동을 추가해 보세요. 스쿼트나 런지 같은 하체 운동을 꾸준히 해나가면 전체적인 활력이 눈에 띄게 향상됩니다.', en: 'Overall health is fine today, but adding lower body strength training would elevate your condition to a noticeably better level. The lower body is Aquarius\'s vulnerable area—consistently strengthening it through squats and lunges will produce visible improvements in your overall vitality. Small investments in targeted training pay large dividends.', zh: '今天整体健康状态不错，但加入下半身力量训练会将你的状态提升到明显更好的水平。下半身是水瓶座的脆弱区域——通过深蹲和弓步持续加强它将在你的整体活力上产生可见的改善。在有针对性的训练上的小投入会产生大回报。', ja: '全体的に無難な健康状態ですが下半身の筋力トレーニングを加えるとコンディションが明らかに良くなります。下半身は水瓶座の脆弱な部位です。スクワットやランジで継続的に強化すると全体的な活力が目に見えて向上します。目標を絞ったトレーニングへの小さな投資が大きな配当をもたらします。', es: 'La salud general esta bien hoy, pero anadir entrenamiento de fuerza del tren inferior elevaria tu condicion a un nivel notablemente mejor. El tren inferior es el area vulnerable de Acuario—fortalecerlo consistentemente a traves de sentadillas y estocadas producira mejoras visibles en tu vitalidad general. Las pequenas inversiones en entrenamiento especifico dan grandes dividendos.' },
    ],
    low: [
      { ko: '평소보다 신경이 더 예민하고 자극에 취약한 날입니다. 이것은 당신의 신경계가 충전을 요청하는 신호입니다. 과도한 소음, 너무 많은 정보 입력, 강한 빛 등 자극을 의식적으로 줄이고 조용하고 안전한 환경을 만들어보세요. 오늘 쉰 만큼 내일 더 강해집니다.', en: 'A day when nerves become easily sensitive and more vulnerable to stimulation than usual—this is your nervous system requesting a recharge. Consciously reduce excessive noise, information overload, and strong light, and create a quiet, safe environment. Every bit of rest you take today makes you stronger tomorrow.', zh: '今天神经比平常更容易变得敏感，对刺激更脆弱——这是你的神经系统请求充电的信号。有意识地减少过度噪音、信息过载和强光，创造一个安静、安全的环境。你今天休息的每一点都让你明天更强大。', ja: '神経が敏感になりやすく通常より刺激に脆弱な日です。これは神経系が充電を求めているサインです。過度な騒音、情報過多、強い光などの刺激を意識的に減らして静かで安全な環境を作ってください。今日休んだ分だけ明日強くなります。', es: 'Un dia donde los nervios se sensibilizan facilmente y son mas vulnerables a la estimulacion que de costumbre—esta es tu sistema nervioso solicitando una recarga. Reduce conscientemente el ruido excesivo, la sobrecarga de informacion y la luz fuerte, y crea un ambiente tranquilo y seguro. Cada poco de descanso que tomes hoy te hace mas fuerte manana.' },
      { ko: '물병자리의 신체적 약점인 발목 부위에 오늘 특히 주의가 필요합니다. 계단을 오르내릴 때나 미끄러운 표면에서 발걸음을 조심하세요. 또한 오늘 운동할 때는 발목 스트레칭을 먼저 충분히 하고 시작하는 것이 부상을 예방하는 가장 효과적인 방법입니다.', en: 'Watch for ankle injuries today—the ankle is Aquarius\'s physical weak point and needs extra caution right now. Be especially careful on stairs or slippery surfaces. Before any exercise, stretch your ankles thoroughly first; this is the most effective way to prevent an injury that could slow you down considerably.', zh: '今天要注意脚踝受伤——脚踝是水瓶座的身体弱点，现在需要格外谨慎。在楼梯或滑溜的地方要特别小心。在任何运动之前，先充分伸展脚踝；这是防止可能大大减慢你速度的伤害的最有效方法。', ja: '足首の怪我に注意してください。足首は水瓶座の身体的な弱点で今は特に注意が必要です。階段や滑りやすい場所では特に気をつけてください。運動の前は足首を十分にストレッチしてください。これが怪我を防ぐ最も効果的な方法です。', es: 'Cuidado con lesiones de tobillo hoy—el tobillo es el punto debil fisico de Acuario y necesita precaucion extra ahora. Ten especial cuidado en escaleras o superficies resbaladizas. Antes de cualquier ejercicio, estira tus tobillos a fondo primero; esta es la forma mas efectiva de prevenir una lesion que podria frenarte considerablemente.' },
      { ko: '활발한 두뇌가 밤에도 쉬지 않으려 해서 불면증이 찾아올 수 있습니다. 잠들기 한 시간 전에 전자기기를 내려놓는 것이 가장 효과적인 대비책입니다. 취침 전 따뜻한 목욕이나 독서로 뇌를 부드럽게 전환해 보세요—충분한 수면이 내일의 창의력을 지켜줍니다.', en: 'Insomnia may visit tonight as your active brain refuses to rest—the most effective preventative measure is stopping electronic device use one hour before sleep. Gently transition your brain with a warm bath or reading before bed. Sufficient sleep is what protects your creativity and innovation capacity for tomorrow.', zh: '今晚可能会出现失眠，因为你活跃的大脑拒绝休息——最有效的预防措施是睡前一小时停止使用电子设备。用温水浴或睡前阅读轻柔地过渡你的大脑。充足的睡眠是保护你明天创造力和创新能力的东西。', ja: '活発な脳が休もうとしないため不眠症が訪れる可能性があります。就寝1時間前に電子機器の使用をやめることが最も効果的な予防策です。入浴前に温かいお風呂や読書で脳を穏やかに切り替えてください。十分な睡眠が明日の創造力と革新能力を守ります。', es: 'El insomnio puede visitar esta noche ya que tu cerebro activo se niega a descansar—la medida preventiva mas efectiva es dejar de usar dispositivos electronicos una hora antes de dormir. Transiciona gentilmente tu cerebro con un bano caliente o lectura antes de dormir. El sueno suficiente es lo que protege tu creatividad e innovacion para manana.' },
      { ko: '순환계에 부담이 생길 수 있는 날입니다. 장시간 같은 자세로 앉아있거나 서있으면 다리와 발목에 혈액이 정체될 수 있습니다. 매 30~45분마다 자리에서 일어나 조금 걸어보세요. 간단한 발목 돌리기 운동이 순환을 크게 개선시켜 줍니다.', en: 'Circulatory system may be strained today—remaining in the same position for long periods can cause blood to pool in the legs and ankles. Get up and walk around every 30 to 45 minutes. Simple ankle rotation exercises between movements will significantly improve circulation and prevent discomfort throughout the day.', zh: '今天循环系统可能受到负担——长时间保持同一姿势可能导致腿和脚踝血液淤积。每30到45分钟起来走动一下。简单的脚踝旋转练习将显著改善循环，防止全天不适。', ja: '循環器系に負担がかかる可能性があります。長時間同じ姿勢でいると脚と足首に血液が滞る可能性があります。30〜45分ごとに立ち上がって少し歩いてください。簡単な足首回し運動が循環を大きく改善し一日中不快感を防ぎます。', es: 'El sistema circulatorio puede resentirse hoy—permanecer en la misma posicion por largos periodos puede hacer que la sangre se acumule en piernas y tobillos. Levantate y camina cada 30 a 45 minutos. Simples ejercicios de rotacion de tobillo entre movimientos mejoraran significativamente la circulacion y prevendran molestias durante el dia.' },
      { ko: '쌓인 스트레스가 오늘 두통이나 근육 경련 같은 신체 증상으로 나타날 수 있습니다. 마그네슘이 이런 증상 완화에 효과적이니 음식이나 보충제를 통해 섭취를 고려해 보세요. 아보카도, 견과류, 다크초콜릿 등이 마그네슘이 풍부한 식품입니다. 몸이 보내는 신호를 외면하지 마세요.', en: 'Stress may manifest as headaches or muscle cramps today—your body is communicating accumulated tension through physical signals. Magnesium is effective for relieving these symptoms; consider getting it through foods like avocado, nuts, or dark chocolate, or through supplements. Never ignore the signals your body sends you.', zh: '今天压力可能以头痛或肌肉痉挛的形式表现——你的身体通过物理信号传达积累的紧张。镁对缓解这些症状有效；考虑通过鳄梨、坚果或黑巧克力等食物或补充剂来获取。永远不要忽视你的身体发出的信号。', ja: 'ストレスが頭痛や筋肉痙攣として現れる可能性があります。身体が積み重なった緊張を物理的なサインで伝えています。マグネシウムはこれらの症状の緩和に効果的です。アボカド、ナッツ類、ダークチョコレートなどの食品や補充剤を通じて摂取を検討してください。身体が送るサインを無視しないでください。', es: 'El estres puede manifestarse como dolores de cabeza o calambres hoy—tu cuerpo esta comunicando tension acumulada a traves de senales fisicas. El magnesio es efectivo para aliviar estos sintomas; considera obtenerlo a traves de alimentos como aguacate, nueces o chocolate negro, o suplementos. Nunca ignores las senales que te envia tu cuerpo.' },
      { ko: '하고 싶은 일이 너무 많아 쉬는 것을 죄처럼 느끼는 것이 당신의 패턴일 수 있습니다. 하지만 과로의 신호가 보인다면 지금 즉시 멈춰야 합니다. 지금 쉬지 않으면 나중에 훨씬 더 긴 회복 시간이 필요해집니다. 쉼은 낭비가 아니라 미래의 나를 위한 투자입니다.', en: 'Do not ignore signs of overwork today—your pattern may be feeling guilty about resting when there is so much you want to do. But when overwork signals appear, you must stop immediately. If you do not rest now, the recovery time needed later will be far longer. Rest is not waste; it is investment in your future self.', zh: '今天不要忽视过劳的信号——你的模式可能是在有这么多你想做的事情时感到休息有罪。但是当过劳信号出现时，你必须立即停止。如果你现在不休息，以后需要的恢复时间将长得多。休息不是浪费；它是对未来自己的投资。', ja: '過労のサインを今日は無視しないでください。やりたいことがたくさんあるのに休むことに罪悪感を感じるのがあなたのパターンかもしれません。しかし過労のサインが現れたら今すぐ止まらなければなりません。今休まなければ後で必要な回復時間がはるかに長くなります。休息は無駄ではなく未来の自分への投資です。', es: 'No ignores las senales de exceso de trabajo hoy—tu patron puede ser sentirte culpable por descansar cuando hay tanto que quieres hacer. Pero cuando aparecen senales de exceso de trabajo, debes detenerte de inmediato. Si no descansas ahora, el tiempo de recuperacion necesario despues sera mucho mas largo. El descanso no es desperdicio; es inversion en tu yo futuro.' },
      { ko: '오늘 몸의 컨디션이 갑자기 달라지는 것을 느낄 수 있습니다. 이런 변화에 당황하지 말고, 몸이 무언가를 조절하려 하는 신호로 읽어보세요. 무리한 활동은 자제하고 몸이 원하는 것을 들어주세요—쉬고 싶다면 쉬고, 가볍게 움직이고 싶다면 그렇게 하세요.', en: 'Sudden condition changes may surprise you today—do not be alarmed, but read this as your body signaling that it needs to recalibrate something. Refrain from overexertion and listen to what your body wants. If it wants rest, rest; if it wants gentle movement, do that. Your body\'s wisdom is reliable today.', zh: '今天突然的状态变化可能让你措手不及——不要惊慌，而是把这读作你的身体发出需要重新校准某些东西的信号。避免过度活动，听从你的身体想要什么。如果它想要休息，就休息；如果它想要轻柔的运动，就那样做。你的身体今天的智慧是可靠的。', ja: '急なコンディションの変化に驚く可能性があります。慌てずにこれを身体が何かを調整しようとしているサインとして読んでください。無理な活動は控えて身体が望むことを聞いてください。休みたければ休み、軽く動きたければそうしてください。今日あなたの身体の知恵は信頼できます。', es: 'Cambios repentinos de condicion pueden sorprenderte hoy—no te alarmes, sino lee esto como tu cuerpo senalando que necesita recalibrarse. Evita actividades excesivas y escucha lo que tu cuerpo quiere. Si quiere descanso, descansa; si quiere movimiento suave, hazlo. La sabiduria de tu cuerpo es confiable hoy.' },
      { ko: '차가운 공기가 물병자리의 약한 부위인 하체를 특히 취약하게 만드는 날입니다. 외출할 때 다리를 따뜻하게 유지하고, 실내에서도 차가운 바닥에 오래 서 있는 것을 피하세요. 발을 따뜻하게 하면 전신 혈액순환이 개선되고 에너지 흐름도 더 원활해집니다.', en: 'Cold air makes your lower body especially vulnerable today—Aquarius\'s weak area is already susceptible, and cold exacerbates it. Keep your legs warm when going out and avoid standing on cold floors for long periods indoors. Warming your feet improves full-body circulation and makes your energy flow more smoothly.', zh: '今天冷空气让水瓶座的弱点区域下半身特别脆弱。外出时保持双腿温暖，室内也避免长时间站在冷地板上。温暖你的脚可以改善全身血液循环，让你的能量流动更顺畅。', ja: '冷たい空気で下半身が特に脆弱になりやすい日です。水瓶座の弱い部位はすでに敏感で冷えがそれを悪化させます。外出時は脚を温かく保ち室内でも冷たい床に長時間立つことを避けてください。足を温めると全身の血液循環が改善しエネルギーの流れがより円滑になります。', es: 'El aire frio hace el tren inferior especialmente vulnerable hoy—el area debil de Acuario ya es susceptible, y el frio la agrava. Mantén las piernas calientes al salir y evita pararte en suelos frios por largos periodos en interiores. Calentar tus pies mejora la circulacion de todo el cuerpo y hace que tu energia fluya mas suavemente.' },
      { ko: '정신적 피로가 쌓이면 몸도 함께 지쳐가는 것을 오늘 경험할 수 있습니다. 에너지를 회복하려면 먼저 감정 해소의 통로를 찾아야 합니다. 글쓰기, 달리기, 친구와의 솔직한 대화 등 당신에게 맞는 방식으로 쌓인 것들을 비워내세요—비운 만큼 새로운 에너지가 채워집니다.', en: 'Mental fatigue may transfer to physical symptoms today—when the mind is exhausted, the body follows. To restore energy, you first need to find outlets for emotional release. Writing, running, or honest conversation with a friend—choose the method that suits you and empty what has accumulated. The more you empty, the more new energy can fill you.', zh: '今天精神疲劳可能转化为身体症状——当思维耗尽时，身体随之而来。要恢复能量，首先需要找到情绪释放的渠道。写作、跑步或与朋友的诚实对话——选择适合你的方式，清空积累的东西。你清空得越多，新的能量就能填充得越多。', ja: '精神的な疲労が身体症状に転化する可能性があります。心が疲れると体も続きます。エネルギーを回復するにはまず感情を解消する通路を見つける必要があります。書くこと、走ること、友人との正直な会話——あなたに合った方法で積み重なったものを排出してください。排出した分だけ新しいエネルギーが満たされます。', es: 'La fatiga mental puede transferirse a sintomas fisicos hoy—cuando la mente esta agotada, el cuerpo sigue. Para restaurar energia, primero necesitas encontrar vias de liberacion emocional. Escritura, correr, o conversacion honesta con un amigo—elige el metodo que te convenga y vacia lo que se ha acumulado. Cuanto mas vacies, mas energia nueva puede llenarte.' },
      { ko: '지식 탐구를 좋아하는 당신이 건강 증상에 대해 검색을 시작하면 끝이 없어질 수 있습니다. 그리고 그 과정에서 불안만 더 커질 수 있습니다. 실제로 걱정되는 증상이 있다면 인터넷 검색보다 전문가 상담이 훨씬 더 정확하고 안심이 됩니다. 오늘 불필요한 건강 검색을 의도적으로 자제해 보세요.', en: 'Excessive health info searching may increase anxiety today—for someone who loves knowledge like you, this search can become endless and actually amplify worry rather than reduce it. If you have a concerning symptom, consulting a professional is far more accurate and reassuring than internet searches. Intentionally restrain unnecessary health searching today.', zh: '今天过度搜索健康信息可能增加焦虑——对于像你这样热爱知识的人，这种搜索可能无休无止，实际上放大而不是减少担忧。如果你有令人担忧的症状，咨询专家比互联网搜索准确得多，也更令人放心。今天有意识地克制不必要的健康搜索。', ja: '健康関連情報を過度に検索するとかえって不安が大きくなります。知識を愛するあなたにとってこの検索は果てしなくなり心配を減らすのではなく増幅させます。心配な症状があるなら専門家への相談がインターネット検索よりはるかに正確で安心できます。今日は不必要な健康検索を意図的に自制してください。', es: 'Buscar informacion de salud excesivamente puede aumentar la ansiedad hoy—para alguien que ama el conocimiento como tu, esta busqueda puede volverse interminable y amplificar la preocupacion en lugar de reducirla. Si tienes un sintoma preocupante, consultar a un profesional es mucho mas preciso y tranquilizador que buscar en internet. Restringe intencionalmente las busquedas de salud innecesarias hoy.' },
    ],
  },
  money: {
    high: [
      { ko: '남들이 아직 주목하지 않는 영역에서 기회를 먼저 발견하는 것이 당신의 재능입니다. 오늘 혁신적인 투자 아이디어가 실질적인 수익으로 이어지는 강력한 기운이 흐릅니다. 남들의 시선을 의식하지 말고 당신의 직관을 믿어보세요—미래를 먼저 본 사람만이 그 결실을 누립니다.', en: 'Innovative investment ideas connect to real profit today—your talent for spotting opportunities others have not yet noticed is at its strongest. Do not worry about others\' opinions; trust your own intuition. Only those who see the future first get to harvest its rewards.', zh: '今天创新的投资想法与真正的利润相连——你发现他人尚未注意到的机会的才能处于最强状态。不要担心他人的看法，相信自己的直觉。只有最先看到未来的人才能收获它的回报。', ja: '革新的な投資アイデアが今日は実際の収益につながります。他者がまだ気づいていない機会を発見するあなたの才能が最強の状態にあります。他者の意見を気にせず自分の直感を信頼してください。未来を先に見た人だけがその実りを収穫できます。', es: 'Las ideas de inversion innovadoras se conectan con ganancias reales hoy—tu talento para detectar oportunidades que otros aun no han notado esta en su punto mas fuerte. No te preocupes por las opiniones de otros; confia en tu propia intuicion. Solo quienes ven el futuro primero pueden cosechar sus recompensas.' },
      { ko: '당신의 넓고 다양한 인맥이 오늘 재정적 기회를 가져다주는 통로가 됩니다. 뜻밖의 곳에서 흥미로운 제안이 들어올 수 있으니 지인들의 이야기에 귀를 기울여보세요. 인맥을 통한 기회는 혼자 찾아내는 것보다 훨씬 더 안전하고 유망할 수 있습니다.', en: 'Financial opportunities come through your network today—your broad and diverse connections become channels for unexpected prosperity. Interesting proposals may arrive from surprising places, so listen carefully to your acquaintances. Opportunities that come through trusted networks are often safer and more promising than those discovered alone.', zh: '今天财务机会通过你的人脉到来——你广泛多样的联系成为意外繁荣的渠道。有趣的提案可能从令人惊讶的地方到来，所以仔细听取熟人的话。通过可信赖人脉获得的机会通常比独自发现的更安全、更有前景。', ja: 'ネットワークを通じた財政的な機会が今日やってきます。広く多様なつながりが予想外の繁栄のチャンネルになります。意外なところから面白い提案が来るかもしれないので知人の話に注意を傾けてください。信頼できるネットワークを通じた機会はしばしば一人で見つけるものより安全で有望です。', es: 'Oportunidades financieras llegan a traves de tu red hoy—tus conexiones amplias y diversas se convierten en canales de prosperidad inesperada. Propuestas interesantes pueden llegar de lugares sorprendentes, asi que escucha atentamente a tus conocidos. Las oportunidades que llegan a traves de redes de confianza suelen ser mas seguras y prometedoras.' },
      { ko: '기술과 디지털에 친숙한 당신에게 오늘 기술 관련 분야에서 예상하지 못했던 수입이 발생할 수 있습니다. 평소에 관심을 갖고 지켜보던 신기술 트렌드가 오늘 금전적 기회로 연결될 수 있으니, 그 신호를 놓치지 마세요. 기술에 대한 당신의 이해가 최고의 금전적 자산입니다.', en: 'Unexpected income may arise from technology-related fields today—your natural affinity for digital and tech makes you ideally positioned for these opportunities. A tech trend you have been following may connect to a financial opportunity today; don\'t miss that signal. Your deep understanding of technology is your greatest financial asset.', zh: '今天技术相关领域可能产生意想不到的收入——你对数字和技术的天然亲和力使你处于这些机会的理想位置。你一直关注的技术趋势今天可能与财务机会相连，不要错过那个信号。你对技术的深刻理解是你最大的财务资产。', ja: '技術関連の分野で予想外の収入が発生する可能性があります。デジタルと技術への自然な親和性があなたをこれらの機会に理想的に位置づけています。追いかけてきた技術トレンドが今日財政的な機会につながるかもしれません。そのシグナルを見逃さないでください。技術への深い理解が最大の財政的資産です。', es: 'Pueden surgir ingresos inesperados de campos tecnologicos hoy—tu afinidad natural por lo digital y tecnologico te posiciona idealmente para estas oportunidades. Una tendencia tecnologica que has estado siguiendo puede conectarse hoy a una oportunidad financiera; no pierdas esa senal. Tu profunda comprension de la tecnologia es tu mayor activo financiero.' },
      { ko: '혼자 조용히 준비해온 부업이나 사이드 프로젝트가 드디어 금전적 결실을 맺을 때가 됐습니다. 지금까지의 노력이 헛되지 않았다는 것을 오늘 확인하게 될 것입니다. 이 결실을 발판 삼아 더 큰 규모로 확장하는 계획을 세워보세요—시작은 작았지만 가능성은 무한합니다.', en: 'The side gig or project you have long been quietly preparing finally bears financial fruit today—your sustained effort has not been in vain. This confirmation of your hard work arriving now is meaningful. Use this achievement as a springboard for scaling up; what started small holds unlimited potential for growth.', zh: '你长期悄悄准备的副业或项目今天终于结出金钱之果——你持续的努力没有白费。这种确认现在到来是有意义的。将此成就作为扩大规模的跳板；小小的开始蕴含着无限的成长潜力。', ja: '長い間密かに準備してきた副業やサイドプロジェクトが今日ようやく金銭的な実を結びます。持続した努力が無駄ではなかったことを確認できます。この成果を拡大のための踏み台にしてください。小さく始まったものでも無限の成長の可能性を秘めています。', es: 'El trabajo secundario o proyecto que llevas largo tiempo preparando silenciosamente finalmente da frutos financieros hoy—tu esfuerzo sostenido no ha sido en vano. Esta confirmacion de tu trabajo duro llegando ahora es significativa. Usa este logro como trampolín para escalar; lo que comenzo pequeno tiene potencial de crecimiento ilimitado.' },
      { ko: '공동체의 힘을 믿는 당신에게 오늘 공동체 기반의 금융 활동이 개인 단독 투자보다 훨씬 높은 수익을 가져올 가능성이 있습니다. 협동조합, 공동투자, 크라우드펀딩 같은 집합적 금융 활동에서 기회를 찾아보세요. 함께할 때 더 강한 것이 물병자리의 본질입니다.', en: 'Community-based financial activities may bring significantly higher returns than individual investment today—your belief in collective power is an asset here. Look for opportunities in cooperative investing, crowdfunding, or community-driven financial activities. Being stronger together is the very essence of Aquarius.', zh: '今天社区型金融活动可能比个人投资带来显著更高的回报——你对集体力量的信念在这里是资产。寻找合作投资、众筹或社区驱动金融活动的机会。在一起更强是水瓶座的本质。', ja: 'コミュニティベースの金融活動が今日個人投資より大幅に高い収益をもたらす可能性があります。集合的な力への信念がここで資産になります。協同投資、クラウドファンディング、コミュニティ主導の金融活動で機会を探してください。一緒にいることでより強くなるのが水瓶座の本質です。', es: 'Las actividades financieras comunitarias pueden traer rendimientos significativamente mas altos que la inversion individual hoy—tu creencia en el poder colectivo es un activo aqui. Busca oportunidades en inversion cooperativa, financiacion colectiva o actividades financieras impulsadas por la comunidad. Ser mas fuertes juntos es la esencia misma de Acuario.' },
      { ko: '오늘 천왕성의 행운이 갑작스러운 형태로 재물운을 열어줍니다. 어디서 어떻게 들어올지 모르니 모든 가능성에 눈과 귀를 열어두세요. 특히 새로운 수익 모델이나 기존과 다른 방식의 수익 창출에 주목하세요—미래의 돈은 과거의 방식으로 오지 않습니다.', en: 'Uranus\' fortune opens sudden financial luck today in unpredictable ways—keep your eyes and ears open to all possibilities. Pay particular attention to new revenue models or unconventional ways of generating income. Future money rarely arrives through the same channels as past money; stay flexible and alert.', zh: '今天天王星的好运以不可预测的方式打开突发的财运——对所有可能性保持眼观耳听。特别关注新的收益模式或非传统的收入创造方式。未来的钱很少通过与过去钱相同的渠道到来；保持灵活和警觉。', ja: '天王星の幸運が今日予測不可能な形で突発的な財運を開きます。すべての可能性に目と耳を開いておいてください。特に新しい収益モデルや非従来の収入創出方法に注目してください。未来のお金は過去のお金と同じチャンネルでは来ないことが多いです。柔軟で警戒心を持ち続けてください。', es: 'La fortuna de Urano abre suerte financiera repentina de maneras impredecibles hoy—mantén los ojos y oidos abiertos a todas las posibilidades. Presta especial atencion a nuevos modelos de ingresos o formas no convencionales de generar ingresos. El dinero futuro rara vez llega por los mismos canales que el dinero pasado; mantente flexible y alerta.' },
      { ko: '남들이 미래를 의심할 때 먼저 투자한 당신의 결정이 오늘 현재의 이익으로 돌아오는 시간입니다. 인내하며 기다린 시간이 결코 헛되지 않았음을 확인하게 됩니다. 이 경험을 토대로 다음번에도 당신의 미래지향적 직관을 더욱 신뢰해 보세요.', en: 'Investments in future value return as present profit today—your decision to invest when others doubted the future is now paying off. The patient waiting was never wasted. Let this experience reinforce your trust in your forward-thinking intuition for the next investment decision you face.', zh: '今天投资未来价值的回报以当前利益的形式回来——你在他人怀疑未来时投资的决定现在得到了回报。耐心等待从未白费。让这次经验加强你对前瞻性直觉的信任，为你面临的下一个投资决定。', ja: '未来の価値に投資したものが今日現在の利益として返ってきます。他者が未来を疑う時に投資したあなたの決断が今実を結んでいます。辛抱強く待った時間は無駄ではありませんでした。この経験を次の投資決定への先見の明のある直感への信頼をさらに強固にする根拠にしてください。', es: 'Las inversiones en valor futuro retornan como ganancia presente hoy—tu decision de invertir cuando otros dudaban del futuro ahora esta dando frutos. La espera paciente nunca fue en vano. Deja que esta experiencia refuerce tu confianza en tu intuicion visionaria para la proxima decision de inversion que enfrentes.' },
      { ko: '당신이 축적해온 지식과 아이디어가 오늘 강력한 경제적 가치로 전환될 수 있는 에너지가 흐릅니다. 머릿속에만 머물러 있던 아이디어를 구체적인 수익 창출 모델로 만들어볼 좋은 시기입니다. 지식이 곧 돈이 되는 이 흐름을 최대한 활용하세요—당신의 뇌가 오늘 가장 수익성 높은 자산입니다.', en: 'Strong energy flows for intellectual assets converting to economic value today—the knowledge and ideas you have accumulated are ready to generate real returns. Now is the ideal time to turn ideas living only in your mind into concrete revenue-generating models. Your brain is your most profitable asset today; maximize its potential.', zh: '今天知识资产转化为经济价值的强大能量流动——你积累的知识和想法准备好产生真正的回报。现在是将只存在于头脑中的想法转化为具体的创收模式的理想时机。你的大脑今天是你最有盈利性的资产，最大化其潜力。', ja: '知的資産が経済的価値に転換される強いエネルギーが流れています。積み重ねてきた知識やアイデアが本当のリターンを生み出す準備ができています。今は頭の中だけに住むアイデアを具体的な収益創出モデルに変える理想的な時期です。今日あなたの脳が最も収益性の高い資産です。その潜在力を最大化してください。', es: 'Fluye fuerte energia para convertir activos intelectuales en valor economico hoy—el conocimiento e ideas que has acumulado estan listos para generar retornos reales. Ahora es el momento ideal para convertir ideas que solo viven en tu mente en modelos concretos de generacion de ingresos. Tu cerebro es tu activo mas rentable hoy; maximiza su potencial.' },
      { ko: '오늘 세우는 재정 계획은 어느 때보다 빠르고 효율적으로 실현될 수 있는 기운이 흐릅니다. 막연한 희망이 아닌 구체적인 숫자와 기한이 담긴 목표를 종이에 적어보세요. 적은 목표가 마음속에만 있는 목표보다 실현 가능성이 훨씬 높다는 것은 수많은 연구가 증명하는 사실입니다.', en: 'Financial plans are realized with exceptional efficiency today—write specific, numbered, time-bound goals down on paper rather than leaving them as vague hopes. Countless studies confirm that written goals have dramatically higher realization rates than goals that exist only in the mind. Today is your day to set your financial vision in stone.', zh: '今天制定的财务计划可以以超常效率实现——用具体的数字和期限把目标写在纸上，而不是留作模糊的希望。无数研究证实，书面目标比只存在于头脑中的目标有显著更高的实现率。今天是将你的财务愿景定下来的日子。', ja: '財政計画が今日は特別な効率で実現されます。具体的な数字と期限を含む目標を紙に書いてください。漠然とした希望にしておくのではなく。書かれた目標は頭の中にだけある目標より実現可能性が劇的に高いということを無数の研究が証明しています。今日はあなたの財政的なビジョンを固める日です。', es: 'Los planes financieros se realizan con excepcional eficiencia hoy—escribe metas especificas, numeradas y con plazos en papel en lugar de dejarlas como esperanzas vagas. Innumerables estudios confirman que los objetivos escritos tienen tasas de realizacion dramaticamente mas altas. Hoy es tu dia para fijar tu vision financiera.' },
      { ko: '오늘 금전적 희소식이 전혀 예상하지 못했던 경로로 들려올 수 있습니다. 항상 가능성의 문을 열어두는 물병자리의 본능이 오늘 빛을 발할 것입니다. 모든 연락과 만남에 열린 마음을 유지하세요—가장 뜻밖의 방향에서 가장 좋은 소식이 찾아오는 날입니다.', en: 'Financial good news comes from unexpected channels today—your natural Aquarian instinct to keep the doors of possibility open will shine especially bright. Maintain an open mind with every contact and encounter you have. The very best news today will arrive from the most completely unexpected direction.', zh: '今天金融好消息可能通过完全意想不到的渠道到来——你天然的水瓶座本能，保持可能性的大门开放，今天将特别闪耀。对你拥有的每次联系和邂逅保持开放心态。今天最好的消息将从最完全意想不到的方向到来。', ja: '予想外の経路から金銭的な好材料が今日届きます。可能性の扉を開けておくという水瓶座の自然な本能が特に輝きます。すべての連絡と出会いに開かれた心を維持してください。今日最も良い知らせは最も完全に予想外の方向から届きます。', es: 'Buenas noticias financieras llegan de canales inesperados hoy—tu instinto acuariano natural de mantener abiertas las puertas de la posibilidad brillara especialmente. Mantén una mente abierta con cada contacto y encuentro que tengas. Las mejores noticias de hoy llegaran de la direccion mas completamente inesperada.' },
    ],
    medium: [
      { ko: '오늘은 재정적으로 큰 변동 없이 안정적인 균형을 유지하는 날입니다. 이런 평온한 날에 앞으로의 재정 방향을 차분히 점검해 보는 것이 좋습니다. 큰 흥분도 걱정도 없는 오늘이 사실은 가장 현명한 재정 결정을 내리기에 최적의 상태입니다.', en: 'Income and expenses stay at similar levels today, maintaining a stable financial balance without major fluctuations. On a calm day like this, it is ideal to quietly review your financial direction going forward. Days without big excitement or worry are actually optimal for making the wisest financial decisions.', zh: '今天收入和支出保持在相似水平，没有大波动地维持稳定的财务平衡。在这样平静的一天，安静地审查你未来的财务方向是理想的。没有大兴奋或担忧的日子实际上是做出最明智财务决定的最佳状态。', ja: '収入と支出が似た水準を維持する安定した一日です。このような穏やかな日に今後の財政方向を静かに見直すのが理想的です。大きな興奮も心配もない今日は実は最も賢明な財政的決定を下すための最適な状態です。', es: 'Ingresos y gastos se mantienen en niveles similares hoy, manteniendo un equilibrio financiero estable sin grandes fluctuaciones. En un dia tranquilo como este, es ideal revisar silenciosamente tu direccion financiera futura. Los dias sin gran emocion ni preocupacion son en realidad optimos para tomar las decisiones financieras mas sabias.' },
      { ko: '인류를 사랑하는 당신은 좋은 명분을 보면 쉽게 지갑을 열려 하는 경향이 있습니다. 오늘은 그 충동적인 기부나 즉흥적인 소비를 잠시 멈추고 계획에 따라 지출하는 것이 더 현명합니다. 진심 어린 기부도 여유가 있을 때 더 지속 가능하게 이루어질 수 있습니다.', en: 'Restrain impulsive donations or spending today and spend according to your plan—your Aquarian love of humanity makes you quick to open your wallet for worthy causes, but sustainable giving requires financial stability first. Heartfelt contributions are more lasting and meaningful when they come from a place of genuine abundance.', zh: '今天克制冲动捐赠或消费，按计划支出——你的水瓶座对人类的爱使你快速为值得的事业打开钱包，但可持续的给予首先需要财务稳定。真诚的贡献在来自真正充裕的地方时更持久、更有意义。', ja: '衝動的な寄付や消費を控えて計画的に支出してください。人類を愛する水瓶座の本性が価値ある目的のためにすぐに財布を開けさせます。しかし持続可能な贈与には財政的な安定が先に必要です。真心からの貢献は本物の豊かさからの場合により持続的で意味深いです。', es: 'Controla donaciones o gastos impulsivos hoy y gasta segun tu plan—tu amor acuariano por la humanidad te hace rapido en abrir la cartera para causas dignas, pero el dar sostenible requiere estabilidad financiera primero. Las contribuciones sinceras son mas duraderas y significativas cuando vienen de un lugar de abundancia genuina.' },
      { ko: '새로운 투자에 끌리는 마음이 오늘도 강하겠지만, 지금은 이미 갖고 있는 것을 잘 관리하는 것이 더 현명합니다. 기존 포트폴리오를 점검하며 방향이 맞지 않는 투자는 재조정하고, 잘 되고 있는 것은 강화하는 것이 오늘의 핵심 재정 전략입니다.', en: 'Reviewing your existing portfolio is wiser than pursuing new investments today—the pull toward new opportunities is strong, but managing what you already have well is the smarter move right now. Review your holdings, rebalance what is off-track, and reinforce what is working well. This maintenance is unglamorous but powerful.', zh: '今天查看你现有的投资组合比追求新投资更明智——对新机会的吸引力很强，但现在好好管理你已经拥有的东西是更聪明的举动。查看你的持仓，重新平衡偏离轨道的，加强运作良好的。这种维护不够光鲜但很有力量。', ja: '新しい投資より既存のポートフォリオを点検するのが今日は賢明です。新しい機会への引力は強いですが今は既に持っているものをうまく管理することがより賢い動きです。持ち分を確認し、軌道から外れているものを再調整し、うまくいっているものを強化してください。このメンテナンスは派手ではありませんが力強いです。', es: 'Revisar tu portafolio existente es mas sabio que perseguir nuevas inversiones hoy—la atraccion hacia nuevas oportunidades es fuerte, pero manejar bien lo que ya tienes es el movimiento mas inteligente ahora. Revisa tus posiciones, reequilibra lo que esta fuera de camino y refuerza lo que esta funcionando bien.' },
      { ko: '우정을 매우 소중히 여기는 당신에게 친구와의 금전 거래는 특히 신중해야 할 영역입니다. 돈이 개입되면 가장 가까운 관계도 흔들릴 수 있습니다. 오늘 그런 상황이 생긴다면 감정보다 원칙을 먼저 세우고, 모든 조건을 명확히 문서화하세요.', en: 'Approach financial dealings with friends carefully today—money can destabilize even the closest relationships, and you value friendship highly. If such a situation arises, establish clear principles before emotions, and document all terms explicitly. A small amount of caution now can protect a friendship worth far more.', zh: '今天与朋友进行金钱往来要谨慎——钱可以动摇即使是最亲密的关系，而你非常珍视友谊。如果出现这种情况，在情感之前建立明确的原则，并明确记录所有条款。现在少一点谨慎可以保护远更有价值的友谊。', ja: '友人や知人との金銭取引は今日は慎重にアプローチしてください。お金は最も親密な関係でも不安定にさせることがあり、あなたは友情を非常に大切にしています。そのような状況が生じたら感情より先に明確な原則を確立してすべての条件を明示的に文書化してください。', es: 'Aborda las transacciones financieras con amigos con cuidado hoy—el dinero puede desestabilizar incluso las relaciones mas cercanas, y tu valoras mucho la amistad. Si surge tal situacion, establece principios claros antes que emociones, y documenta todos los terminos explicitamente. Un poco de precaucion ahora puede proteger una amistad que vale mucho mas.' },
      { ko: '아낀다고 무조건 좋은 것이 아닌 날입니다. 오늘은 합리적이고 가치 있는 소비가 더 현명한 전략입니다. 당신의 성장에 기여하는 교육, 도구, 경험에 투자하는 것을 두려워하지 마세요. 미래의 나를 위한 투자는 언제나 가장 높은 수익률을 가져옵니다.', en: 'Rational spending is more effective than simply saving today—not all frugality is wisdom. The smartest strategy now is investing in things that contribute to your growth: education, tools, and meaningful experiences. Investment in your future self always generates the highest return rate of all.', zh: '今天理性消费比单纯节约更有效——并非所有节俭都是智慧。现在最聪明的策略是投资于有助于你成长的事物：教育、工具和有意义的体验。对未来自己的投资总是产生所有投资中最高的回报率。', ja: '今日は節約より合理的な消費の方が効果的です。すべての節約が知恵ではありません。今最も賢明な戦略はあなたの成長に貢献するもの——教育、ツール、意味のある経験——に投資することです。未来の自分への投資は常に最も高い収益率をもたらします。', es: 'El gasto racional es mas efectivo que simplemente ahorrar hoy—no toda frugalidad es sabiduria. La estrategia mas inteligente ahora es invertir en cosas que contribuyan a tu crecimiento: educacion, herramientas y experiencias significativas. La inversion en tu yo futuro siempre genera la tasa de retorno mas alta de todas.' },
      { ko: '디지털 서비스를 사랑하는 당신에게는 어느새 구독 서비스가 잔뜩 쌓여있을 수 있습니다. 오늘 디지털 구독 서비스와 자동 결제 목록을 꼼꼼히 점검해 보세요. 거의 사용하지 않는 서비스를 해지하는 것만으로도 생각보다 큰 절약이 가능합니다—그 돈을 더 가치 있는 곳에 쓸 수 있습니다.', en: 'Checking digital subscriptions and unnecessary auto-payments can yield surprising savings today—as a digital technology lover, you may have accumulated more subscriptions than you realize. Auditing your subscriptions and canceling rarely-used services can free up significantly more money than expected, redirecting it to more valuable uses.', zh: '今天检查数字订阅和不必要的自动付款可以实现意想不到的节约——作为数字技术爱好者，你可能积累了比你意识到的更多的订阅。审核你的订阅并取消很少使用的服务可以释放比预期多得多的资金，将其重定向到更有价值的用途。', ja: 'デジタルサブスクリプションや不要な自動決済を今日点検すれば意外な節約が可能です。デジタル技術の愛好者として気づかないうちに思ったより多くのサブスクリプションが積み重なっているかもしれません。サブスクリプションを監査してほとんど使わないサービスを解約すれば予想以上に多くのお金が解放され、より価値ある使途に向けられます。', es: 'Revisar suscripciones digitales y pagos automaticos innecesarios puede generar ahorros sorprendentes hoy—como amante de la tecnologia digital, puede que hayas acumulado mas suscripciones de las que te das cuenta. Auditar tus suscripciones y cancelar servicios raramente usados puede liberar significativamente mas dinero del esperado, redirigiendolo a usos mas valiosos.' },
      { ko: '재정적 자유야말로 물병자리에게 진정한 독립의 기반입니다. 오늘은 그 자유를 향한 장기 계획을 세우기에 매우 적합한 시간입니다. 5년, 10년 후의 재정 목표를 명확히 정하고, 그것을 향한 첫 번째 구체적 행동을 오늘 시작해 보세요.', en: 'An appropriate time to plan long-term for financial freedom—for Aquarius, financial freedom is the true foundation of genuine independence. Clarify your financial goals for five and ten years from now, then begin the first specific action toward them today. The journey to financial freedom starts with one clear plan.', zh: '制定实现财务自由的长期计划的合适时间——对水瓶座来说，财务自由是真正独立的真正基础。明确你5年和10年后的财务目标，然后今天开始向它们迈出第一个具体行动。财务自由之旅从一个清晰的计划开始。', ja: '財政的自由のための長期計画を立てるのに適した時間です。水瓶座にとって財政的自由は真の独立の本当の基盤です。5年後、10年後の財政目標を明確にして今日それに向けた最初の具体的な行動を始めてください。財政的自由への旅は一つの明確な計画から始まります。', es: 'Un momento adecuado para planificar a largo plazo la libertad financiera—para Acuario, la libertad financiera es el verdadero fundamento de la independencia genuina. Clarifica tus metas financieras para cinco y diez anos a partir de ahora, luego comienza la primera accion especifica hacia ellas hoy. El camino a la libertad financiera comienza con un plan claro.' },
      { ko: '큰 지출에는 주의하면서 소소한 지출은 무심코 넘기는 것이 재정 낭비의 가장 흔한 패턴입니다. 오늘 가계부를 꼼꼼히 확인하여 별 생각 없이 나간 지출을 파악해 보세요. 작은 지출을 관리하는 습관이 장기적으로 가장 큰 재정적 차이를 만들어냅니다.', en: 'Check your budget to prevent small expenses from piling up today—the most common financial waste pattern is being careful with large expenses while letting small ones slip through. Identify mindless small expenditures in your records. The habit of managing small spending creates the biggest long-term financial difference of all.', zh: '今天查看账本防止小支出累积——最常见的财务浪费模式是对大支出谨慎，而让小支出溜走。在你的记录中识别无意识的小支出。管理小支出的习惯在长期内创造所有中最大的财务差异。', ja: '些細な支出が積み重ならないよう今日は家計簿を確認してください。最も一般的な財政的無駄のパターンは大きな支出には注意しながら小さなものは見過ごすことです。記録の中で無意識の小さな支出を特定してください。小さな支出を管理する習慣が長期的に最も大きな財政的違いを生みます。', es: 'Revisa tu presupuesto para evitar que pequenos gastos se acumulen hoy—el patron de desperdicio financiero mas comun es ser cuidadoso con grandes gastos mientras los pequenos se escapan. Identifica pequenos gastos irreflexivos en tus registros. El habito de manejar los gastos pequenos crea la mayor diferencia financiera a largo plazo de todas.' },
      { ko: '타인을 돕고 싶은 인도주의적 마음과 자신의 재정적 안전을 지켜야 하는 현실 사이에서 균형이 필요한 날입니다. 두 가지 모두 중요하며, 하나를 위해 다른 하나를 완전히 희생하는 것은 지속 가능하지 않습니다. 오늘은 자신을 먼저 채우는 것도 이기심이 아닌 지속 가능한 관대함의 방법임을 기억하세요.', en: 'A day to find balance between spending for others and investing in yourself—both your humanitarian impulse and your financial security deserve consideration. Sacrificing one entirely for the other is not sustainable. Remember today that filling yourself first is not selfishness but the path to sustainable generosity toward others.', zh: '今天需要在为他人支出和为自己投资之间找到平衡——你的人道主义冲动和财务安全都值得考虑。完全为一方牺牲另一方是不可持续的。今天记住，首先充实自己不是自私，而是对他人可持续慷慨的途径。', ja: '他人のための支出と自分のための投資の間でバランスを見つける必要がある日です。人道主義的な衝動と財政的な安全の両方が考慮に値します。一方のために他方を完全に犠牲にすることは持続可能ではありません。今日は自分を先に満たすことが利己主義ではなく他者への持続可能な寛大さへの道であることを覚えておいてください。', es: 'Un dia para encontrar equilibrio entre gastar en otros e invertir en ti—tanto tu impulso humanitario como tu seguridad financiera merecen consideracion. Sacrificar uno completamente por el otro no es sostenible. Recuerda hoy que llenarte primero no es egoismo sino el camino hacia la generosidad sostenible hacia otros.' },
      { ko: '논리와 데이터를 사랑하는 물병자리의 강점이 재정 결정에서 가장 빛나는 날입니다. 오늘은 감정에 흔들리지 말고 숫자를 철저히 분석한 뒤 결정하는 자신의 이성적인 능력을 믿어보세요. 차갑게 분석하는 것이 냉정한 것이 아니라 미래를 위한 진정한 지혜입니다.', en: 'Financial decisions should be grounded in data rather than emotions today—this is where your Aquarian analytical strength shines brightest. Check the numbers carefully, run the calculations, and trust your logical mind over fleeting feelings. The clearer your data, the more confident your financial choices become.', zh: '今天金钱决定应基于数据而非情感——这是你水瓶座分析优势最闪耀的地方。仔细确认数字，进行计算，信任你的逻辑思维而非短暂的感觉。数据越清晰，你的财务选择就越自信。', ja: '今日は感情ではなくデータに基づいて金融の決定を下してください。これは水瓶座の分析的な強みが最も輝く場所です。数字をしっかり確認して計算を行い、瞬間的な感情より論理的な心を信頼してください。データが明確なほど財務的な選択はより自信を持ったものになります。', es: 'Las decisiones financieras deben basarse en datos, no emociones hoy—aqui es donde tu fortaleza analitica acuariana brilla mas. Revisa los numeros cuidadosamente, haz los calculos y confia en tu mente logica sobre sentimientos pasajeros. Cuanto mas claros sean tus datos, mas confiadas seran tus elecciones financieras.' },
    ],
    low: [
      { ko: '예상치 못한 지출이 발생하는 것은 누구에게나 일어날 수 있는 일이며, 오늘 그런 상황이 올 수 있습니다. 당황하지 말고 지금 비상금 규모를 먼저 확인해 두세요. 이런 날일수록 새로운 지출은 최소화하고 이미 있는 자원으로 버티는 것이 가장 현명한 전략입니다.', en: 'Sudden expenses can happen to anyone, and today carries that risk for you—this is a universal experience, not a personal failure. Before anything else, check the size of your emergency fund and know what resources you have available. Minimize new spending today and rely on existing resources to weather whatever arises.', zh: '意外支出可能发生，今天你面临这种风险——这是普遍经历，不是个人失败。在做任何事之前，检查你的应急资金规模，了解你有哪些可用资源。今天尽量减少新支出，依靠现有资源来应对任何出现的情况。', ja: '突然の支出は誰にでも起こりうることで今日あなたにそのリスクがあります。これは普遍的な経験であり個人的な失敗ではありません。何よりも先に非常資金の規模を確認して利用可能なリソースを把握してください。今日は新しい支出を最小限にして既存のリソースに頼って何が起きても乗り越えてください。', es: 'Los gastos repentinos pueden ocurrirle a cualquiera, y hoy llevas ese riesgo—es una experiencia universal, no un fracaso personal. Antes de cualquier cosa, revisa el tamano de tu fondo de emergencia y conoce los recursos disponibles. Minimiza los nuevos gastos hoy y apoyate en los recursos existentes para superar lo que surja.' },
      { ko: '새롭고 혁신적인 것에 끌리는 물병자리의 성향이 오늘 재정적 위험을 초래할 수 있습니다. "혁신적"이라는 말에 매혹되어 충분한 검증 없이 투자를 결정하는 것은 오늘 가장 피해야 할 행동입니다. 결정하기 전에 최소 세 가지 독립된 정보 출처를 통해 사실을 확인하는 시간을 가지세요.', en: 'Your Aquarian attraction to the new and innovative may bring financial risk today—investments that seem groundbreaking can carry hidden pitfalls. Resist the pull of excitement and verify thoroughly through at least three independent sources before deciding anything. The most innovative-sounding opportunity is sometimes the most dangerous one.', zh: '今天你水瓶座对新奇和创新的吸引力可能带来财务风险——看起来突破性的投资可能隐藏陷阱。抵抗兴奋的吸引，在决定任何事情之前通过至少三个独立来源彻底验证。听起来最创新的机会有时是最危险的。', ja: '新しく革新的なものへの水瓶座の引力が今日財政的なリスクをもたらす可能性があります。画期的に見える投資には隠れた落とし穴がある可能性があります。興奮の引力に抵抗し何かを決定する前に少なくとも3つの独立したソースを通じて徹底的に検証してください。最も革新的に聞こえる機会が時に最も危険なものです。', es: 'Tu atraccion acuariana hacia lo nuevo e innovador puede traer riesgo financiero hoy—las inversiones que parecen revolucionarias pueden tener trampas ocultas. Resiste el impulso de la emocion y verifica a fondo a traves de al menos tres fuentes independientes antes de decidir cualquier cosa. La oportunidad que suena mas innovadora es a veces la mas peligrosa.' },
      { ko: '오늘 유독 강하게 느껴지는 구매 충동은 진짜 필요에서 오는 것이 아닐 수 있습니다. 충동은 나쁜 것이 아니지만, 그것에 지배당하는 것은 나중에 후회를 남길 수 있습니다. 24시간 규칙을 적용해 지금 당장 결제 버튼을 누르지 말고, 하루 뒤에도 여전히 원하는지 스스로에게 물어보세요.', en: 'The impulse buying urge is unusually strong today, but this feeling may not reflect genuine need—your desire for novelty and stimulation is running high right now. Do not let the excitement of discovery override your financial judgment. Apply the 24-hour rule: step away completely and ask yourself tomorrow if you still truly want it.', zh: '今天冲动购买的冲动异常强烈，但这种感觉可能不反映真正的需要——你对新奇和刺激的渴望现在很高。不要让发现的兴奋凌驾于你的财务判断之上。应用24小时规则：完全离开，明天问问自己是否仍然真的想要它。', ja: '今日は衝動的な購買衝動が異常に強いですが、この感覚は本当の必要から来ていないかもしれません。新しさと刺激への欲求が今高まっています。発見の興奮が財務的判断に勝らないようにしてください。24時間ルールを適用してください。完全に離れて翌日まだ本当に欲しいかどうか自分に聞いてみてください。', es: 'El impulso de compra compulsiva es inusualmente fuerte hoy, pero este sentimiento puede no reflejar necesidad genuina—tu deseo de novedad y estimulacion esta muy alto ahora. No dejes que la emocion del descubrimiento anule tu juicio financiero. Aplica la regla de 24 horas: alejate completamente y preguntate manana si aun lo quieres de verdad.' },
      { ko: '인류를 사랑하는 당신의 마음이 오늘 재정적 약점이 될 수 있는 날입니다. 타인의 금전적 요청이 들어올 때, 즉각적인 동정심보다 먼저 자신의 실제 재정 상황을 냉정하게 파악하는 것이 중요합니다. "No"라고 말하는 것이 이기적인 것이 아니라, 미래에도 지속적으로 돕기 위한 현명한 자기 보호임을 기억하세요.', en: 'Your humanitarian heart can become a financial vulnerability today when others bring financial requests your way. Before responding with immediate sympathy, honestly assess your own financial situation first. Saying no is not selfishness—it is wise self-protection that keeps you able to genuinely help others sustainably over the long term.', zh: '当他人带来金钱请求时，你的人道主义心可能成为今天的财务弱点。在立即同情地回应之前，先诚实地评估你自己的财务状况。说不不是自私——这是明智的自我保护，使你能够在长期内可持续地真正帮助他人。', ja: '他人が金銭的な要求を持ってくると今日あなたの人道主義的な心が財政的な弱点になる可能性があります。即座の同情で反応する前にまず自分の財政状況を正直に評価してください。断ることは利己主義ではありません。これは賢明な自己保護であり長期的に持続可能な形で他者を真に助けられるようにするものです。', es: 'Tu corazon humanitario puede convertirse en una vulnerabilidad financiera hoy cuando otros traen solicitudes economicas. Antes de responder con simpatia inmediata, evalua honestamente tu propia situacion financiera primero. Decir no no es egoismo—es autoproteccion sabia que te mantiene capaz de ayudar genuinamente a otros de manera sostenible a largo plazo.' },
      { ko: '오늘 예상치 못한 수리비나 분실로 인한 갑작스러운 지출이 생길 가능성이 있습니다. 이런 상황은 미리 대비하면 충격을 크게 줄일 수 있습니다. 지금 당장 보험 가입 현황과 보장 내용을 확인하고, 비상금의 유동성 상태도 함께 점검해 두는 것이 현명합니다.', en: 'An unexpected repair bill or loss-related expense may arise today, catching you off guard financially. The impact of such surprises is far smaller when you are prepared—check your insurance coverage status and benefit details right now. Also confirm that your emergency fund is liquid and accessible if you need it quickly.', zh: '今天可能出现意外维修费或丢失相关支出，让你在财务上措手不及。当你有准备时，这种意外的影响要小得多——现在检查你的保险覆盖状态和保障细节。还要确认你的应急资金是流动的，如果你需要快速使用可以获取。', ja: '今日予想外の修理費や紛失に関連した支出が発生してあなたの財政的な不意を突く可能性があります。準備ができていればそのような驚きの影響はずっと小さくなります。今すぐ保険の補償状態と給付の詳細を確認してください。また非常資金が流動的で素早く必要な場合にアクセス可能であることを確認してください。', es: 'Una factura de reparacion inesperada o gasto relacionado con perdida puede surgir hoy, atrapandote desprevenido financieramente. El impacto de tales sorpresas es mucho menor cuando estas preparado—revisa el estado de tu cobertura de seguro y los detalles de beneficios ahora mismo. Tambien confirma que tu fondo de emergencia es liquido y accesible si lo necesitas rapidamente.' },
      { ko: '오늘은 재정적으로 보수적으로 행동하는 것이 가장 현명한 날입니다. 고수익 고위험 투기적 투자는 오늘 절대 건드리지 말아야 할 영역입니다. 돈을 버는 것보다 이미 가진 것을 지키는 것이 오늘의 최우선 목표이며, 원금 보전이 최고의 투자 전략입니다.', en: 'Speculative investments must absolutely be avoided today—this is a day to act conservatively with your finances without exception. Protecting what you already have is more important than chasing gains right now. Capital preservation is not merely playing it safe; on a day like this, it is the highest form of financial intelligence.', zh: '今天绝对要避免投机性投资——这是一个毫无例外地保守行事的日子。保护你已经拥有的比现在追逐收益更重要。保全本金不仅仅是保守；在这样的一天，它是最高形式的财务智慧。', ja: '今日は例外なく財政的に保守的に行動する日です。投機的な投資は絶対に避けなければなりません。今は利益を追うより既に持っているものを守ることの方が重要です。元本保全は単に安全を保つだけでなく、このような日には最高の形の財務的知性です。', es: 'Las inversiones especulativas deben evitarse absolutamente hoy—es un dia para actuar conservadoramente con tus finanzas sin excepcion. Proteger lo que ya tienes es mas importante que perseguir ganancias ahora mismo. La preservacion del capital no es simplemente ir a lo seguro; en un dia como este, es la forma mas elevada de inteligencia financiera.' },
      { ko: '오늘 재정적 스트레스가 평소보다 심하게 느껴질 수 있으며, 그것은 당신만의 경험이 아닙니다. 지금 당장의 상황이 전부가 아니라는 것을 기억하세요—물병자리는 시간이 흘러도 회복력이 강한 별자리입니다. 현재의 어려움을 전체 재정 여정 속 하나의 구간으로 바라보면, 지금보다 훨씬 더 평온하게 앞으로 나아갈 수 있습니다.', en: 'Financial stress may feel heavier than usual today, and that is a valid experience—you are not alone in feeling this way. Remember that current circumstances are not permanent, and Aquarius has remarkable resilience over time. Viewing present difficulties as one stretch within your entire financial journey makes it possible to move forward with far more calm than the stress itself suggests.', zh: '今天财务压力可能比平时感觉更重，这是一种有效的体验——你并不孤单。记住当前情况不是永久的，水瓶座随着时间推移有非凡的韧性。将现在的困难视为你整个财务旅程中的一段，使你能够以比压力本身暗示的更多平静向前迈进。', ja: '今日は財政的なストレスが普段より重く感じられるかもしれません。これは有効な経験であり、あなたは一人ではありません。現在の状況は永続的ではなく、水瓶座は時間が経つにつれて並外れた回復力を持っていることを覚えておいてください。現在の困難を財政的な旅全体の一つの区間として見ることで、ストレス自体が示すよりもずっと穏やかに前進できます。', es: 'El estres financiero puede sentirse mas pesado de lo habitual hoy, y esa es una experiencia valida—no estas solo en sentirte asi. Recuerda que las circunstancias actuales no son permanentes, y Acuario tiene una resistencia notable con el tiempo. Ver las dificultades presentes como un tramo dentro de tu viaje financiero completo hace posible avanzar con mucha mas calma de lo que el estres mismo sugiere.' },
      { ko: '공동체 정신을 사랑하는 물병자리에게 공유 경제나 공동 투자는 이상적으로 느껴질 수 있지만, 오늘은 그 영역에서 분쟁이 생길 가능성이 높습니다. 먼저 관련된 모든 계약 사항을 처음부터 다시 꼼꼼히 확인해 두세요. 명확한 문서와 합의는 관계도 지키고 재정도 지키는 가장 확실한 방법입니다.', en: 'Disputes in shared economy ventures or joint investments may arise today—the communal spirit you love as an Aquarian can become complicated when money enters the picture. Recheck all contract terms and agreements from the beginning carefully. Clear documentation and explicit mutual understanding are the most reliable way to protect both your finances and your relationships simultaneously.', zh: '今天共享经济活动或共同投资中可能出现纠纷——当金钱进入画面时，你作为水瓶座所喜爱的集体精神可能会变得复杂。从头仔细重新检查所有合同条款和协议。明确的文件记录和明确的相互理解是同时保护你的财务和关系的最可靠方式。', ja: '今日は共有経済の活動や共同投資で紛争が起きる可能性があります。お金が絡むと水瓶座として好きな共同体精神が複雑になることがあります。最初からすべての契約条項と合意を注意深く再確認してください。明確な文書化と明示的な相互理解があなたの財政と関係を同時に守る最も信頼できる方法です。', es: 'Pueden surgir disputas en actividades de economia compartida o inversiones conjuntas hoy—el espiritu comunitario que amas como acuariano puede complicarse cuando el dinero entra en escena. Revisa todos los terminos del contrato y acuerdos desde el principio cuidadosamente. La documentacion clara y el entendimiento mutuo explicito son la forma mas confiable de proteger tanto tus finanzas como tus relaciones simultaneamente.' },
      { ko: '세상을 더 나은 곳으로 만들고 싶은 물병자리의 이상주의는 아름다운 가치이지만, 오늘 그 이상을 위해 무리한 재정을 투입하는 것은 위험합니다. 위대한 목표도 한 번에 이루어지지 않으며, 단계적으로 접근할 때 지속 가능성이 생깁니다. 오늘은 꿈의 크기를 줄이는 것이 아니라 속도를 조절하는 것이 진정한 지혜입니다.', en: 'Your Aquarian idealism about making the world better is beautiful, but overcommitting financially to those ideals today carries real danger. Great goals are never achieved all at once—sustainability comes from a phased approach that keeps you financially stable throughout the journey. Today, moderating your pace is not shrinking your dreams; it is wisdom that keeps your vision alive for the long haul.', zh: '你关于让世界变得更好的水瓶座理想主义是美丽的，但今天为那些理想过度承诺财务承担真正的危险。伟大的目标从不是一次实现的——可持续性来自于在整个旅程中保持你财务稳定的分阶段方法。今天，调节你的节奏不是缩小你的梦想；这是让你的愿景长期保持活力的智慧。', ja: '世界をより良くしようとする水瓶座の理想主義は美しいですが、今日それらの理想に財政的に過度にコミットすることは本当の危険を伴います。偉大な目標は一度に達成されることはありません。持続可能性は旅を通じて財政的に安定していられる段階的なアプローチから来ます。今日ペースを調整することは夢を縮小することではありません。これはあなたのビジョンを長期的に生き続けさせる知恵です。', es: 'Tu idealismo acuariano sobre hacer el mundo mejor es hermoso, pero sobrecomprometerte financieramente con esos ideales hoy conlleva peligro real. Las grandes metas nunca se logran de una vez—la sostenibilidad viene de un enfoque gradual que te mantiene financieramente estable durante todo el viaje. Hoy, moderar tu ritmo no es encoger tus suenos; es la sabiduria que mantiene tu vision viva a largo plazo.' },
      { ko: '분석력이 뛰어난 물병자리임에도 오늘은 금전 관련 서류나 계약서에서 놓치는 것이 생길 수 있으니 각별히 주의하세요. 핵심 조항만 훑어보지 말고 작은 글씨까지 전부 읽어야 합니다—중요한 조건들이 눈에 잘 띄지 않는 곳에 숨어있을 수 있습니다. 서명하기 전에 이해되지 않는 부분이 있다면 반드시 전문가의 도움을 받으세요.', en: 'Read all financial documents and contracts with exceptional care today—even with your sharp analytical mind, important conditions can hide in fine print on days like this. Do not skim headlines and key clauses only; read every word including the smallest text. If anything is unclear before signing, seek expert guidance without hesitation—the cost of not understanding is always higher than the cost of asking.', zh: '今天以格外小心阅读所有财务文件和合同——即使有你敏锐的分析思维，在这样的日子里重要条件也可能隐藏在小字中。不要只浏览标题和关键条款；阅读每一个字，包括最小的文字。如果签名前有任何不清楚的地方，毫不犹豫地寻求专家指导——不理解的代价总是高于询问的代价。', ja: '今日はすべての金融書類や契約書を格別な注意で読んでください。鋭い分析力を持つ水瓶座でもこのような日は重要な条件が小さな文字に隠れている可能性があります。見出しと重要条項だけを斜め読みしないでください。最も小さな文字を含めてすべての言葉を読んでください。署名前に何かが不明な場合は迷わず専門家の指導を求めてください。理解しないことのコストは常に尋ねることのコストより高いです。', es: 'Lee todos los documentos financieros y contratos con cuidado excepcional hoy—incluso con tu aguda mente analitica, condiciones importantes pueden esconderse en letra pequena en dias como este. No leas solo titulares y clausulas clave; lee cada palabra incluyendo el texto mas pequeno. Si algo no esta claro antes de firmar, busca orientacion experta sin dudarlo—el costo de no entender siempre es mayor que el costo de preguntar.' },
    ],
  },
};
